// ── CONTENT EXPANSION (rebuilt clean 2026-03-20) ──

(function(){
  if(!window.QB_NUTRITION) return;
  var fc=window.QB_NUTRITION.flashcards,qz=window.QB_NUTRITION.quiz;
  if(!fc||!qz) return;
  ['easy','medium','hard'].forEach(function(d){if(!fc[d])fc[d]=[];if(!qz[d])qz[d]=[];});
  fc.easy=fc.easy.concat([{"term":"Calorie","def":"Unit of energy in food — 1 calorie = energy to raise 1g water by 1°C","breakdown":"Food calories are actually kilocalories (kcal). The calorie count on a food label = kcal"},{"term":"Carbohydrate calories","def":"4 calories per gram of carbohydrate","breakdown":"Carbs are the body's preferred energy source. 1 slice bread ≈ 15g carbs = 60 calories"},{"term":"Protein calories","def":"4 calories per gram of protein","breakdown":"Same as carbs but protein builds/repairs tissue. 3oz chicken ≈ 21g protein = 84 calories"},{"term":"Fat calories","def":"9 calories per gram of fat — more than double carbs/protein","breakdown":"Fat is energy-dense. 1 tbsp olive oil = 14g fat = 126 calories. Why fatty foods are calorie-heavy"},{"term":"Alcohol calories","def":"7 calories per gram of alcohol — between fat and carbs","breakdown":"Alcohol provides calories but no essential nutrients — 'empty calories'"},{"term":"Simple carbohydrates","def":"Single or double sugar units — digest quickly, rapid blood sugar spike","breakdown":"Glucose, fructose (fruit), lactose (milk), sucrose (table sugar). Fast energy but short-lasting"},{"term":"Complex carbohydrates","def":"Long chains of sugar units — digest slowly, steady blood sugar","breakdown":"Starch (potatoes, rice) and fiber (vegetables, whole grains). Sustained energy release"},{"term":"Dietary fiber","def":"Indigestible plant carbohydrate — feeds gut bacteria, aids digestion, lowers cholesterol","breakdown":"Soluble fiber: dissolves in water (oats, beans). Insoluble fiber: doesn't dissolve (wheat bran, vegetables)"},{"term":"Recommended daily fiber","def":"25g/day for women, 38g/day for men (or 14g per 1000 calories)","breakdown":"Most Americans get only 15g/day. Fiber deficiency linked to constipation, colon cancer risk, heart disease"},{"term":"Essential amino acids","def":"9 amino acids the body cannot make — must come from food","breakdown":"Histidine, Isoleucine, Leucine, Lysine, Methionine, Phenylalanine, Threonine, Tryptophan, Valine"},{"term":"Fat-soluble vitamins","def":"Vitamins A, D, E, K — stored in fat tissue and liver — can accumulate to toxic levels","breakdown":"Stored long-term so don't need daily intake. Excess supplementation can cause toxicity (especially A and D)"},{"term":"Water-soluble vitamins","def":"Vitamins C and all B vitamins — not stored, excess excreted in urine","breakdown":"Need regular daily intake. Deficiency develops faster than fat-soluble vitamins. B12 exception: stored in liver"},{"term":"Vitamin A functions","def":"Vision (especially night vision), immune function, skin and cell growth","breakdown":"Preformed A (retinol) in animal foods. Provitamin A (beta-carotene) in orange/yellow vegetables. Deficiency causes night blindness"},{"term":"Vitamin C functions","def":"Collagen synthesis, antioxidant, immune support, iron absorption enhancement","breakdown":"Found in citrus, bell peppers, strawberries. Deficiency causes scurvy. Water-soluble — cook gently to preserve"},{"term":"Vitamin D functions","def":"Calcium absorption, bone health, immune function, muscle function","breakdown":"Synthesized in skin from sunlight. Food sources: fatty fish, fortified dairy. Deficiency: rickets (children), osteomalacia (adults)"},{"term":"Iron functions","def":"Oxygen transport in hemoglobin, energy metabolism, immune function","breakdown":"Heme iron (meat) absorbed 2-3x better than non-heme iron (plants). Vitamin C enhances non-heme iron absorption"},{"term":"Calcium functions","def":"Bone and tooth structure, muscle contraction, nerve transmission, blood clotting","breakdown":"99% of body's calcium is in bones/teeth. Dairy, leafy greens, fortified foods. Deficiency leads to osteoporosis"},{"term":"Sodium functions","def":"Fluid balance, nerve transmission, muscle contraction","breakdown":"DRI: <2300mg/day. Average American gets ~3400mg. Excess raises blood pressure. Kidney disease requires further restriction"},{"term":"Potassium functions","def":"Fluid balance, heart rhythm, muscle and nerve function — counters sodium","breakdown":"High potassium diet lowers blood pressure. Found in bananas, potatoes, beans, leafy greens"},{"term":"Dehydration signs","def":"Dark urine, dry mouth, headache, fatigue, dizziness, reduced urine output","breakdown":"2% body weight fluid loss impairs cognitive performance. 5-8% causes serious symptoms. Sports drinks replace electrolytes"},{"term":"BMI formula","def":"Body Mass Index = weight(kg) / height(m)². Screening tool, not diagnostic","breakdown":"<18.5 underweight; 18.5-24.9 normal; 25-29.9 overweight; ≥30 obese. Doesn't account for muscle mass"},{"term":"Basal Metabolic Rate (BMR)","def":"Calories burned at complete rest — energy for vital functions (breathing, circulation, cell repair)","breakdown":"Largest component of total daily energy expenditure. Influenced by age, sex, body composition, genetics"},{"term":"Food label serving size","def":"Reference amount for nutrition information — NOT a recommendation of how much to eat","breakdown":"Calories and all nutrients on label are per serving. If you eat 2 servings, double everything"},{"term":"% Daily Value (%DV)","def":"How much a nutrient in one serving contributes to a 2000-calorie daily diet","breakdown":"5% DV or less = low in that nutrient. 20% DV or more = high. Use to compare foods and assess diet quality"},{"term":"Added sugars","def":"Sugars added during food processing — listed separately on Nutrition Facts since 2020","breakdown":"DRI: <10% of calories (50g/day for 2000-cal diet). Natural sugars in fruit and milk not counted as added"}]);
  fc.medium=fc.medium.concat([{"term":"Anemia types in nutrition","def":"Iron-deficiency anemia (most common), B12/folate (megaloblastic), vitamin C deficiency anemia","breakdown":"Iron: microcytic small RBCs. B12/folate: macrocytic large RBCs. All reduce oxygen-carrying capacity"},{"term":"Folate/Folic acid","def":"B vitamin critical for DNA synthesis and cell division — prevents neural tube defects in pregnancy","breakdown":"Folate = natural form (leafy greens, beans). Folic acid = synthetic (supplements, fortified foods). 400mcg/day recommended; 600mcg pregnant"},{"term":"Vitamin B12","def":"B vitamin for nerve function, DNA synthesis, red blood cell formation — only in animal foods","breakdown":"Vegans must supplement. Deficiency causes pernicious anemia and nerve damage. Stored in liver (3-5 year supply)"},{"term":"Thiamin (B1)","def":"B vitamin for carbohydrate metabolism and nerve function","breakdown":"Deficiency causes beriberi (wet: heart failure; dry: nerve damage). Wernicke-Korsakoff syndrome in alcoholics"},{"term":"Niacin (B3)","def":"B vitamin for energy metabolism — too much causes flushing","breakdown":"Deficiency causes pellagra: Dermatitis, Diarrhea, Dementia, Death (the 4 D's)"},{"term":"Zinc functions","def":"Immune function, wound healing, protein synthesis, taste/smell, DNA synthesis","breakdown":"Oysters highest zinc content. Red meat, poultry, beans, nuts. Deficiency: impaired growth, taste loss, poor wound healing"},{"term":"Magnesium functions","def":"300+ enzymatic reactions, muscle/nerve function, blood glucose, bone structure, energy production","breakdown":"Found in nuts, seeds, leafy greens, whole grains. Deficiency common, linked to hypertension, diabetes, migraines"},{"term":"Iodine functions","def":"Thyroid hormone synthesis — regulates metabolism, growth, brain development","breakdown":"Iodized salt solved endemic goiter (enlarged thyroid). Deficiency during pregnancy causes cretinism (intellectual disability)"},{"term":"Phytochemicals","def":"Non-nutrient plant compounds with health benefits — not essential but protective","breakdown":"Lycopene (tomatoes), flavonoids (berries), glucosinolates (broccoli), resveratrol (red wine). Disease prevention, not just treatment"},{"term":"Probiotics","def":"Live beneficial microorganisms that colonize the gut — improve digestive and immune health","breakdown":"Lactobacillus and Bifidobacterium common strains. Found in yogurt, kefir, kimchi, sauerkraut. Restore gut flora after antibiotics"},{"term":"Prebiotics","def":"Non-digestible food components that feed beneficial gut bacteria","breakdown":"Inulin, FOS (fructooligosaccharides). Found in garlic, onions, bananas, asparagus. Distinct from probiotics"},{"term":"Top 9 food allergens","def":"Milk, Eggs, Fish, Shellfish, Tree nuts, Peanuts, Wheat, Soybeans, Sesame","breakdown":"Required on U.S. food labels since FALCPA (2004). Sesame added as 9th in 2023. Together cause 90% of food allergic reactions"},{"term":"Insulin function in nutrition","def":"Pancreatic hormone that allows cells to take up glucose from blood — lowers blood sugar","breakdown":"Released after meals. Signals cells to absorb glucose. Also promotes fat and protein storage. Absence/resistance = diabetes"},{"term":"Glucagon function","def":"Pancreatic hormone that raises blood glucose by stimulating glycogen breakdown and gluconeogenesis","breakdown":"Released when blood glucose falls (fasting, exercise). Counter-regulatory to insulin. Used as emergency treatment for severe hypoglycemia"},{"term":"Dietary Reference Intakes (DRI)","def":"Framework of nutrient intake standards including RDA, AI, UL, and EAR","breakdown":"RDA: meets needs of 97% of healthy people. AI: adequate intake when RDA unknown. UL: highest daily intake unlikely to cause harm"},{"term":"Energy balance equation","def":"Weight change = Energy in (food) - Energy out (BMR + activity + thermic effect)","breakdown":"Positive balance = weight gain. Negative balance = weight loss. 3500 kcal deficit ≈ 1 lb fat loss (approximate and contested)"},{"term":"Hypertension and diet","def":"DASH diet reduces blood pressure: low sodium, high potassium, calcium, magnesium","breakdown":"DASH = Dietary Approaches to Stop Hypertension. Emphasizes fruits, vegetables, low-fat dairy, whole grains. Limit sodium to 1500-2300mg"},{"term":"Mediterranean diet","def":"Plant-based diet with olive oil, fish, whole grains, legumes, moderate wine — linked to longevity","breakdown":"Consistently ranked top diet by research. Reduces cardiovascular disease, type 2 diabetes, cognitive decline. UNESCO intangible heritage"},{"term":"Food security","def":"All people at all times have access to sufficient, safe, and nutritious food","breakdown":"4 dimensions: Availability, Access, Utilization, Stability. Food insecurity affects 800M globally, 30M+ in U.S."},{"term":"Hunger vs appetite","def":"Hunger: physiological need for food. Appetite: psychological desire for food","breakdown":"Hunger = ghrelin (stomach hormone). Appetite influenced by senses, emotions, habits. Leptin signals satiety to brain"}]);
  fc.hard=fc.hard.concat([{"term":"Absorptive state (fed state)","def":"Post-meal period — nutrients absorbed, insulin dominant, anabolism occurs","breakdown":"Glucose → glycogen and fat storage. Amino acids → protein synthesis. Lasts 2-4 hours after meal"},{"term":"Post-absorptive state (fasted state)","def":"Between meals — glycogen breakdown, gluconeogenesis, fat oxidation to maintain blood glucose","breakdown":"Glucagon dominant. Liver releases glucose. After 12-18h glycogen depleted, fat becomes primary fuel"},{"term":"Ketogenesis","def":"Liver converts fatty acids to ketone bodies during prolonged fasting or carb restriction","breakdown":"Ketones: acetoacetate, beta-hydroxybutyrate, acetone. Brain uses ketones when glucose scarce. Basis of ketogenic diet"},{"term":"Gluconeogenesis","def":"Synthesis of new glucose from non-carbohydrate precursors (amino acids, glycerol, lactate)","breakdown":"Occurs in liver and kidney. Maintains blood glucose during fasting. Amino acids most important substrate"},{"term":"Enterohepatic circulation","def":"Recycling of bile salts from intestine back to liver via portal circulation","breakdown":"Bile salts emulsify fat for absorption. 95% recycled, 5% lost in feces. Soluble fiber interrupts this cycle, lowering cholesterol"},{"term":"VLDL, IDL, LDL, HDL differences","def":"Lipoprotein particles differ in triglyceride/cholesterol ratio and apolipoprotein composition","breakdown":"VLDL: liver-made, triglyceride-rich. IDL: VLDL remnant. LDL: cholesterol-rich, atherogenic. HDL: reverse cholesterol transport"},{"term":"Phospholipid structure and function","def":"Glycerol + 2 fatty acids + phosphate group — forms cell membrane bilayer","breakdown":"Amphipathic: hydrophilic head, hydrophobic tails. Forms lipid bilayer of all cell membranes. Lecithin is a common dietary phospholipid"},{"term":"Proteolysis and peptide absorption","def":"Protein digested to amino acids and small peptides — absorbed by specific transporters","breakdown":"Stomach: pepsin. Pancreas: trypsin, chymotrypsin. Small intestine brush border: peptidases. Di/tripeptides absorbed whole"},{"term":"Vitamin D synthesis pathway","def":"7-dehydrocholesterol → UV light → previtamin D3 → liver (25-OH-D3) → kidney (1,25-OH2-D3 = calcitriol)","breakdown":"Calcitriol is the active hormone form. Kidney conversion impaired in kidney disease — supplementation as active form needed"},{"term":"Iron absorption regulation","def":"Hepcidin (liver hormone) regulates iron absorption — high iron → high hepcidin → reduced absorption","breakdown":"Hepcidin degrades ferroportin (iron exporter) in enterocytes. Inflammation increases hepcidin → anemia of chronic disease"}]);
  qz.easy=qz.easy.concat([{"q":"How many calories does 1 gram of carbohydrate provide?","opts":["2","4","7","9"],"correct":1,"explain":"Carbohydrates provide 4 calories per gram. The same as protein (4 cal/g). Fat provides 9 cal/g and alcohol provides 7 cal/g."},{"q":"Which nutrient is the body's preferred energy source?","opts":["Fat","Protein","Carbohydrates","Vitamins"],"correct":2,"explain":"Carbohydrates are the body's preferred energy source because they are most efficiently converted to glucose for immediate use. The brain especially relies on glucose."},{"q":"What is the recommended daily sodium intake for healthy adults?","opts":["Less than 1000mg","Less than 2300mg","Less than 3500mg","Less than 5000mg"],"correct":1,"explain":"The recommended daily sodium intake is less than 2300mg for healthy adults. The average American consumes about 3400mg daily, which contributes to hypertension."},{"q":"Which type of fat is considered most harmful to heart health?","opts":["Monounsaturated fat","Polyunsaturated fat","Saturated fat","Trans fat"],"correct":3,"explain":"Trans fat (partially hydrogenated oil) is most harmful — it raises LDL (bad) cholesterol AND lowers HDL (good) cholesterol simultaneously. The FDA banned most trans fats in U.S. foods in 2018."},{"q":"Vitamin D deficiency in children causes which condition?","opts":["Scurvy","Rickets","Pellagra","Beriberi"],"correct":1,"explain":"Vitamin D deficiency in children causes rickets — soft, weak bones that bow under body weight. In adults, the same deficiency causes osteomalacia (soft bones). Vitamin D is needed for calcium absorption."},{"q":"Which mineral is most important for bone health?","opts":["Iron","Zinc","Calcium","Magnesium"],"correct":2,"explain":"Calcium is the most important mineral for bone health — 99% of body calcium is stored in bones and teeth. Adequate calcium throughout life reduces osteoporosis risk. Vitamin D is needed for calcium absorption."},{"q":"What does MyPlate recommend for half the plate?","opts":["Grains and dairy","Fruits and vegetables","Protein and grains","Fruits and protein"],"correct":1,"explain":"MyPlate recommends filling half the plate with fruits and vegetables. One quarter should be grains (preferably whole grains) and one quarter protein, with a small dairy serving on the side."},{"q":"Which vitamin is produced by the skin in sunlight?","opts":["Vitamin A","Vitamin B12","Vitamin C","Vitamin D"],"correct":3,"explain":"Vitamin D is synthesized in the skin when UV light converts 7-dehydrocholesterol to previtamin D3. This is then activated in the liver and kidneys. Many people are deficient due to limited sun exposure."},{"q":"A food label shows 20% DV for sodium. This means the food is:","opts":["Low in sodium","Moderate in sodium","High in sodium","Sodium-free"],"correct":2,"explain":"20% Daily Value or more means the food is HIGH in that nutrient. 5% DV or less = low. The %DV shows how much a nutrient in one serving contributes to a 2000-calorie daily diet."},{"q":"Omega-3 fatty acids are best obtained from which food source?","opts":["Red meat","White bread","Fatty fish (salmon, sardines)","Vegetable oils"],"correct":2,"explain":"Fatty fish like salmon, mackerel, sardines, and herring are the best sources of EPA and DHA — the most beneficial forms of omega-3 fatty acids. ALA omega-3 from flaxseed and walnuts must be converted and is less efficiently used."},{"q":"Which is an example of a complete protein?","opts":["White rice","Black beans","Eggs","Whole wheat bread"],"correct":2,"explain":"Eggs are a complete protein — they contain all 9 essential amino acids in adequate amounts. Most animal proteins (meat, dairy, eggs) are complete. Most plant proteins are incomplete but can be combined."},{"q":"What is fiber's primary benefit for digestive health?","opts":["Provides energy for digestion","Adds bulk to stool and feeds beneficial gut bacteria","Breaks down fat in the intestine","Absorbs water-soluble vitamins"],"correct":1,"explain":"Dietary fiber adds bulk to stool (preventing constipation) and feeds beneficial gut bacteria (prebiotic effect). Soluble fiber also lowers cholesterol and slows glucose absorption."},{"q":"Which B vitamin is essential for preventing neural tube defects in pregnancy?","opts":["Thiamin (B1)","Niacin (B3)","Folate (B9)","Cobalamin (B12)"],"correct":2,"explain":"Folate (vitamin B9) is critical for preventing neural tube defects like spina bifida. All women of childbearing age should consume 400mcg daily; pregnant women need 600mcg. Folic acid fortification in grains has reduced neural tube defects dramatically."},{"q":"What happens to excess water-soluble vitamins in the body?","opts":["Stored in fat tissue","Stored in the liver","Excreted in urine","Converted to fat-soluble vitamins"],"correct":2,"explain":"Excess water-soluble vitamins (vitamin C and all B vitamins) are excreted in urine since the body cannot store them. This is why they need to be consumed regularly, and why toxicity is rare (unlike fat-soluble vitamins)."},{"q":"Iron absorption is enhanced by consuming iron with which nutrient?","opts":["Calcium","Vitamin C","Vitamin D","Zinc"],"correct":1,"explain":"Vitamin C (ascorbic acid) significantly enhances non-heme iron absorption from plant foods. Consuming iron-rich plants with vitamin C sources (citrus juice, bell peppers) can double or triple iron absorption."},{"q":"What does BMI measure?","opts":["Body fat percentage precisely","Weight relative to height as a screening tool","Muscle mass and bone density","Metabolic rate"],"correct":1,"explain":"BMI (Body Mass Index) measures weight in kg divided by height in meters squared. It is a SCREENING tool, not a precise health measure. It cannot distinguish between muscle and fat mass."},{"q":"Which eating pattern is associated with the longest healthy lifespans?","opts":["High-protein diet","Ketogenic diet","Mediterranean diet","Low-fat diet"],"correct":2,"explain":"The Mediterranean diet — rich in olive oil, fish, vegetables, legumes, and whole grains — is consistently associated with the longest healthy lifespans and lowest rates of heart disease, diabetes, and cognitive decline in research studies."},{"q":"What is the function of insulin in nutrition?","opts":["Break down stored fat","Allow cells to absorb glucose from the blood","Convert protein to glucose","Signal hunger to the brain"],"correct":1,"explain":"Insulin is a pancreatic hormone that allows cells to take up glucose from the bloodstream, lowering blood sugar after meals. Type 1 diabetes: no insulin produced. Type 2: cells don't respond properly to insulin."},{"q":"How many glasses of water does the Institute of Medicine recommend for women daily?","opts":["4 glasses (1 liter)","6 glasses (1.5 liters)","9 glasses (2.2 liters)","13 glasses (3 liters)"],"correct":2,"explain":"The Institute of Medicine recommends about 9 cups (2.2 liters) of total water daily for women and 13 cups (3 liters) for men. This includes water from all beverages and food (about 20% of water comes from food)."},{"q":"Which condition results from inadequate protein intake in children?","opts":["Rickets","Kwashiorkor","Scurvy","Pellagra"],"correct":1,"explain":"Kwashiorkor results from protein deficiency (with adequate calories) in children — characterized by edema (fluid swelling, especially abdominal), growth failure, and fatty liver. Common in developing regions where weaned children receive starchy but protein-poor diets."}]);
  qz.medium=qz.medium.concat([{"q":"Which lipoprotein is known as 'bad' cholesterol because it deposits cholesterol in artery walls?","opts":["HDL","VLDL","LDL","Chylomicrons"],"correct":2,"explain":"LDL (Low-Density Lipoprotein) carries cholesterol from the liver to cells and can deposit it in artery walls, forming plaques (atherosclerosis). LDL < 100 mg/dL is optimal. Saturated and trans fats raise LDL."},{"q":"What is the difference between hunger and appetite?","opts":["They are the same thing","Hunger is physiological; appetite is psychological","Appetite is physiological; hunger is psychological","Hunger lasts longer than appetite"],"correct":1,"explain":"Hunger is a physiological need for food — triggered by the hormone ghrelin from the stomach. Appetite is a psychological desire for food, influenced by senses, emotions, habits, and environment. You can have appetite without hunger (dessert after a large meal)."},{"q":"Which vitamin deficiency causes pellagra, characterized by the 4 D's?","opts":["Thiamin (B1)","Riboflavin (B2)","Niacin (B3)","Pyridoxine (B6)"],"correct":2,"explain":"Niacin (B3) deficiency causes pellagra — Dermatitis, Diarrhea, Dementia, and Death (the 4 D's). Common where corn-based diets dominate without traditional nixtamalization process. Tryptophan can be converted to niacin."},{"q":"What is the thermic effect of food?","opts":["Temperature increase from eating hot food","Energy used to digest, absorb, and metabolize food (about 10% of calories)","Calories burned during cooking","Heat generated during food storage"],"correct":1,"explain":"The thermic effect of food (TEF) is the energy required to digest, absorb, and metabolize nutrients — about 10% of total energy intake. Protein has the highest TEF (20-30%), making high-protein diets slightly more metabolically costly."},{"q":"A patient has iron-deficiency anemia. Which food combination would BEST improve iron absorption?","opts":["Iron supplement with milk","Spinach salad with lemon dressing and vitamin C-rich bell peppers","Red meat with coffee","Iron-fortified cereal with tea"],"correct":1,"explain":"Spinach (non-heme iron) with bell peppers and lemon dressing provides vitamin C, which dramatically enhances non-heme iron absorption. Coffee and tea contain tannins that INHIBIT iron absorption. Calcium in milk can also reduce iron absorption."},{"q":"What is glycogen, and where is it stored?","opts":["Fat storage in adipose tissue","Glucose storage in liver and muscles","Protein storage in organ tissue","Cholesterol storage in the gallbladder"],"correct":1,"explain":"Glycogen is the storage form of glucose in the body — long chains of glucose molecules. About 100g stored in liver (to maintain blood glucose) and 300-400g in muscles (for local energy use). Depleted after 12-18 hours of fasting."},{"q":"The DASH diet was specifically designed to address which health condition?","opts":["Type 2 diabetes","Osteoporosis","Hypertension (high blood pressure)","Celiac disease"],"correct":2,"explain":"DASH (Dietary Approaches to Stop Hypertension) was designed to reduce blood pressure without medication. It emphasizes fruits, vegetables, low-fat dairy, whole grains, and limits sodium, saturated fat, and added sugars."},{"q":"What distinguishes celiac disease from gluten sensitivity?","opts":["Celiac is less severe","Celiac is an autoimmune condition that damages intestinal villi; gluten sensitivity is not","Gluten sensitivity requires stricter avoidance","They are identical conditions"],"correct":1,"explain":"Celiac disease is an autoimmune reaction where gluten triggers the immune system to attack and damage the small intestine's villi, impairing nutrient absorption. Non-celiac gluten sensitivity causes symptoms without the autoimmune intestinal damage."},{"q":"Which hormone signals satiety (fullness) to the brain?","opts":["Ghrelin","Glucagon","Leptin","Cortisol"],"correct":2,"explain":"Leptin is produced by fat cells and signals the brain (hypothalamus) that energy stores are sufficient — suppressing hunger. Ghrelin is the 'hunger hormone' that increases before meals. In obesity, leptin resistance can develop."},{"q":"What is nutrient density?","opts":["The weight of nutrients in a food","The number of different nutrients in a food","The amount of nutrients relative to a food's calorie content","The concentration of minerals in water"],"correct":2,"explain":"Nutrient density measures the amount of beneficial nutrients (vitamins, minerals, protein, fiber) per calorie. A highly nutrient-dense food provides many nutrients with few calories (kale, salmon). Low nutrient density = many calories, few nutrients (soda, candy)."},{"q":"Which macronutrient is most important for wound healing and tissue repair?","opts":["Carbohydrates","Fat","Protein","Vitamins"],"correct":2,"explain":"Protein is most critical for wound healing — amino acids are the building blocks for new tissue, collagen synthesis, and immune cells. Vitamin C also plays a role in collagen formation. Adequate protein intake is essential after surgery or injury."},{"q":"What is the main function of bile in fat digestion?","opts":["Break down fat chemically","Emulsify fat into small droplets for enzyme access","Absorb fat-soluble vitamins","Transport fat in the blood"],"correct":1,"explain":"Bile (produced by the liver, stored in the gallbladder) emulsifies fat — breaking large fat globules into tiny droplets, increasing surface area for pancreatic lipase to work. Bile does not chemically digest fat; lipase does."},{"q":"Excessive consumption of vitamin A (preformed retinol) can cause:","opts":["Scurvy","Goiter","Toxicity — liver damage, birth defects","Pellagra"],"correct":2,"explain":"Vitamin A (preformed retinol from animal sources/supplements) is fat-soluble and stored in the liver. Excess causes hypervitaminosis A — liver damage, bone pain, birth defects. Beta-carotene (plant form) cannot cause toxicity as the body regulates conversion."},{"q":"Which fatty acid type is essential (must be obtained from diet) for human health?","opts":["Saturated fatty acids","Monounsaturated fatty acids","Linoleic acid (omega-6) and alpha-linolenic acid (omega-3)","All fatty acids are essential"],"correct":2,"explain":"Linoleic acid (omega-6) and alpha-linolenic acid (omega-3) are the two essential fatty acids — the body cannot synthesize them. All other fatty acids can be made from these or from acetyl-CoA."},{"q":"What is the primary role of the large intestine in nutrition?","opts":["Protein digestion","Fat absorption","Water absorption and gut bacteria fermentation of fiber","Vitamin synthesis"],"correct":2,"explain":"The large intestine (colon) absorbs water and electrolytes from indigestible food residue. Resident gut bacteria ferment dietary fiber, producing short-chain fatty acids that nourish colonocytes and reduce cancer risk. No significant nutrient absorption occurs here."},{"q":"A teenage athlete needs more of which nutrient compared to a sedentary peer?","opts":["Fat","Vitamin C","Protein and overall calories","Sodium"],"correct":2,"explain":"Active teens need more total calories to fuel activity and more protein to support muscle repair and growth. Iron needs also increase for female athletes. Energy needs vary by sport intensity and training volume."},{"q":"Which condition results from excessive fluoride intake during tooth development?","opts":["Dental caries","Dental fluorosis (white spots/mottling on teeth)","Gingivitis","Enamel erosion from acid"],"correct":1,"explain":"Dental fluorosis occurs when children ingest too much fluoride during tooth development — causing white spots, streaks, or pitting on permanent teeth. Low levels are cosmetic only. Fluoride in water prevents caries; excess causes fluorosis."},{"q":"What is the 'thermic effect of food' for protein compared to carbohydrates?","opts":["Lower (0-3%) vs higher (5-10%)","Higher (20-30%) vs lower (5-10%)","The same for both (10%)","Protein has no thermic effect"],"correct":1,"explain":"Protein has a thermic effect of 20-30% — meaning 20-30% of protein calories are burned just in digestion and metabolism. Carbohydrates have a 5-10% thermic effect. This is one reason high-protein diets may aid weight management."},{"q":"Which test best assesses long-term blood glucose control over 2-3 months?","opts":["Fasting blood glucose","Oral glucose tolerance test","Hemoglobin A1c (HbA1c)","Random blood glucose"],"correct":2,"explain":"HbA1c (glycated hemoglobin) reflects average blood glucose over the past 2-3 months — the lifespan of red blood cells. Used to diagnose and monitor diabetes management. Normal: <5.7%; Prediabetes: 5.7-6.4%; Diabetes: ≥6.5%"},{"q":"What is the role of phytochemicals in nutrition?","opts":["They are essential nutrients like vitamins","Non-essential plant compounds with disease-preventive properties","They replace protein in plant-based diets","They are toxic when consumed in large amounts"],"correct":1,"explain":"Phytochemicals are non-nutrient plant compounds (lycopene, flavonoids, glucosinolates, etc.) that have health-protective properties but are not nutritionally essential. They function as antioxidants, anti-inflammatory agents, and cancer-protective compounds."}]);
  qz.hard=qz.hard.concat([{"q":"In nitrogen balance, what does a 'negative nitrogen balance' indicate?","opts":["More nitrogen consumed than excreted — muscle building","More nitrogen excreted than consumed — muscle breakdown","Equal nitrogen in and out — maintenance","Nitrogen being converted to fat"],"correct":1,"explain":"Negative nitrogen balance means more nitrogen is lost (excreted) than consumed. Since nitrogen comes almost entirely from protein, this indicates net protein breakdown — occurring during starvation, illness, severe injury, or inadequate protein intake."},{"q":"What is enterohepatic circulation and why does it matter for cholesterol?","opts":["Liver-to-intestine nutrient delivery","Recycling of bile salts from intestine back to liver — soluble fiber interrupts this, lowering cholesterol","The pathway of dietary fat absorption","The portal circulation carrying nutrients from intestine to liver"],"correct":1,"explain":"Enterohepatic circulation is the recycling of bile salts from the intestine back to the liver via the portal vein — 95% of bile salts are recycled. Soluble fiber binds bile salts in the intestine, interrupting recycling and forcing the liver to use cholesterol to make new bile salts, thus lowering blood cholesterol."},{"q":"What is gluconeogenesis, and which amino acid is the primary substrate?","opts":["Glucose storage as glycogen; branched-chain amino acids","New glucose synthesis from non-carbohydrate precursors; alanine is the primary amino acid substrate","Fat synthesis from glucose; glutamine","Ketone body synthesis from fatty acids; leucine"],"correct":1,"explain":"Gluconeogenesis is the synthesis of new glucose from non-carbohydrate precursors (amino acids, glycerol, lactate) primarily in the liver. Alanine from muscle protein breakdown is the most important amino acid substrate during fasting/starvation."},{"q":"The vitamin D synthesis pathway requires activation in which two organs?","opts":["Stomach and intestine","Liver (25-hydroxylation) and kidney (1-alpha-hydroxylation to active calcitriol)","Pancreas and liver","Skin and small intestine"],"correct":1,"explain":"Vitamin D synthesis: skin produces cholecalciferol (D3) from UV light. The LIVER adds a hydroxyl group (25-OH-D3/calcidiol). The KIDNEY adds another hydroxyl group to make 1,25-OH2-D3 (calcitriol) — the active hormone form that promotes calcium absorption."},{"q":"Hepcidin regulates iron homeostasis. Which condition would INCREASE hepcidin secretion?","opts":["Iron deficiency anemia","Hemochromatosis (iron overload) and inflammation","Blood loss and pregnancy","Vegetarian diet"],"correct":1,"explain":"Hepcidin is the master regulator of iron. High iron levels and inflammation INCREASE hepcidin, which degrades ferroportin (the iron exporter), reducing iron absorption. This explains anemia of chronic disease — inflammation raises hepcidin, blocking iron release even when stores are present."}]);
})();

(function(){
  if(!window.QB_MATH) return;
  var fc=window.QB_MATH.flashcards,qz=window.QB_MATH.quiz;
  if(!fc||!qz) return;
  ['easy','medium','hard'].forEach(function(d){if(!fc[d])fc[d]=[];if(!qz[d])qz[d]=[];});
  fc.easy=fc.easy.concat([{"term":"Ratio","def":"Comparison of two quantities using division — written as a:b or a/b","breakdown":"A 1:2 ratio of drug to saline means 1 part drug per 2 parts saline. Used for mixing solutions in healthcare"},{"term":"Proportion","def":"Two equal ratios — used to solve dosage problems: a/b = c/d","breakdown":"If 250mg in 5mL, how much for 375mg? Set up: 250/5 = 375/x → x = 7.5mL"},{"term":"Percentage","def":"Parts per hundred — converts to decimal by dividing by 100","breakdown":"25% = 25/100 = 0.25. A 5% saline solution has 5g salt per 100mL water"},{"term":"Metric system base units","def":"Meter (length), Gram (mass), Liter (volume) — decimals based on powers of 10","breakdown":"Healthcare uses metric: mg for drugs, mL for fluids, cm for height. Prefixes: kilo(1000×), centi(1/100), milli(1/1000), micro(1/1,000,000)"},{"term":"Kilogram to pound conversion","def":"1 kg = 2.2 lbs — used to calculate medication doses based on body weight","breakdown":"Patient weighs 154 lbs → 154 ÷ 2.2 = 70 kg. Drug dose: 5 mg/kg → 70 × 5 = 350 mg total dose"},{"term":"Celsius to Fahrenheit","def":"°F = (°C × 9/5) + 32 — healthcare uses both temperature scales","breakdown":"37°C × 9/5 = 66.6 + 32 = 98.6°F (normal body temp). Quick mental check: 37°C = 98.6°F, 40°C = 104°F (fever)"},{"term":"Fahrenheit to Celsius","def":"°C = (°F - 32) × 5/9","breakdown":"Patient temp 102.2°F → (102.2-32) × 5/9 = 70.2 × 5/9 = 39°C. Above 38°C (100.4°F) is fever in adults"},{"term":"Pulse rate calculation","def":"Count beats in 15 seconds, multiply by 4 — or count 30 sec × 2 for more accuracy","breakdown":"15-sec count: 18 beats × 4 = 72 bpm (normal). 30-sec count: 36 beats × 2 = 72 bpm. Count for 60 sec if irregular rhythm"},{"term":"Respiratory rate","def":"Count breaths per minute — one breath = one rise and fall of chest","breakdown":"Normal adult: 12-20 breaths/min. Count for 30 seconds × 2. Abnormal if <12 (bradypnea) or >20 (tachypnea)"},{"term":"Blood pressure reading","def":"Systolic (top number) / Diastolic (bottom number) in mmHg","breakdown":"120/80 mmHg: systolic = pressure during heartbeat, diastolic = pressure between beats. Read the gauge as it falls"},{"term":"Median","def":"Middle value when data is arranged in order","breakdown":"Data: 68, 72, 74, 76, 88. Median = 74. If even number: average the two middle values. Less affected by extreme outliers than mean"},{"term":"Mode","def":"Most frequently occurring value in a data set","breakdown":"Heart rates: 68, 72, 72, 74, 72, 80. Mode = 72. A data set can have no mode, one mode, or multiple modes"},{"term":"Range","def":"Difference between the highest and lowest values in a data set","breakdown":"Blood glucose readings: 85, 92, 104, 118, 145. Range = 145 - 85 = 60 mg/dL. Measures data spread"},{"term":"Fraction to decimal conversion","def":"Divide numerator by denominator: 3/4 = 3 ÷ 4 = 0.75","breakdown":"Drug concentration: 1/2 strength solution = 0.5 concentration. 3/8 = 0.375. Essential for dosage calculations"},{"term":"Decimal to percent","def":"Multiply decimal by 100: 0.75 × 100 = 75%","breakdown":"Solution strength: 0.9 = 90% (normal saline is 0.9% NaCl). Survival rate: 0.85 = 85% survival"},{"term":"24-hour time conversion","def":"To convert 1 PM onward: add 12. To convert back: subtract 12 if ≥1300","breakdown":"2:30 PM → 1430. 11:45 PM → 2345. 0930 → 9:30 AM. 1630 → 4:30 PM (1630 - 1200 = 4:30)"},{"term":"Fluid ounces to milliliters","def":"1 fl oz = 29.57 mL (approximately 30 mL)","breakdown":"Patient drinks 8 oz water: 8 × 30 = 240 mL. 1 cup = 8 oz = 240 mL. Used for fluid intake/output records"},{"term":"Drug concentration","def":"Amount of drug per unit volume — mg/mL or mg/tablet","breakdown":"500 mg in 250 mL = 2 mg/mL concentration. Need 750 mg → 750 ÷ 2 = 375 mL needed"},{"term":"Dosage formula","def":"Dose needed = (desired dose ÷ dose on hand) × quantity on hand","breakdown":"Need 250mg, have 500mg/tablet → (250÷500) × 1 tab = 0.5 tablet. Need 75mg, have 25mg/5mL → (75÷25)×5 = 15mL"},{"term":"Drops per minute (IV rate)","def":"gtts/min = (volume in mL × drop factor) ÷ time in minutes","breakdown":"1000mL over 8 hours, 15 gtts/mL factor: (1000 × 15) ÷ 480 min = 15000 ÷ 480 = 31.25 ≈ 31 gtts/min"},{"term":"Percent error","def":"|(Measured - True) ÷ True| × 100 — measures accuracy of measurement","breakdown":"True weight 70kg, scale reads 71kg: |71-70|/70 × 100 = 1/70 × 100 = 1.43% error. Used in lab quality control"},{"term":"Body surface area (BSA)","def":"Measurement used for chemotherapy and burn treatment dosing (m²)","breakdown":"BSA used because some drugs distribute based on body size. Mosteller formula: BSA = √(height cm × weight kg ÷ 3600)"}]);
  fc.medium=fc.medium.concat([{"term":"Dimensional analysis","def":"Method to convert units by multiplying by conversion fractions that equal 1","breakdown":"Convert 2.5 kg to mg: 2.5 kg × (1000g/1kg) × (1000mg/1g) = 2,500,000 mg = 2.5 × 10⁶ mg"},{"term":"IV flow rate calculation","def":"mL/hour = total volume ÷ total hours for infusion pumps","breakdown":"1 liter over 8 hours = 1000mL ÷ 8h = 125 mL/hr. Adjust if rate changes. Pumps use mL/hr; gravity uses gtts/min"},{"term":"Standard deviation","def":"Measure of how spread out data is around the mean — larger SD = more variation","breakdown":"Lab values: SD tells if results are tightly clustered or highly variable. Normal distribution: 68% within 1 SD, 95% within 2 SD"},{"term":"Percentile","def":"Position in a ranked distribution — 75th percentile = scored higher than 75% of the group","breakdown":"A child's height at 90th percentile: taller than 90% of peers. Used in growth charts. NOT the same as 90% correct"},{"term":"Caloric needs calculation (Harris-Benedict)","def":"BMR varies by sex, weight, height, age — then multiplied by activity factor","breakdown":"Basic: Women BMR ≈ 655 + (9.6×kg) + (1.8×cm) - (4.7×age). Sedentary: BMR × 1.2. Moderately active: BMR × 1.55"},{"term":"Concentration percentage calculation","def":"% = (grams of solute ÷ mL of solution) × 100","breakdown":"10g of NaCl in 1000mL = (10÷1000)×100 = 1% solution. Normal saline = 0.9% = 9g NaCl per 1000mL"},{"term":"Dilution calculation (C1V1=C2V2)","def":"Concentration 1 × Volume 1 = Concentration 2 × Volume 2","breakdown":"Dilute 70% alcohol to 50%: 70 × V1 = 50 × 100mL → V1 = 5000÷70 = 71.4 mL of 70% + 28.6 mL water"},{"term":"Rounding in healthcare","def":"Medication doses rounded to practical amounts — tablets to nearest half, liquids to nearest 0.1mL","breakdown":"Calculated dose 1.73 tablets → give 1.5 tablets (nearest half). 4.16 mL liquid → give 4.2 mL. NEVER round up significantly"},{"term":"Scientific notation","def":"Very large or small numbers expressed as a × 10ⁿ","breakdown":"1,000,000 cells = 1 × 10⁶. 0.00025 mg = 2.5 × 10⁻⁴ mg. Microbiology uses scientific notation for bacterial counts"},{"term":"Absolute risk vs relative risk","def":"Absolute: actual % difference. Relative: ratio of risks between groups","breakdown":"Drug reduces heart attack from 2% to 1%. Absolute risk reduction = 1%. Relative risk reduction = 50%. Headlines often report relative (more impressive)"},{"term":"Sensitivity and specificity","def":"Sensitivity: ability to identify true positives (catches disease). Specificity: ability to identify true negatives (rules out disease)","breakdown":"High sensitivity: few false negatives (good screening). High specificity: few false positives (good confirmation). Perfect test has both = 100%"},{"term":"Number needed to treat (NNT)","def":"NNT = 1 ÷ Absolute Risk Reduction — patients needed to treat to prevent one bad outcome","breakdown":"ARR = 5% (0.05): NNT = 1÷0.05 = 20. Must treat 20 patients to prevent 1 event. Lower NNT = more effective treatment"},{"term":"Apothecary to metric conversion","def":"1 grain = 65 mg, 1 dram = 4 mL, 1 ounce = 30 mL, 1 minim = 0.06 mL","breakdown":"Older prescriptions may use grains. Aspirin 5 grains = 5 × 65mg = 325mg. Most systems now use metric exclusively"},{"term":"Significant figures in healthcare","def":"Meaningful digits in a measurement — precision matters for dosing","breakdown":"Temperature 98.6°F: 3 significant figures. Drug dose 2.50 mg: 3 sig figs (the zero is significant). Recording more precision than instrument allows is incorrect"}]);
  fc.hard=fc.hard.concat([{"term":"Pharmacokinetics: first-order kinetics","def":"Drug elimination rate proportional to concentration — constant percentage eliminated per time","breakdown":"Most drugs follow first-order: if half-life = 4hr, 100mg → 50mg (4hr) → 25mg (8hr) → 12.5mg (12hr). Predictable"},{"term":"Half-life calculation","def":"Time for drug concentration to fall by 50% — 5 half-lives for full elimination","breakdown":"Half-life 6hr: drug given at 0800. By 2000 (12hr/2 half-lives): 25% remains. By 0200 (18hr/3 half-lives): 12.5% remains"},{"term":"Loading dose vs maintenance dose","def":"Loading: large initial dose to rapidly achieve therapeutic level. Maintenance: smaller doses to sustain level","breakdown":"Loading dose = target concentration × volume of distribution. Given when rapid effect needed (e.g., digoxin, antibiotics)"},{"term":"Confidence interval interpretation","def":"Range that likely contains the true population value — 95% CI means 95% confidence the true value falls within","breakdown":"BP drug study: mean reduction 5.2 mmHg (95% CI: 3.1-7.3). True effect likely between 3.1 and 7.3 mmHg. If CI includes 0, result not significant"},{"term":"Pearson correlation coefficient (r)","def":"Measures strength and direction of linear relationship: r ranges from -1 to +1","breakdown":"r = +1: perfect positive. r = -1: perfect negative. r = 0: no relationship. r = 0.8: strong positive correlation. Healthcare research uses r² (variance explained)"}]);
  qz.easy=qz.easy.concat([{"q":"A patient weighs 176 pounds. What is their weight in kilograms?","opts":["60 kg","80 kg","88 kg","100 kg"],"correct":1,"explain":"176 lbs ÷ 2.2 = 80 kg. Memorize: divide pounds by 2.2 to get kilograms. This conversion is used constantly for weight-based medication dosing."},{"q":"Normal body temperature is 37°C. What is this in Fahrenheit?","opts":["96.8°F","98.6°F","100.4°F","102.2°F"],"correct":1,"explain":"°F = (37 × 9/5) + 32 = (37 × 1.8) + 32 = 66.6 + 32 = 98.6°F. Memorize this pair: 37°C = 98.6°F. A temperature of 40°C = 104°F indicates significant fever."},{"q":"A nurse counts 18 pulse beats in 15 seconds. What is the pulse rate per minute?","opts":["54 bpm","72 bpm","90 bpm","108 bpm"],"correct":1,"explain":"18 beats × 4 (to convert 15 seconds to 1 minute) = 72 bpm. Normal adult range is 60-100 bpm. This is the most common clinical pulse counting method."},{"q":"What time is 2:30 PM in military (24-hour) time?","opts":["0230","1230","1430","2230"],"correct":2,"explain":"For PM times after 12 PM, add 12: 2:30 PM + 12 = 14:30 = 1430. Morning times stay the same (0800 = 8:00 AM). Midnight = 0000."},{"q":"A medication order reads 500mg. The tablets on hand are 250mg each. How many tablets should be given?","opts":["0.5 tablet","1 tablet","2 tablets","4 tablets"],"correct":2,"explain":"Using the dosage formula: desired ÷ on hand × quantity = 500 ÷ 250 × 1 tablet = 2 tablets."},{"q":"The mean of these five temperatures is: 98.2, 98.6, 99.0, 98.8, 99.4","opts":["98.6°F","98.8°F","99.0°F","98.2°F"],"correct":1,"explain":"Mean = sum ÷ count = (98.2 + 98.6 + 99.0 + 98.8 + 99.4) ÷ 5 = 494.0 ÷ 5 = 98.8°F."},{"q":"1 fluid ounce equals approximately how many milliliters?","opts":["10 mL","15 mL","30 mL","60 mL"],"correct":2,"explain":"1 fluid ounce ≈ 30 mL (exactly 29.57 mL). A standard 8 oz cup = 240 mL. Used for recording oral fluid intake in healthcare settings."},{"q":"A patient's BMI is 27. Which category does this fall in?","opts":["Underweight","Normal weight","Overweight","Obese"],"correct":2,"explain":"BMI 25-29.9 = Overweight. BMI categories: <18.5 underweight, 18.5-24.9 normal, 25-29.9 overweight, ≥30 obese. BMI is a screening tool, not a diagnosis."},{"q":"What percentage is equivalent to the fraction 3/4?","opts":["25%","50%","75%","80%"],"correct":2,"explain":"3 ÷ 4 = 0.75 = 75%. To convert any fraction to percent: divide numerator by denominator, then multiply by 100."},{"q":"A patient's blood pressure is recorded as 130/85 mmHg. What is the systolic pressure?","opts":["85 mmHg","130 mmHg","215 mmHg","45 mmHg"],"correct":1,"explain":"In a blood pressure reading, the TOP number (130) is the systolic pressure — pressure during heart contraction. The BOTTOM number (85) is diastolic — pressure between beats."},{"q":"What is the median of: 62, 68, 72, 78, 84?","opts":["62","68","72","78"],"correct":2,"explain":"Median = middle value when arranged in order. The list already has 5 values in order: 62, 68, 72, 78, 84. The middle (3rd) value is 72."},{"q":"Normal urine output per hour for adults is at least:","opts":["10 mL/hr","30 mL/hr","60 mL/hr","100 mL/hr"],"correct":1,"explain":"Minimum normal urine output is 30 mL/hr (0.5 mL/kg/hr). Below this indicates possible dehydration, kidney impairment, or poor perfusion. This is a critical clinical monitoring value."},{"q":"A drug is ordered at 10 mg/kg for a child weighing 30 kg. What total dose is needed?","opts":["30 mg","100 mg","300 mg","3,000 mg"],"correct":2,"explain":"10 mg/kg × 30 kg = 300 mg total dose. Weight-based dosing is the standard in pediatrics. Always confirm with pharmacy."},{"q":"How many milligrams are in 1 gram?","opts":["10 mg","100 mg","1,000 mg","10,000 mg"],"correct":2,"explain":"1 gram = 1,000 milligrams. The prefix 'milli' = 1/1000. So 1g = 1000 mg. 1 kg = 1000 g = 1,000,000 mg. Essential for medication dosing."},{"q":"What is the range of these pulse readings: 64, 72, 68, 80, 76?","opts":["8","12","16","20"],"correct":2,"explain":"Range = highest - lowest = 80 - 64 = 16 bpm. Range measures the spread of data. It is simple but sensitive to extreme values."},{"q":"A patient drinks 6 fluid ounces of juice. How many mL is this?","opts":["60 mL","120 mL","180 mL","240 mL"],"correct":2,"explain":"6 fl oz × 30 mL/oz = 180 mL. Fluid intake is recorded in mL in healthcare. Always convert ounces to mL for accurate I&O documentation."},{"q":"What is 15% of 80?","opts":["8","12","15","20"],"correct":1,"explain":"15% of 80 = 0.15 × 80 = 12. In healthcare: a 15% solution means 15g per 100mL. Percentage calculations are used in drug concentrations and statistics."},{"q":"Convert 0730 military time to standard time.","opts":["7:30 PM","7:30 AM","12:30 AM","19:30"],"correct":1,"explain":"Times 0001-1159 in military time convert directly: 0730 = 7:30 AM. Times 1300-2359 subtract 12: 1900 = 7:00 PM. 0000 = midnight."},{"q":"A patient's temperature is 39.4°C. Convert to Fahrenheit.","opts":["100.4°F","101.4°F","102.9°F","103.9°F"],"correct":2,"explain":"°F = (39.4 × 9/5) + 32 = (39.4 × 1.8) + 32 = 70.92 + 32 = 102.92°F ≈ 102.9°F. A high fever requiring clinical attention."},{"q":"What does a proportion allow you to do in healthcare math?","opts":["Add unlike units","Solve for unknown values when ratios are equal","Convert Celsius to Fahrenheit","Calculate BMI"],"correct":1,"explain":"A proportion states that two ratios are equal (a/b = c/d), allowing you to solve for an unknown value. Essential for dosage calculations: if 500mg is in 10mL, how much liquid for 750mg? Set up 500/10 = 750/x → x = 15 mL."}]);
  qz.medium=qz.medium.concat([{"q":"An IV is ordered to run 500 mL over 4 hours. The drop factor is 20 gtts/mL. What is the flow rate in gtts/min?","opts":["31 gtts/min","42 gtts/min","10 gtts/min","25 gtts/min"],"correct":1,"explain":"Formula: (Volume × Drop factor) ÷ Time in minutes. (500 × 20) ÷ 240 minutes = 10,000 ÷ 240 = 41.7 ≈ 42 gtts/min."},{"q":"A drug has a half-life of 4 hours. A patient receives 200mg at 8 AM. How much remains at 4 PM?","opts":["100 mg","50 mg","25 mg","12.5 mg"],"correct":1,"explain":"8 AM to 4 PM = 8 hours = 2 half-lives. After 1 half-life (4hr): 100mg. After 2 half-lives (8hr): 50mg. Each half-life reduces amount by 50%."},{"q":"A child's height is at the 85th percentile. What does this mean?","opts":["The child is 85 cm tall","The child is taller than 85% of peers the same age","The child scored 85% on a growth test","The child needs 85 more cm to reach adult height"],"correct":1,"explain":"85th percentile means the child is taller than 85% of children the same age and sex. Percentiles describe position within a distribution, not actual measurements or test scores."},{"q":"A solution is prepared by dissolving 5g of drug in 200mL of water. What is the percentage concentration?","opts":["1%","2.5%","5%","10%"],"correct":1,"explain":"% concentration = (grams ÷ mL) × 100 = (5 ÷ 200) × 100 = 0.025 × 100 = 2.5%. This is read as 2.5% w/v (weight/volume) concentration."},{"q":"A patient's urine output over 8 hours is 320 mL. Is this within normal range?","opts":["No, too low (below 240mL minimum)","Yes, normal (240-480mL expected)","No, too high","Cannot determine without weight"],"correct":1,"explain":"Normal minimum urine output = 30 mL/hr. Over 8 hours: 30 × 8 = 240 mL minimum. 320 mL ÷ 8 hrs = 40 mL/hr, which is within normal range (30-60 mL/hr is typical)."},{"q":"Using C1V1 = C2V2, how many mL of a 70% solution is needed to make 500 mL of a 35% solution?","opts":["175 mL","250 mL","350 mL","500 mL"],"correct":1,"explain":"C1V1 = C2V2 → 70 × V1 = 35 × 500 → V1 = 17,500 ÷ 70 = 250 mL. Add water to make total volume 500 mL. Used in lab and pharmacy dilution calculations."},{"q":"A clinical study reports sensitivity of 95% and specificity of 80% for a diagnostic test. What does 80% specificity mean?","opts":["80% of sick patients test positive","80% of healthy patients correctly test negative","80% accuracy overall","80% chance the positive result is correct"],"correct":1,"explain":"Specificity = true negative rate. 80% specificity means the test correctly identifies 80% of healthy people as disease-free. The other 20% are false positives. High specificity is needed for confirmatory tests."},{"q":"What is 2.5 grams converted to micrograms?","opts":["2,500 mcg","25,000 mcg","250,000 mcg","2,500,000 mcg"],"correct":3,"explain":"1 gram = 1,000 mg = 1,000,000 mcg. So 2.5 g = 2.5 × 1,000,000 = 2,500,000 mcg. Always use dimensional analysis: 2.5g × (1000mg/1g) × (1000mcg/1mg) = 2,500,000 mcg."},{"q":"A patient's blood glucose readings over a week are: 95, 102, 98, 115, 89, 107, 110. What is the mean?","opts":["98 mg/dL","102.3 mg/dL","107 mg/dL","110 mg/dL"],"correct":1,"explain":"Mean = sum ÷ count = (95+102+98+115+89+107+110) ÷ 7 = 716 ÷ 7 = 102.3 mg/dL. The mean blood glucose helps assess overall glycemic control."},{"q":"A drug label reads 250 mg/5 mL. A patient needs 375 mg. How many mL should be given?","opts":["5 mL","7.5 mL","10 mL","15 mL"],"correct":1,"explain":"Dosage formula: (desired ÷ on hand) × quantity = (375 ÷ 250) × 5 mL = 1.5 × 5 = 7.5 mL. Always double-check by unit analysis: 7.5 mL × 250mg/5mL = 375 mg ✓"},{"q":"A research study shows a treatment reduces infection rate from 8% to 4%. What is the relative risk reduction?","opts":["4%","50%","200%","400%"],"correct":1,"explain":"Relative risk reduction = absolute reduction ÷ control rate = 4% ÷ 8% = 0.5 = 50%. Absolute risk reduction = 4%. Relative risk reduction (50%) sounds more impressive — always check both when evaluating research."}]);
  qz.hard=qz.hard.concat([{"q":"A patient needs 1.5 g of a drug. Available: 500 mg tablets. How many tablets are needed?","opts":["1.5 tablets","2 tablets","3 tablets","4 tablets"],"correct":2,"explain":"Convert: 1.5g = 1500mg. Tablets needed = 1500mg ÷ 500mg/tablet = 3 tablets. Always convert to same units first, then apply dosage formula."},{"q":"Drug A has a half-life of 12 hours and is given at 0600. After how many hours will 87.5% of the drug be eliminated?","opts":["12 hours","24 hours","36 hours","48 hours"],"correct":2,"explain":"After 1 half-life: 50% eliminated, 50% remains. After 2 half-lives: 75% eliminated, 25% remains. After 3 half-lives: 87.5% eliminated, 12.5% remains. 3 × 12hr = 36 hours."},{"q":"A 95% confidence interval for a drug's blood pressure reduction is -8 to -2 mmHg. What can you conclude?","opts":["The drug has no effect","The drug significantly reduces BP (CI does not include 0)","More studies are needed before any conclusion","The drug raises BP in 5% of patients"],"correct":1,"explain":"A 95% CI that does NOT include zero indicates a statistically significant result. The entire CI (-8 to -2) is on the negative side, meaning the drug consistently reduces BP. If the CI included 0, the result would not be statistically significant."},{"q":"A nurse must infuse 1000 mL of NS at 125 mL/hr using a pump. The infusion started at 0900. When will it finish?","opts":["1700","1800","1900","2000"],"correct":0,"explain":"1000 mL ÷ 125 mL/hr = 8 hours. 0900 + 8 hours = 1700 (5:00 PM). Time-to-completion calculations are essential for planning nursing care and scheduling next bag changes."}]);
})();

(function(){
  if(!window.QB_CAREERS) return;
  var fc=window.QB_CAREERS.flashcards,qz=window.QB_CAREERS.quiz;
  if(!fc||!qz) return;
  ['easy','medium','hard'].forEach(function(d){if(!fc[d])fc[d]=[];if(!qz[d])qz[d]=[];});
  fc.easy=fc.easy.concat([{"term":"Primary care physician","def":"First-contact doctor for routine and preventive care — refers to specialists","breakdown":"Family medicine, internal medicine, pediatrics, OB/GYN are primary care fields. The 'medical home' for patients"},{"term":"Specialist","def":"Physician with advanced training in a specific body system or disease type","breakdown":"Cardiologist (heart), neurologist (nervous system), orthopedist (bones), dermatologist (skin). Seen after PCP referral"},{"term":"Physician Assistant (PA)","def":"Medical professional licensed to practice medicine with physician supervision — diagnoses, treats, prescribes","breakdown":"Master's level training. Works in all medical and surgical specialties. More flexible than physicians for many healthcare settings"},{"term":"Certified Nursing Assistant (CNA)","def":"Provides basic patient care — bathing, feeding, vital signs, repositioning — under nurse supervision","breakdown":"State-approved training program (4-12 weeks). Entry-level healthcare. Common pathway to nursing. Long-term care and hospitals"},{"term":"Emergency Medical Technician (EMT)","def":"Provides emergency medical care in the field and transport to hospital","breakdown":"EMT-Basic: airway, bleeding, fractures, CPR, basic medications. Paramedic: advanced level — IVs, medications, intubation, advanced procedures"},{"term":"Medical Laboratory Scientist (MLS)","def":"Analyzes blood, tissue, body fluids for disease diagnosis — runs laboratory tests","breakdown":"Bachelor's degree. Also called clinical laboratory scientist (CLS). Performs CBC, cultures, coagulation tests, blood typing"},{"term":"Podiatrist (DPM)","def":"Diagnoses and treats conditions of the foot, ankle, and lower leg","breakdown":"4-year podiatric medical school. Performs foot surgery. Manages diabetic foot complications — a leading cause of amputation"},{"term":"Dietitian/Nutritionist (RD/RDN)","def":"Assesses nutritional needs, creates medical nutrition therapy plans, counsels on diet","breakdown":"Bachelor's degree + supervised internship + RD exam. Works in hospitals, schools, public health. Medical nutrition therapy for diabetes, kidney disease, eating disorders"},{"term":"Social Worker (MSW/LCSW)","def":"Addresses social, psychological, and economic factors affecting health — connects patients to resources","breakdown":"Master's degree. In hospitals: discharge planning, insurance navigation, mental health support, abuse reporting"}]);
  fc.medium=fc.medium.concat([{"term":"Interdisciplinary team","def":"Healthcare team from different professions collaborating for patient care","breakdown":"Hospital team: physician, NP/PA, RN, pharmacist, PT/OT, social worker, dietitian. Better outcomes than siloed individual care"},{"term":"Continuing education (CE)","def":"Required education to maintain professional licensure — healthcare fields require regular updates","breakdown":"Nurses: 20-30 CE hours per 2-year license renewal. Physicians: 50 CME hours/year. Ensures providers stay current with evidence"},{"term":"National Provider Identifier (NPI)","def":"Unique 10-digit number identifying healthcare providers for billing and administration","breakdown":"Required for all healthcare providers who bill insurance. Used in HIPAA transactions. Covered entities must use NPI in claims"},{"term":"Credentials and credentialing","def":"Process of verifying a provider's qualifications before granting hospital privileges","breakdown":"Hospital checks: medical school, residency, board certification, malpractice history, references. Must be renewed every 2 years"},{"term":"Health Maintenance Organization (HMO)","def":"Insurance plan requiring primary care physician referrals to see specialists — lower cost, less flexibility","breakdown":"Patient selects a PCP who coordinates care. Must use in-network providers or pay full cost. Lower premiums than PPO"},{"term":"Preferred Provider Organization (PPO)","def":"Insurance plan allowing patients to see any provider — higher cost, more flexibility","breakdown":"Can see specialists without referral. Out-of-network coverage (at higher cost). More expensive premiums than HMO"},{"term":"Fee-for-service","def":"Payment model where providers are paid for each service performed — incentivizes volume over value","breakdown":"Traditional model. Criticized for incentivizing unnecessary procedures. Being replaced by value-based care models"},{"term":"Value-based care","def":"Payment model linking provider reimbursement to patient outcomes and quality rather than volume","breakdown":"Accountable Care Organizations (ACOs), bundled payments, pay-for-performance. Goal: better outcomes at lower cost"},{"term":"HIPAA Privacy Rule","def":"Federal regulation protecting patient health information — who can see it and how it can be shared","breakdown":"Patients have right to access their records. Providers can share for treatment, payment, operations. Violations: fines up to $1.9M/year"},{"term":"Informed consent","def":"Patient's right to understand and agree to treatment before it is performed","breakdown":"Must include: what procedure is, why needed, risks, benefits, alternatives, right to refuse. Patient must be competent to consent. Written for surgery"},{"term":"Advance directive","def":"Legal document stating a patient's wishes for medical treatment if they cannot speak for themselves","breakdown":"Living will: specific treatment preferences. Healthcare proxy/POA: designates decision-maker. DNR: do not resuscitate order"},{"term":"Medical malpractice","def":"Professional negligence by a healthcare provider that causes patient harm","breakdown":"Four elements: duty, breach, causation, damages. Requires expert testimony. Malpractice insurance required for most providers"},{"term":"Burnout in healthcare","def":"Chronic occupational stress causing exhaustion, cynicism, and reduced professional efficacy","breakdown":"Affects 50%+ of physicians, 35%+ of nurses. Leads to medical errors, turnover, substance abuse. COVID significantly worsened rates"},{"term":"Cultural competence","def":"Ability to effectively serve patients from diverse cultural backgrounds — respecting values and beliefs","breakdown":"Essential skill: over 400 languages spoken in U.S. healthcare. Includes: health literacy, interpreter services, avoiding assumptions"},{"term":"Health literacy","def":"Patient's ability to understand and use health information to make informed decisions","breakdown":"Only 12% of U.S. adults have proficient health literacy. Poor health literacy linked to worse outcomes. Providers must use plain language"},{"term":"Case management","def":"Coordinating care across providers and settings for patients with complex needs","breakdown":"Case managers are RNs or social workers. Ensure appropriate care transitions, prevent readmissions, coordinate resources"},{"term":"Discharge planning","def":"Preparing patient for safe transition from hospital to next care setting","breakdown":"Begins at admission. Includes: home care needs, medication reconciliation, follow-up appointments, patient/family education"}]);
  fc.hard=fc.hard.concat([{"term":"Triple aim (IHI)","def":"Institute for Healthcare Improvement's framework: better patient experience, better population health, lower per capita cost","breakdown":"Proposed by Don Berwick in 2008. Now 'Quadruple Aim' adds: improving provider experience (reducing burnout)"},{"term":"Social determinants of health (SDOH)","def":"Non-medical factors influencing health: housing, food, education, income, social support","breakdown":"Account for 30-55% of health outcomes. Poverty, food insecurity, unsafe housing have larger health impact than clinical care alone"},{"term":"Accountable Care Organization (ACO)","def":"Group of providers sharing responsibility for quality and cost of care for a defined population","breakdown":"CMS Medicare Shared Savings Program. ACOs rewarded for keeping patients healthy and avoiding unnecessary hospitalizations"},{"term":"Magnet Recognition Program","def":"ANCC designation for hospitals demonstrating nursing excellence and superior patient outcomes","breakdown":"Magnet hospitals have better nurse retention, lower mortality, higher patient satisfaction. Requires shared governance, evidence-based practice"},{"term":"Nurse-to-patient ratio","def":"Number of patients assigned to each nurse — affects safety and outcomes","breakdown":"California only U.S. state mandating ratios (1:5 med-surg, 1:2 ICU). Studies show each additional patient per RN increases 30-day mortality 7%"}]);
  qz.easy=qz.easy.concat([{"q":"Which healthcare professional is typically the first point of contact for routine medical care?","opts":["Specialist physician","Emergency physician","Primary care physician","Surgeon"],"correct":2,"explain":"Primary care physicians (family medicine, internal medicine, pediatrics) are the first point of contact for routine and preventive care. They diagnose common conditions and refer patients to specialists when needed."},{"q":"What does 'scope of practice' define in healthcare?","opts":["A provider's salary range","The geographic area where a provider can work","The legal boundaries of what a provider is allowed to do based on their training and license","The number of patients a provider can see per day"],"correct":2,"explain":"Scope of practice defines the legal boundaries of what a healthcare professional can do based on their education, training, and license. It varies by profession and state. For example, CNAs can take vital signs but cannot administer medications."},{"q":"Which healthcare role focuses on helping patients perform daily activities after illness or injury?","opts":["Physical Therapist","Occupational Therapist","Respiratory Therapist","Speech-Language Pathologist"],"correct":1,"explain":"Occupational Therapists (OT) help patients regain ability to perform daily activities (occupations) like dressing, cooking, and working. PTs focus on movement and strength. RTs focus on breathing. SLPs focus on speech and swallowing."},{"q":"HIPAA primarily protects which type of patient information?","opts":["Financial records","Protected Health Information (PHI)","Employment records","Credit history"],"correct":1,"explain":"HIPAA (Health Insurance Portability and Accountability Act) protects Protected Health Information (PHI) — any information that can identify a patient and relates to their health condition, treatment, or payment. This includes medical records, test results, and billing information."},{"q":"What is the primary difference between an RN and an LPN/LVN?","opts":["RNs work in hospitals; LPNs work in nursing homes only","RNs have more education and a broader scope of practice than LPNs","LPNs can prescribe medications; RNs cannot","They have exactly the same role with different titles"],"correct":1,"explain":"RNs (Registered Nurses) have more education (associate or bachelor's degree + NCLEX-RN) and a broader scope of practice than LPNs/LVNs (Licensed Practical/Vocational Nurses). LPNs provide basic nursing care under RN or physician supervision."},{"q":"Which healthcare professional specializes in analyzing blood and body fluid samples?","opts":["Phlebotomist","Medical Laboratory Scientist","Radiologic Technologist","Surgical Technologist"],"correct":1,"explain":"Medical Laboratory Scientists (MLS) analyze blood, tissue, and body fluid samples to diagnose disease. They run tests like CBCs, cultures, and blood typing. Phlebotomists draw the blood; MLS analyze it."},{"q":"What is informed consent?","opts":["A patient's permission for a provider to bill insurance","Patient's right to understand and agree to treatment before it is performed","Written permission from family members for surgery","Insurance approval for a medical procedure"],"correct":1,"explain":"Informed consent is the patient's right to understand a procedure's purpose, risks, benefits, and alternatives before agreeing to it. Patients must be competent to consent. For surgery, written consent is required. Patients always have the right to refuse."},{"q":"An advance directive primarily addresses which situation?","opts":["What to do if a patient cannot pay for care","Patient's treatment wishes if they become unable to communicate","How to handle a medical malpractice claim","Employment benefits for healthcare workers"],"correct":1,"explain":"An advance directive states a patient's wishes for medical treatment if they cannot speak for themselves (unconscious, severe dementia, etc.). Includes living wills (specific treatment preferences) and healthcare proxies (designating a decision-maker)."},{"q":"What degree does a Nurse Practitioner (NP) require?","opts":["Associate degree","Bachelor's degree","Master's or doctoral degree","Medical Doctor (MD) degree"],"correct":2,"explain":"Nurse Practitioners require master's or doctoral-level education beyond their RN license. They can diagnose, treat, and prescribe medications. In many states, NPs can practice independently without physician supervision."},{"q":"What is the primary role of a Respiratory Therapist?","opts":["Administer physical rehabilitation exercises","Manage breathing disorders and ventilator support","Perform surgical procedures","Analyze laboratory specimens"],"correct":1,"explain":"Respiratory Therapists (RTs) manage breathing disorders — they operate mechanical ventilators, administer breathing treatments (nebulizers), perform pulmonary function tests, and assist with intubation. Critical in ICUs and with patients who have lung conditions."},{"q":"Which insurance model requires a PCP referral to see a specialist?","opts":["PPO (Preferred Provider Organization)","HMO (Health Maintenance Organization)","Medicare","Medicaid"],"correct":1,"explain":"HMOs (Health Maintenance Organizations) require patients to select a primary care physician who coordinates all care and provides referrals to specialists. HMOs are generally less expensive but offer less flexibility than PPOs."},{"q":"What does EHR stand for in healthcare?","opts":["Emergency Health Response","Electronic Health Record","Essential Health Requirement","Extended Hospital Record"],"correct":1,"explain":"EHR stands for Electronic Health Record — the digital version of a patient's medical records shared across providers and healthcare systems. EHRs replaced paper charts and enable care coordination, reduce errors, and allow data analysis."},{"q":"Which health professional has a Doctorate of Pharmacy (PharmD) degree?","opts":["Physician","Pharmacist","Physical Therapist","Podiatrist"],"correct":1,"explain":"Pharmacists earn a Doctorate of Pharmacy (PharmD) — a 4-year professional degree. They dispense medications, counsel patients, check for drug interactions, and manage medication therapy. Clinical pharmacists are essential members of hospital care teams."},{"q":"What is burnout in the healthcare context?","opts":["Physical exhaustion from long shifts","Chronic occupational stress causing exhaustion, cynicism, and reduced professional efficacy","A term for hospital budget deficits","Equipment failure from overuse"],"correct":1,"explain":"Healthcare burnout is a syndrome of chronic occupational stress resulting in emotional exhaustion, depersonalization (cynicism), and reduced sense of personal accomplishment. It affects 50%+ of physicians and 35%+ of nurses, contributing to medical errors and turnover."},{"q":"What is the role of a case manager in healthcare?","opts":["Managing hospital finances","Coordinating care across providers and settings for complex patients","Performing surgical case setups","Managing medical staff scheduling"],"correct":1,"explain":"Case managers (usually RNs or social workers) coordinate care for patients with complex needs across providers and settings — ensuring smooth transitions, preventing readmissions, connecting patients with community resources, and managing insurance authorizations."},{"q":"Cultural competence in healthcare primarily means:","opts":["Speaking multiple languages fluently","Effectively serving patients from diverse cultural backgrounds by respecting their values and beliefs","Only treating patients from the same culture as the provider","Requiring patients to adopt mainstream healthcare values"],"correct":1,"explain":"Cultural competence means the ability to effectively serve patients from diverse cultural backgrounds, respecting their values, beliefs, and communication styles. This includes using interpreter services, understanding cultural health practices, and avoiding stereotypical assumptions."}]);
  qz.medium=qz.medium.concat([{"q":"A patient refuses a recommended blood transfusion due to religious beliefs. What is the appropriate response?","opts":["Administer the transfusion anyway — the patient's life is at risk","Respect the patient's right to refuse — document the refusal and explore alternatives","Contact a judge to override the decision","Discharge the patient immediately"],"correct":1,"explain":"Competent adults have the absolute right to refuse medical treatment, even life-saving treatment. The provider must document the refusal, ensure the patient understands the risks, and explore acceptable alternatives. This is a fundamental principle of patient autonomy and informed consent."},{"q":"What is the Triple Aim framework developed by the Institute for Healthcare Improvement?","opts":["Safety, Quality, Efficiency","Better patient experience, better population health, lower per capita cost","Access, Quality, Affordability","Prevention, Treatment, Recovery"],"correct":1,"explain":"The Triple Aim (IHI, 2008) has three interdependent goals: (1) improve patient experience of care, (2) improve population health, (3) reduce per capita healthcare costs. Often expanded to 'Quadruple Aim' by adding improving provider experience."},{"q":"Which factor is considered a Social Determinant of Health (SDOH)?","opts":["A patient's genetic predisposition to cancer","Access to nutritious food and safe housing","A patient's cholesterol level","The effectiveness of a prescribed medication"],"correct":1,"explain":"Social Determinants of Health are non-medical factors that influence health outcomes: food security, housing stability, education, income, social support, transportation, and neighborhood safety. SDOH account for an estimated 30-55% of health outcomes."},{"q":"A Physician Assistant differs from a Nurse Practitioner primarily in that:","opts":["PAs can prescribe controlled substances; NPs cannot","PAs come from a medical model education; NPs from a nursing model","NPs require physician supervision in all states; PAs do not","PAs hold doctoral degrees; NPs hold master's degrees"],"correct":1,"explain":"PAs are trained in the medical model (similar to physicians, disease-focused). NPs come from nursing education and a nursing model emphasizing holistic care. Both can diagnose, treat, and prescribe; however, their educational frameworks and philosophies differ."},{"q":"What does 'value-based care' mean in contrast to 'fee-for-service'?","opts":["Patients pay based on how much they value the care received","Providers are paid based on patient outcomes and quality rather than volume of services","Care is provided at a discount for uninsured patients","Services are billed based on their market value"],"correct":1,"explain":"Value-based care links provider payment to patient outcomes, quality metrics, and efficiency rather than volume. Fee-for-service pays for each service regardless of outcome. Value-based models (ACOs, bundled payments) incentivize keeping patients healthy and avoiding unnecessary procedures."},{"q":"A hospital is seeking Magnet Recognition. What does this designation indicate?","opts":["The hospital uses magnetic resonance imaging","The hospital has demonstrated nursing excellence and superior patient outcomes","The hospital attracts the most patients in the region","The hospital has the strongest financial performance"],"correct":1,"explain":"Magnet Recognition (from ANCC) is the gold standard for nursing excellence. Magnet hospitals demonstrate strong nursing leadership, shared governance, evidence-based practice, and consistently better patient outcomes including lower mortality and higher patient satisfaction."},{"q":"Telehealth expanded significantly during COVID-19. What is a major ongoing limitation?","opts":["Telehealth can only treat infectious diseases","Not all conditions are appropriate for remote care and reimbursement rules are still evolving","Telehealth requires patients to come to a clinic","Telehealth is only available to patients with smartphones"],"correct":1,"explain":"While telehealth dramatically improves access — especially for rural patients — limitations include: not all conditions can be safely managed remotely (requires physical exam), reimbursement policies vary by payer and state, technology barriers exist for elderly or low-income patients, and licensure across state lines is complex."},{"q":"What is health literacy and why does it matter clinically?","opts":["A measure of how much a provider knows about health","A patient's ability to understand and use health information to make decisions — poor health literacy leads to worse outcomes","The amount of health education a patient has completed","A provider's ability to explain diagnoses clearly"],"correct":1,"explain":"Health literacy is a patient's ability to obtain, process, and understand health information needed to make appropriate decisions. Only 12% of U.S. adults have proficient health literacy. Poor health literacy is linked to worse chronic disease management, more hospitalizations, and lower medication adherence."}]);
  qz.hard=qz.hard.concat([{"q":"A state law gives NPs full practice authority. What does this mean clinically?","opts":["NPs can perform surgery independently","NPs can diagnose, treat, and prescribe without physician oversight in that state","NPs earn the same salary as physicians","NPs must consult physicians for all complex cases"],"correct":1,"explain":"Full practice authority (granted by 26+ states) allows NPs to evaluate patients, diagnose conditions, interpret tests, initiate treatment plans, and prescribe medications without a physician collaboration agreement. Reduces barriers in areas with physician shortages."},{"q":"A hospital implements a 1:4 nurse-to-patient ratio. Based on research, what outcome would you predict?","opts":["No change — ratios don't affect outcomes","Increased costs with no quality improvement","Reduced patient mortality and improved nurse retention","Increased nurse burnout from higher expectations"],"correct":2,"explain":"Research consistently shows lower nurse-to-patient ratios improve outcomes. Aiken et al. found each additional patient per nurse is associated with 7% increased 30-day mortality and 23% higher nurse burnout odds. California mandated ratios reduced mortality and improved nurse retention."},{"q":"What is an Accountable Care Organization (ACO) and how does it differ from a traditional hospital?","opts":["An ACO is a specialty hospital for complex care","An ACO is a group of providers sharing responsibility for quality and cost of care for a defined population, rewarded for keeping patients healthy","An ACO is a government agency overseeing hospital compliance","An ACO is an insurance company that owns hospitals"],"correct":1,"explain":"ACOs are networks of doctors, hospitals, and other providers who voluntarily coordinate care for Medicare patients. If they provide high-quality care while spending less than projected, they share in the savings. This incentivizes prevention and care coordination rather than volume."}]);
})();


(function(){
  if(!window.QB_HEALTHY_LIVING) return;
  var fc=window.QB_HEALTHY_LIVING.flashcards,qz=window.QB_HEALTHY_LIVING.quiz;
  if(!fc||!qz) return;
  ['easy','medium','hard'].forEach(function(d){if(!fc[d])fc[d]=[];if(!qz[d])qz[d]=[];});
  fc.easy=fc.easy.concat([{"term":"Health triangle","def":"Three dimensions of health: physical, mental/emotional, and social","breakdown":"All three must be balanced for total wellness. Neglecting one affects the others. HOSA Healthy Living tests all three dimensions"},{"term":"Physical health","def":"The condition of the body — fitness, nutrition, sleep, avoiding harmful substances","breakdown":"Components: cardiovascular fitness, muscular strength/endurance, flexibility, body composition. Maintained through exercise and nutrition"},{"term":"Social health","def":"Ability to form satisfying interpersonal relationships and adapt to social situations","breakdown":"Strong social connections linked to better immune function, lower mortality, greater happiness. Loneliness is a public health crisis"},{"term":"Body composition","def":"Ratio of fat mass to lean mass (muscle, bone, organs, water)","breakdown":"More meaningful than weight alone. Measured by: DEXA scan, hydrostatic weighing, BodPod, bioelectric impedance, skinfold calipers"},{"term":"Resting heart rate","def":"Heart beats per minute at complete rest — lower = better cardiovascular fitness","breakdown":"Average adult: 60-100 bpm. Athletes: 40-60 bpm. For each beat lower, heart works more efficiently. Measure first thing in morning"},{"term":"Sleep hygiene","def":"Habits and practices that promote good sleep quality","breakdown":"Consistent schedule, dark/cool/quiet room, no screens 1hr before bed, avoid caffeine after 2 PM, no alcohol before bed. 8-10 hours for teens"},{"term":"Sleep stages","def":"NREM sleep (stages 1-3) and REM sleep — cycle repeats 4-6 times per night","breakdown":"Stage 3 (deep sleep): physical restoration. REM: memory consolidation, dreaming. Disruption of either stage affects health and cognition"},{"term":"Stress response (fight or flight)","def":"Physiological reaction to perceived threat — cortisol and adrenaline released, body prepares for action","breakdown":"Useful for actual threats. Chronic activation: hypertension, immune suppression, anxiety, weight gain. Modern stressors rarely require fight or flight"},{"term":"Cortisol","def":"Primary stress hormone released by adrenal glands — elevated chronically with chronic stress","breakdown":"Short-term: raises blood glucose, suppresses digestion, sharpens alertness. Chronic: increases belly fat, weakens immune system, disrupts sleep"},{"term":"Nicotine addiction","def":"Physical and psychological dependence on nicotine — highly addictive chemical in tobacco","breakdown":"Nicotine reaches brain in 7-10 seconds. Releases dopamine — reward pathway. Withdrawal: irritability, anxiety, cravings. Smoking cessation doubles over cold turkey"},{"term":"Alcohol and brain development","def":"Alcohol significantly damages developing brains — adolescents especially vulnerable","breakdown":"Prefrontal cortex develops until age 25. Alcohol impairs memory, impulse control, and learning. Teens who drink before 15 are 4x more likely to develop alcohol dependency"},{"term":"Immunization","def":"Administration of vaccine to stimulate immune response and provide protection from disease","breakdown":"Herd immunity: when enough of population is immune to protect those who cannot be vaccinated. Threshold varies: measles 95%, polio 80-85%"},{"term":"Infectious disease transmission","def":"Direct: contact, droplet, sexual. Indirect: airborne, vector, fomite, fecal-oral","breakdown":"Droplet: stays <3 feet (flu). Airborne: stays suspended (COVID, TB, measles). Fomite: contaminated surface. Vector: mosquito, tick"},{"term":"Hand hygiene","def":"Most effective infection prevention — wash 20 seconds with soap or use 60%+ alcohol sanitizer","breakdown":"WHO 5 moments: before patient contact, before aseptic procedure, after body fluid exposure, after patient contact, after touching patient environment"},{"term":"Sun protection","def":"SPF 30+ sunscreen, reapply every 2 hours, UV-protective clothing — prevents skin cancer","breakdown":"UV radiation causes 99% of non-melanoma skin cancers. SPF 30 blocks 97% of UVB. Must reapply after swimming/sweating. Most common cancer in U.S."},{"term":"Dental health","def":"Brush 2x daily with fluoride toothpaste, floss daily, regular dental cleanings","breakdown":"Oral bacteria linked to cardiovascular disease, diabetes complications. Fluoride strengthens enamel. Gum disease affects 47% of adults 30+"},{"term":"Screen time effects","def":"Excessive screen time linked to poor sleep, depression, anxiety, sedentary behavior","breakdown":"Blue light suppresses melatonin — disrupts sleep. Social media comparison increases depression rates. AAP: teens limit recreational screen time, prioritize sleep"}]);
  fc.medium=fc.medium.concat([{"term":"Metabolic syndrome","def":"Cluster of conditions: abdominal obesity, hypertension, high blood glucose, abnormal cholesterol","breakdown":"Having 3 of 5 criteria = metabolic syndrome. Dramatically increases cardiovascular disease and type 2 diabetes risk. Affects 1 in 3 Americans"},{"term":"Hypertension stages","def":"Normal: <120/80. Elevated: 120-129/<80. Stage 1 HTN: 130-139/80-89. Stage 2 HTN: ≥140/90","breakdown":"Hypertension: 'silent killer' — no symptoms until organ damage. First-line: lifestyle changes. Stage 2: medication usually needed. Damages heart, kidneys, brain, eyes"},{"term":"Diabetes types","def":"Type 1: autoimmune destruction of beta cells. Type 2: insulin resistance + relative insulin deficiency. Gestational: during pregnancy","breakdown":"T1: requires insulin. T2: often manageable with lifestyle + oral meds → insulin. Prediabetes (HbA1c 5.7-6.4%): reversible with lifestyle changes"},{"term":"Cardiovascular risk factors","def":"Modifiable: smoking, inactivity, poor diet, obesity, hypertension, diabetes, high cholesterol. Non-modifiable: age, sex, genetics","breakdown":"Modifiable risk factors are the target of prevention programs. Framingham Risk Score calculates 10-year CVD risk from risk factors"},{"term":"Body mass index limitations","def":"BMI doesn't measure body fat directly — can misclassify muscular athletes as overweight","breakdown":"Alternative measures: waist circumference (>40in men, >35in women = increased risk), waist-to-hip ratio, body fat percentage. BMI is population screening tool"},{"term":"Sleep and immune function","def":"Sleep deprivation reduces cytokine production and immune cell activity — increases infection susceptibility","breakdown":"<7 hours/night: 3x more likely to develop cold when exposed. Sleep during illness: fever increases cytokine production and immune effectiveness"},{"term":"Mental health conditions prevalence","def":"Anxiety disorders: most common (18%). Depression: 8%. Eating disorders: 5-10%. Schizophrenia: 1%","breakdown":"50% of mental illness begins by age 14. Average 11-year delay between onset and first treatment. Early intervention dramatically improves outcomes"},{"term":"Cognitive behavioral therapy (CBT)","def":"Evidence-based therapy challenging negative thought patterns and behaviors — first-line for anxiety, depression","breakdown":"Identifies cognitive distortions (catastrophizing, all-or-nothing thinking). Teaches reframing. More effective than medication alone for many conditions"},{"term":"Exercise and mental health","def":"150 min/week of moderate exercise reduces depression risk by 30%, anxiety by 48%","breakdown":"Exercise: releases endorphins, serotonin, BDNF (brain growth factor). As effective as antidepressants for mild-moderate depression. Free, no side effects"},{"term":"Health behavior change models","def":"Transtheoretical Model (stages of change): Precontemplation → Contemplation → Preparation → Action → Maintenance","breakdown":"People don't change immediately — they progress through stages. Interventions should match stage. Motivational interviewing helps move through stages"},{"term":"Healthy People 2030","def":"National health promotion and disease prevention objectives set by DHHS every decade","breakdown":"500+ objectives covering leading causes of disease and disability. Current focus: health equity, social determinants, mental health, substance use, COVID recovery"},{"term":"Cancer prevention behaviors","def":"No tobacco, limit alcohol, sun protection, healthy weight, physical activity, screening, vaccination","breakdown":"HPV vaccine prevents cervical, throat, and other cancers. Screening: mammogram, colonoscopy, Pap smear, lung CT for smokers. 40% of cancers preventable"},{"term":"Overtraining syndrome","def":"Excessive training without adequate recovery — causes performance decline, fatigue, mood changes, injury","breakdown":"Signs: persistent fatigue, decreased performance, resting HR increase, sleep disruption, frequent illness. Treatment: rest, recovery, nutrition. Prevent by periodization"},{"term":"RICE method (injury)","def":"Rest, Ice, Compression, Elevation — first aid for acute musculoskeletal injuries","breakdown":"Updated to PRICE (Protection) or POLICE (Optimal Loading). Ice for 20min/hour. Compression reduces swelling. Elevation above heart level. Seek care if severe"}]);
  fc.hard=fc.hard.concat([{"term":"Epigenetics and lifestyle","def":"Lifestyle factors can alter gene expression without changing DNA sequence — reversible","breakdown":"Exercise, diet, stress, sleep, toxin exposure alter methylation patterns. Father's obesity before conception affects offspring metabolism. Some changes heritable"},{"term":"Telomere length and aging","def":"Telomeres shorten with each cell division and stress — shorter = biological aging. Lifestyle affects rate","breakdown":"Chronic stress, poor sleep, smoking accelerate telomere shortening. Exercise, Mediterranean diet, mindfulness slow shortening. Nobel Prize 2009 (Blackburn, Greider, Szostak)"},{"term":"Gut-brain axis","def":"Bidirectional communication between gut microbiome and brain — affects mood, cognition, behavior","breakdown":"90% of serotonin produced in gut. Gut bacteria produce neurotransmitters. Dysbiosis (imbalanced microbiome) linked to depression, anxiety, autism spectrum disorder"},{"term":"Hormetic stress","def":"Low-dose stress that triggers adaptive response stronger than the original stressor — 'what doesn't kill you makes you stronger'","breakdown":"Exercise: muscle damage → stronger muscles. Intermittent fasting: cellular autophagy. Cold exposure: mitochondrial biogenesis. Dose and recovery are critical"}]);
  qz.easy=qz.easy.concat([{"q":"What are the three dimensions of the health triangle?","opts":["Physical, mental, and spiritual","Physical, mental/emotional, and social","Physical, academic, and social","Nutritional, physical, and emotional"],"correct":1,"explain":"The health triangle consists of three equal dimensions: physical health (body), mental/emotional health (mind), and social health (relationships). All three must be in balance for total wellness. Neglecting one dimension affects the others."},{"q":"How many minutes per week of moderate aerobic exercise do health guidelines recommend for adults?","opts":["60 minutes","90 minutes","150 minutes","300 minutes"],"correct":2,"explain":"Health guidelines recommend at least 150 minutes of moderate-intensity aerobic exercise per week (or 75 minutes of vigorous activity). This can be broken into 30-minute sessions, 5 days per week. Additional benefits at 300 minutes/week."},{"q":"Which type of exercise primarily improves cardiovascular fitness?","opts":["Anaerobic exercise","Flexibility training","Aerobic exercise","Resistance training"],"correct":2,"explain":"Aerobic exercise (running, swimming, cycling) primarily improves cardiovascular and respiratory fitness by strengthening the heart, improving lung capacity, and increasing oxygen delivery to muscles. Anaerobic exercise primarily builds strength and muscle mass."},{"q":"What does the FITT principle stand for?","opts":["Flexibility, Intensity, Timing, Training","Frequency, Intensity, Time, Type","Fitness, Interval, Time, Technique","Frequency, Interval, Training, Tension"],"correct":1,"explain":"FITT = Frequency (how often), Intensity (how hard), Time (how long), Type (what kind of exercise). These four variables are manipulated to design effective, progressive exercise programs that avoid plateau and overtraining."},{"q":"How many hours of sleep do teenagers (14-17) need per night?","opts":["6-7 hours","7-8 hours","8-10 hours","10-12 hours"],"correct":2,"explain":"Teenagers aged 14-17 need 8-10 hours of sleep per night. The developing brain requires extra sleep for growth hormone release, memory consolidation, emotional regulation, and physical development. Most teens are chronically sleep-deprived."},{"q":"Which of the following is an example of a mental health strategy?","opts":["Taking vitamin supplements","Mindfulness meditation","Drinking energy drinks","Avoiding all social interaction"],"correct":1,"explain":"Mindfulness meditation is an evidence-based mental health strategy — it reduces anxiety, depression, and stress by training present-moment awareness. Other mental health strategies include therapy (CBT), exercise, social connection, journaling, and adequate sleep."},{"q":"What is the most effective action for preventing the spread of infectious disease?","opts":["Wearing a mask at all times","Taking antibiotics preventively","Proper hand washing for 20 seconds","Avoiding all public places"],"correct":2,"explain":"Proper hand hygiene — washing with soap and water for at least 20 seconds (or using 60%+ alcohol sanitizer) — is the single most effective way to prevent spread of most infectious diseases. It removes pathogens from the skin before they can be transferred to mucous membranes."},{"q":"Which behavior is MOST associated with reducing cancer risk?","opts":["Eating red meat daily","Avoiding tobacco use","Drinking orange juice daily","Sleeping more than 10 hours"],"correct":1,"explain":"Tobacco avoidance is the single most impactful cancer prevention behavior — smoking causes about 30% of all cancer deaths. Other key behaviors: healthy weight, physical activity, limiting alcohol, sun protection, cancer screenings, and HPV/Hepatitis B vaccination."},{"q":"What does sun protection factor (SPF) 30 indicate?","opts":["Protects skin for 30 minutes only","Blocks approximately 97% of UVB rays","Provides 30 times more protection than SPF 1","Is only needed at SPF 50 or higher"],"correct":1,"explain":"SPF 30 blocks approximately 97% of UVB rays. SPF 50 blocks 98%. No sunscreen blocks 100%. Reapply every 2 hours and after swimming or sweating. Use broad-spectrum (UVA + UVB) SPF 30+ daily."},{"q":"Chronic stress primarily causes long-term harm through which mechanism?","opts":["Causing immediate organ failure","Prolonged elevation of cortisol and adrenaline that damages body systems","Reducing appetite completely","Eliminating the immune response"],"correct":1,"explain":"Chronic stress causes prolonged elevation of cortisol and adrenaline. Long-term effects include: hypertension, weakened immune system, increased abdominal fat, sleep disruption, anxiety, depression, and increased cardiovascular risk. Acute stress is beneficial; chronic stress is harmful."},{"q":"What is herd immunity?","opts":["When all animals in a herd are vaccinated","When enough of a population is immune to prevent disease spread to unprotected individuals","Immunity that develops from herding cattle","Natural immunity that develops after infection"],"correct":1,"explain":"Herd immunity occurs when enough of a population is immune (through vaccination or prior infection) that the disease cannot spread efficiently, protecting those who cannot be vaccinated (infants, immunocompromised). The threshold varies: measles requires 95% immunity."},{"q":"Which of the following best describes the health benefit of regular physical activity for mental health?","opts":["Reduces the need for sleep","Releases endorphins and neurotransmitters that reduce depression and anxiety","Eliminates the need for mental health treatment","Only benefits mental health in elite athletes"],"correct":1,"explain":"Regular physical activity releases endorphins, serotonin, and BDNF (brain-derived neurotrophic factor) — chemicals that improve mood, reduce anxiety, and protect against depression. Studies show 150 min/week reduces depression risk by 30% and is as effective as antidepressants for mild-moderate depression."},{"q":"What is the primary health risk associated with excessive alcohol consumption by adolescents?","opts":["It causes immediate liver failure","It disrupts brain development since the brain develops until age 25","It primarily affects physical fitness","It has no unique risks for teens compared to adults"],"correct":1,"explain":"Adolescent brains are still developing until age 25 — alcohol is especially damaging during this critical period. Teen drinking impairs memory, impulse control, and decision-making. Teens who drink before age 15 are 4x more likely to develop alcohol use disorder."},{"q":"According to the FITT principle, changing which variable would improve cardiovascular fitness in an intermediate exerciser?","opts":["Type: switching from running to playing cards","Frequency: adding one more workout day per week","Time: reducing workout duration","Intensity: exercising at 20% max heart rate"],"correct":1,"explain":"Adding frequency (an extra workout day) is an appropriate progression for an intermediate exerciser. Increasing intensity (higher HR zone) or time are also valid. Reducing time or intensity would cause regression. Playing cards is not aerobic exercise."},{"q":"The 'fight or flight' response is controlled primarily by which system?","opts":["Digestive system","Immune system","Sympathetic nervous system","Parasympathetic nervous system"],"correct":2,"explain":"The sympathetic nervous system triggers the fight-or-flight response — releasing adrenaline (epinephrine) and cortisol, increasing heart rate and blood pressure, dilating airways, redirecting blood to muscles. The parasympathetic system controls 'rest and digest.'"}]);
  qz.medium=qz.medium.concat([{"q":"A 16-year-old's maximum heart rate is estimated to be 204 bpm. What is their aerobic training zone?","opts":["102-143 bpm","122-173 bpm","163-184 bpm","60-80 bpm"],"correct":1,"explain":"Max HR = 220 - 16 = 204 bpm. Aerobic training zone = 60-85% of max HR. 60%: 204 × 0.60 = 122.4 bpm. 85%: 204 × 0.85 = 173.4 bpm. Training at 122-173 bpm provides optimal cardiovascular benefit."},{"q":"Metabolic syndrome is diagnosed when a patient has three or more of which criteria?","opts":["Underweight, low blood pressure, low cholesterol, high HDL, low blood glucose","Abdominal obesity, hypertension, high triglycerides, low HDL, high fasting blood glucose","High protein intake, low carbohydrate intake, high physical activity, low sleep, high stress","Overweight BMI, low vitamin D, high iron, low calcium, elevated WBC"],"correct":1,"explain":"Metabolic syndrome is diagnosed with 3+ of: (1) waist >40in men/>35in women, (2) triglycerides ≥150, (3) HDL <40mg/dL men/<50 women, (4) BP ≥130/85, (5) fasting glucose ≥100mg/dL. Dramatically increases CVD and diabetes risk."},{"q":"A student sleeps 5 hours per night during the school week. Which health consequences are MOST likely?","opts":["Improved academic performance from more study time","Impaired memory consolidation, increased cortisol, weakened immune function, increased depression risk","No significant health effects if they 'catch up' on weekends","Only physical health effects, not mental health effects"],"correct":1,"explain":"Chronic sleep deprivation (teens need 8-10 hours) causes: impaired memory and learning (REM sleep consolidates memory), elevated cortisol (stress response), weakened immunity (cytokine production drops), increased depression and anxiety risk, and poor impulse control. Weekend catch-up sleep partially compensates but doesn't fully restore."},{"q":"Which stage of the Transtheoretical Model describes a person who knows they need to exercise more but isn't doing anything about it yet?","opts":["Precontemplation","Contemplation","Preparation","Action"],"correct":1,"explain":"Contemplation: the person is aware of the problem and considering change but hasn't committed to action. Precontemplation: not yet aware or not considering change. Preparation: making plans to change. Action: actively changing behavior (within 6 months). Maintenance: sustaining change >6 months."},{"q":"Which intervention has the STRONGEST evidence for treating mild to moderate depression?","opts":["Vitamin supplements alone","Regular aerobic exercise combined with cognitive behavioral therapy","Elimination of all sugar from diet","Complete social isolation to reduce stimulation"],"correct":1,"explain":"The combination of regular aerobic exercise and CBT (cognitive behavioral therapy) has the strongest evidence base for treating mild to moderate depression. Exercise alone is as effective as antidepressants for many patients. CBT addresses thought patterns. Together they address both biological and psychological dimensions."},{"q":"What distinguishes overtraining syndrome from normal exercise fatigue?","opts":["Overtraining fatigue resolves after one rest day; normal fatigue persists for weeks","Overtraining causes persistent performance decline, mood changes, and elevated resting HR despite rest","Overtraining only affects professional athletes","Normal fatigue is always more severe than overtraining"],"correct":1,"explain":"Overtraining syndrome (OTS) causes persistent fatigue, decreased performance, elevated resting heart rate, mood disturbances, frequent illness, and sleep disruption that do NOT resolve with short rest. It requires weeks to months of reduced training. Prevented by periodization (planned recovery cycles)."},{"q":"HPV vaccination is recommended primarily because it prevents which diseases?","opts":["HIV and hepatitis","Cervical cancer and other HPV-related cancers and genital warts","All sexually transmitted infections","Breast cancer and prostate cancer"],"correct":1,"explain":"HPV vaccine prevents cancers caused by human papillomavirus — primarily cervical cancer but also vaginal, vulvar, penile, anal, and oropharyngeal (throat) cancers, plus genital warts. Gardasil 9 covers 9 HPV strains responsible for 90% of HPV cancers. Recommended at age 11-12."}]);
  qz.hard=qz.hard.concat([{"q":"Research shows a strong link between gut microbiome and mental health. Which statement best explains this relationship?","opts":["Gut bacteria directly control all emotions through the bloodstream","The gut-brain axis allows bidirectional communication — gut bacteria produce neurotransmitters and send signals via the vagus nerve affecting mood and cognition","Gut health only affects physical health, not mental health","The relationship is theoretical and not clinically relevant yet"],"correct":1,"explain":"The gut-brain axis involves bidirectional signaling between the enteric nervous system (gut) and central nervous system (brain) via the vagus nerve, immune system, and bacterial metabolites. Gut bacteria produce 90% of the body's serotonin. Dysbiosis (microbiome imbalance) is associated with depression, anxiety, and cognitive changes."},{"q":"Epigenetic research suggests which lifestyle implications?","opts":["Genetics alone determine health outcomes — lifestyle is irrelevant","Lifestyle factors (diet, exercise, stress, sleep) alter gene expression without changing DNA — these changes can be reversed and some are heritable","Only medications can alter gene expression","Epigenetic changes happen randomly and cannot be influenced"],"correct":1,"explain":"Epigenetics shows that lifestyle factors alter gene expression through DNA methylation and histone modification — without changing the DNA sequence. These changes are often reversible (exercise reverses stress-induced methylation changes) and some are transmitted to offspring. This is why lifestyle interventions can counteract genetic predispositions."},{"q":"What is allostatic load and how is it clinically useful?","opts":["A single blood test measuring overall health status","The cumulative biological burden of chronic stress measured across multiple physiological systems — predicts disease and mortality","A measure of how much exercise someone can handle","The amount of cortisol in the bloodstream at any given time"],"correct":1,"explain":"Allostatic load quantifies the cumulative wear on the body from chronic stress across multiple biomarkers: cortisol levels, blood pressure, waist-hip ratio, inflammatory markers (IL-6, CRP), HbA1c, and lipids. High allostatic load predicts cardiovascular disease, cognitive decline, immune dysfunction, and all-cause mortality — more accurately than any single biomarker."}]);
})();

(function(){
  if(!window.QB_VETERINARY) return;
  var fc=window.QB_VETERINARY.flashcards,qz=window.QB_VETERINARY.quiz;
  if(!fc||!qz) return;
  ['easy','medium','hard'].forEach(function(d){if(!fc[d])fc[d]=[];if(!qz[d])qz[d]=[];});
  fc.easy=fc.easy.concat([{"term":"Veterinarian (DVM/VMD)","def":"Doctor of Veterinary Medicine — diagnoses and treats animal diseases, performs surgery","breakdown":"4-year veterinary school after bachelor's. Specialties: small animal, large animal, exotic, zoo, public health, research, military"},{"term":"Veterinary technician (RVT/CVT)","def":"Licensed professional assisting veterinarians — similar to RN for humans","breakdown":"2-4 year program + national board exam (VTNE). Performs lab tests, administers medications, assists surgery, takes radiographs"},{"term":"Zoonotic disease","def":"Infectious disease transmissible between animals and humans","breakdown":"Examples: rabies, Lyme disease, salmonella, ringworm, toxoplasmosis, COVID-19 (SARS-CoV-2 originated in animals). One Health concept"},{"term":"One Health","def":"Concept recognizing human, animal, and environmental health are interconnected and interdependent","breakdown":"Shared by CDC, WHO, and USDA. Zoonoses, antimicrobial resistance, food safety, climate change are One Health issues"},{"term":"Canine anatomy — dogs","def":"Carnivore digestive system: short intestine, sharp teeth, no amylase in saliva","breakdown":"4 canine (fang) teeth. Stomach can hold large meals (evolved as feast-famine hunters). Panting = thermoregulation (no sweat glands on body)"},{"term":"Feline anatomy — cats","def":"Obligate carnivores — cannot survive without animal protein (taurine essential)","breakdown":"Retractable claws. Righting reflex allows landing on feet. Purring: 25-150 Hz vibrations with healing properties. Jacobson's organ for pheromone detection"},{"term":"Equine anatomy — horses","def":"Herbivore with unique hindgut fermentation; sensitive GI tract prone to colic","breakdown":"Single-toed (hoof = modified middle finger). Sleep standing using stay apparatus. 10-gallon stomach — must eat frequently. Largest domesticated animal"},{"term":"Bovine anatomy — cattle","def":"Ruminants with 4-compartment stomach: rumen, reticulum, omasum, abomasum","breakdown":"Rumen: fermentation chamber — bacteria break down cellulose. Regurgitate and rechew cud. Produce methane (significant greenhouse gas)"},{"term":"Ruminant","def":"Even-toed ungulate that digests plant-based food by chewing cud — cattle, sheep, goats, deer","breakdown":"4-compartment stomach allows cellulose digestion (humans cannot). Rumen bacteria produce volatile fatty acids used for energy. Require high-fiber diets"},{"term":"Vital signs (dogs)","def":"Temperature: 99.5-102.5°F, Pulse: 60-140 bpm, Respiration: 10-30 breaths/min","breakdown":"Larger dogs have slower HR than small dogs. Normal dog temp range same as cats. Respiration varies with activity, anxiety, temperature"},{"term":"Vital signs (cats)","def":"Temperature: 99.5-102.5°F, Pulse: 120-200 bpm, Respiration: 20-30 breaths/min","breakdown":"Cats have faster HR than dogs. Feline temperature same range as canine. Cats often stress at vet — white coat syndrome increases HR and temp"},{"term":"Anesthesia (veterinary)","def":"Drug-induced unconsciousness for surgery — includes induction agent + inhaled maintenance agent","breakdown":"Propofol or ketamine for induction. Isoflurane/sevoflurane inhaled for maintenance. Monitoring: HR, SpO2, capnography, blood pressure, temperature"},{"term":"Rabies vaccine","def":"Core vaccine for all dogs and cats — legally required in most jurisdictions","breakdown":"Given at 12-16 weeks, 1 year later, then every 1-3 years depending on product. State laws require vaccination. Non-core vaccines based on risk"},{"term":"Core vaccines (dogs)","def":"DHPP: Distemper, Hepatitis (Adenovirus), Parainfluenza, Parvovirus + Rabies","breakdown":"Given as combo vaccine (DA2PP or DHPP). Puppy series: 8, 12, 16 weeks. Boosted 1 year, then every 3 years. Rabies per local law"},{"term":"Core vaccines (cats)","def":"FVRCP: Feline Viral Rhinotracheitis, Calicivirus, Panleukopenia + Rabies","breakdown":"Panleukopenia: highly contagious, often fatal — feline distemper. Kitten series: 8, 12, 16 weeks. Rabies required by law"},{"term":"Microchipping","def":"Implanting a RFID chip under pet's skin — permanent identification, recovers lost pets","breakdown":"Injected between shoulder blades. 15-digit ISO standard number. Owner registers in database. 20x more likely to reunite with lost pet"},{"term":"Flea lifecycle","def":"Egg → Larva → Pupa → Adult — 95% of flea population is in the environment, not on the pet","breakdown":"Adult fleas on pet = 5% of total infestation. Must treat environment AND all pets. Pupae resistant to insecticides. Full lifecycle: 2 weeks - 6 months"},{"term":"Animal restraint","def":"Safe physical or chemical handling of animals to prevent injury to animal and handler","breakdown":"Fear-free approach: minimize stress through gentle handling, calming techniques, pheromones. Restraint should be minimum necessary. Muzzles for safety when needed"},{"term":"Microorganism identification in veterinary lab","def":"Gram stain: differentiates bacteria (gram+ purple vs gram- pink). Culture identifies specific organism","breakdown":"Gram-positive: thick peptidoglycan wall (Staph, Strep). Gram-negative: thin wall with outer membrane (E. coli, Salmonella). Different antibiotic sensitivity"}]);
  fc.medium=fc.medium.concat([{"term":"Antimicrobial resistance (AMR)","def":"Microorganisms evolve to resist antibiotics — significant One Health concern","breakdown":"Veterinary antibiotic use contributes to AMR in human pathogens. MRSA, MRSP (Staphylococcus pseudintermedius). Prudent use critical: culture before treating"},{"term":"Feline urological syndrome (FLUTD)","def":"Group of conditions affecting feline lower urinary tract — straining to urinate, blood in urine, urethral obstruction","breakdown":"Male cats especially prone to urethral obstruction ('blocked cat') — emergency. Causes: crystals, stones, idiopathic cystitis. Moist food diet reduces risk"},{"term":"Diabetes in pets","def":"Type 1-like in dogs (require insulin). Type 2-like in cats (may resolve with diet + insulin)","breakdown":"Signs: polyuria, polydipsia, weight loss despite eating. Treated with insulin injections. Cats: often responds to low-carbohydrate diet + insulin. Monitor glucose and fructosamine"},{"term":"Cushing's disease (hyperadrenocorticism)","def":"Excess cortisol production — most common endocrine disorder in dogs","breakdown":"Signs: pot-belly, hair loss, increased appetite/thirst, muscle wasting, skin changes. Pituitary-dependent (85%) or adrenal tumor (15%). Treatment: trilostane or mitotane"},{"term":"Hypothyroidism in dogs","def":"Deficiency of thyroid hormone — most common endocrine disorder in dogs","breakdown":"Signs: weight gain, lethargy, hair loss, cold intolerance. Diagnosed by T4 level. Treatment: lifetime levothyroxine supplementation. Not seen commonly in cats (hyperthyroid more common in cats)"},{"term":"Hyperthyroidism in cats","def":"Excess thyroid hormone production — most common endocrine disorder in middle-aged to older cats","breakdown":"Signs: weight loss despite increased appetite, hyperactivity, heart disease, hypertension, vomiting. Treatment: radioactive iodine (curative), methimazole, surgical thyroidectomy, prescription diet"},{"term":"Anesthesia monitoring","def":"Continuous assessment during surgical anesthesia — HR, SpO2, ETCO2, blood pressure, temperature","breakdown":"ETCO2 (end-tidal CO2): confirms correct tube placement, monitors ventilation. SpO2 < 95% is concerning. Temperature drops rapidly in anesthetized patients — warming devices essential"},{"term":"Veterinary dentistry","def":"Most common disease in pets: periodontal disease — affects 80% of dogs and 70% of cats over age 3","breakdown":"Bacteria spread from mouth to heart, kidneys, liver. Professional cleaning under anesthesia. Home brushing prevents plaque buildup. Annual dental exam important"},{"term":"Pain assessment in animals","def":"Animals hide pain — behavioral changes: lethargy, aggression, posture changes, decreased appetite","breakdown":"Pain scales: Colorado State Feline Acute Pain Scale, Glasgow Composite Pain Scale. Pre-emptive analgesia better than treating established pain. Multimodal analgesia preferred"},{"term":"Feline infectious peritonitis (FIP)","def":"Progressive, usually fatal disease caused by feline coronavirus mutation","breakdown":"Two forms: wet (effusions in chest/abdomen) and dry (granulomas in organs). Primarily affects young cats. New antiviral (GS-441524) shows 80%+ cure rate — expensive but transformative"},{"term":"Distemper in dogs","def":"Viral disease affecting GI, respiratory, and nervous systems — often fatal","breakdown":"Highly contagious airborne virus. Signs: fever, discharge, coughing, neurological signs. No specific antiviral — supportive care. Core vaccine prevents. Raccoons also susceptible"},{"term":"Food animal medicine","def":"Veterinary care for cattle, pigs, sheep, goats, poultry — production and welfare focused","breakdown":"Large animal practitioners do herd-level medicine. Focus: production diseases, reproductive management, food safety, biosecurity, welfare audits"},{"term":"Necropsy","def":"Post-mortem examination of an animal — analogous to human autopsy","breakdown":"Gross and histopathologic examination to determine cause of death. Essential for flock/herd disease investigation. State labs perform on wildlife and food animals"},{"term":"Veterinary public health","def":"Application of veterinary skills to protect and improve human and animal population health","breakdown":"USDA food inspectors are veterinarians. Epidemiologists investigating zoonotic outbreaks. Military working dog veterinarians. Laboratory research veterinarians. Biosecurity for bioterrorism response"}]);
  fc.hard=fc.hard.concat([{"term":"Sepsis in veterinary patients","def":"Life-threatening systemic inflammatory response to infection — requires aggressive treatment","breakdown":"Signs: fever or hypothermia, tachycardia, tachypnea, altered mentation. SIRS + suspected infection = sepsis. Treatment: IV fluids, broad-spectrum antibiotics, vasopressors if needed"},{"term":"Disseminated intravascular coagulation (DIC)","def":"Pathological clotting throughout vasculature with simultaneous bleeding — consumptive coagulopathy","breakdown":"DIC = 'Death Is Coming' — grave prognosis. Triggered by: sepsis, neoplasia, trauma, envenomation. Uses up clotting factors (bleeding) + forms microthrombi (organ failure)"},{"term":"Toxicology — common pet toxins","def":"Dogs: grapes/raisins, xylitol (sugar-free gum), chocolate, NSAIDs, rodenticide. Cats: lilies (fatal), NSAIDs, acetaminophen","breakdown":"Grapes: 1 grape can cause acute renal failure in dogs. Xylitol: causes hypoglycemia and liver failure. Lilies (all parts) cause feline renal failure within 72 hours — no antidote"},{"term":"Rodenticide toxicity (anticoagulant)","def":"Inhibits vitamin K epoxide reductase — blocks production of clotting factors — internal hemorrhage","breakdown":"Brodifacoum, bromadiolone: second-generation. Half-life weeks — treated with vitamin K for weeks. Relay toxicity: pets eating poisoned rodents. Signs delayed 2-7 days"},{"term":"Shock treatment in veterinary patients","def":"IV fluid bolus (crystalloids or colloids) + identify and treat cause + vasopressors if unresponsive","breakdown":"Crystalloids (LRS, normal saline): 10-20 mL/kg bolus dogs, 10 mL/kg cats. Colloids (Hetastarch, albumin): smaller volume needed. Measure and monitor response continuously"}]);
  qz.easy=qz.easy.concat([{"q":"What does 'zoonotic disease' mean?","opts":["Disease only found in zoo animals","Infectious disease transmissible between animals and humans","Disease affecting multiple animal species but not humans","A disease requiring quarantine at a zoo"],"correct":1,"explain":"Zoonotic diseases are infectious diseases that can be transmitted between animals and humans. Examples include rabies, Lyme disease (tick-borne), salmonella, ringworm, toxoplasmosis, and even COVID-19 (which originated from animals). This is why veterinary and human medicine intersect."},{"q":"What is the 'One Health' concept?","opts":["The idea that all pets should receive identical medical care","The recognition that human, animal, and environmental health are interconnected","A vaccination program for one specific disease","A veterinary care plan for one animal"],"correct":1,"explain":"One Health recognizes that the health of humans, animals, and the environment are fundamentally interconnected. Zoonotic diseases, antimicrobial resistance, food safety, and environmental health issues require collaboration between human medicine, veterinary medicine, and environmental science."},{"q":"What is the most common route of rabies transmission to humans?","opts":["Contact with infected animal feces","Scratch from infected animal","Bite from infected animal transmitting saliva","Inhaling air near infected bats"],"correct":2,"explain":"Rabies is most commonly transmitted through the bite of an infected animal, which introduces infected saliva into the wound. Post-exposure prophylaxis (PEP) — rabies immune globulin plus vaccine — is effective if given promptly after exposure."},{"q":"Dogs are classified as which type of eater?","opts":["Obligate carnivores","Herbivores","Omnivores","Insectivores"],"correct":2,"explain":"Dogs are omnivores — they can digest and utilize nutrients from both animal and plant sources. This differs from cats, which are obligate carnivores (must eat animal protein). Dogs have more amylase than cats, allowing better starch digestion."},{"q":"Cattle have how many compartments in their stomach?","opts":["1","2","3","4"],"correct":3,"explain":"Ruminants like cattle have a 4-compartment stomach: rumen (fermentation chamber), reticulum (honeycomb texture, catches debris), omasum (water absorption), and abomasum (true stomach, acid digestion). This allows digestion of cellulose-rich plant material."},{"q":"What does a spay surgery involve?","opts":["Removal of the male animal's testes","Removal of the female animal's ovaries and uterus","Placement of a microchip","Removal of the animal's dewclaws"],"correct":1,"explain":"A spay (ovariohysterectomy) is the surgical removal of a female animal's ovaries and uterus. It permanently prevents reproduction and significantly reduces the risk of pyometra (uterine infection) and mammary (breast) cancer."},{"q":"Which disease is in the core vaccine series for dogs (DHPP)?","opts":["Leptospirosis","Lyme disease","Parvovirus","Giardia"],"correct":2,"explain":"DHPP stands for Distemper, Hepatitis (Adenovirus), Parainfluenza, and Parvovirus — all core vaccines for dogs. Rabies is also core. Leptospirosis and Lyme are non-core (given based on risk). Parvovirus is especially dangerous for unvaccinated puppies."},{"q":"What is heartworm disease and how is it transmitted?","opts":["Intestinal parasites spread by fleas","Parasitic worms in the heart and arteries transmitted by mosquito bites","A viral heart disease spread by tick bites","A bacterial heart infection from contaminated food"],"correct":1,"explain":"Heartworm (Dirofilaria immitis) is transmitted through mosquito bites. Larvae grow into worms up to 12 inches long living in the heart and pulmonary arteries. Prevention (monthly medication) is far safer and cheaper than treatment. Dogs, cats, and ferrets can be affected."},{"q":"What is the normal rectal temperature range for both dogs and cats?","opts":["97-99°F","99.5-102.5°F","103-105°F","95-97°F"],"correct":1,"explain":"Normal rectal temperature for both dogs and cats is 99.5-102.5°F (37.5-39.2°C). Temperatures above 103°F indicate fever. Above 105°F is a medical emergency. Rectal temperature is most accurate; ear and forehead readings are less reliable in animals."},{"q":"What percentage of a flea infestation lives OFF the pet (in the environment)?","opts":["5%","25%","50%","95%"],"correct":3,"explain":"95% of a flea infestation (eggs, larvae, pupae) lives in the environment (carpet, bedding, yard) — only 5% (adult fleas) lives on the pet. This is why treating the pet alone is insufficient — you must also treat the environment to break the flea lifecycle."},{"q":"What is microchipping in pets?","opts":["Implanting GPS tracking in the brain","Subcutaneous implantation of an RFID chip for permanent identification","A type of surgical monitoring device","A chip that dispenses medication"],"correct":1,"explain":"A microchip is a tiny RFID (radio frequency identification) device implanted under the skin between the shoulder blades. Each chip has a unique 15-digit number linked to owner information in a registry database. Microchipped pets are 20x more likely to be reunited with owners if lost."},{"q":"Which disease primarily affects the intestinal tract and bone marrow of unvaccinated puppies?","opts":["Distemper","Rabies","Parvovirus","Leptospirosis"],"correct":2,"explain":"Canine parvovirus attacks rapidly dividing cells — primarily the GI tract (causing severe bloody vomiting and diarrhea) and bone marrow (causing immunosuppression). It is highly contagious and can be fatal without aggressive treatment. Vaccination is the most effective prevention."}]);
  qz.medium=qz.medium.concat([{"q":"A cat presents with straining to urinate, crying in the litter box, and no urine production for 24 hours. What is the most likely emergency?","opts":["Bladder infection (UTI)","Feline urethral obstruction ('blocked cat') — life-threatening emergency","Constipation","Kidney stones requiring surgery in 1 week"],"correct":1,"explain":"Urethral obstruction ('blocked cat') is a life-threatening emergency — the urethra is obstructed (crystals, mucus plug, or spasm), preventing urine outflow. Without treatment, cats die from uremia and hyperkalemia within 24-48 hours. Requires immediate urethral catheterization and hospitalization. Male cats are most susceptible due to narrow urethra."},{"q":"The One Health approach would be MOST applicable to investigating which scenario?","opts":["A dog with a broken leg","An outbreak of Salmonella infections in humans traced to contaminated poultry","A cat with dental disease","A horse with a respiratory infection on a single farm"],"correct":1,"explain":"One Health is most applicable to the Salmonella outbreak — it involves the intersection of animal health (poultry), human health (infected people), and environmental health (food processing facilities). Investigation requires collaboration between veterinarians, public health officials, and environmental scientists."},{"q":"Antimicrobial resistance is a One Health concern because:","opts":["Only animals can develop resistance","Antibiotic use in veterinary medicine can select for resistant bacteria that transfer to humans","Resistance only occurs with human antibiotic use","Animals and humans have completely separate bacterial populations"],"correct":1,"explain":"Antibiotic use in food animals and pets selects for resistant bacteria that can transfer to humans through direct contact, food, or environmental routes. MRSA is documented passing between humans and pets. This is why veterinary antimicrobial stewardship — using antibiotics prudently and only when necessary — is a critical One Health issue."},{"q":"A dog with Cushing's disease presents with pot-belly, hair loss, increased thirst, and muscle weakness. What is the underlying mechanism?","opts":["Insufficient thyroid hormone","Excess cortisol production from pituitary or adrenal abnormality","Insulin deficiency","Excess growth hormone"],"correct":1,"explain":"Cushing's disease (hyperadrenocorticism) results from excess cortisol — most commonly from a pituitary tumor causing excess ACTH production (85% of cases) or from an adrenal tumor (15%). Chronic excess cortisol causes all the classic signs: pot-belly (fat redistribution), muscle wasting, PU/PD, hair loss, and immunosuppression."},{"q":"Why do cats get hyperthyroidism while dogs more commonly get hypothyroidism?","opts":["It is a coincidence with no biological explanation","Cats have overactive immune systems; dogs have underactive thyroid glands","Cats tend to develop thyroid tumors (adenomas) causing excess hormone; dogs tend to have autoimmune thyroid destruction causing deficiency","Dogs eat more iodine than cats"],"correct":2,"explain":"In cats, hyperthyroidism is almost always caused by benign thyroid adenomas producing excess T4. In dogs, hypothyroidism typically results from autoimmune lymphocytic thyroiditis or idiopathic atrophy destroying the thyroid gland. These are distinct diseases with different mechanisms, not just opposite versions of the same condition."},{"q":"What is the clinical significance of periodontal disease in pets beyond the mouth?","opts":["There is no systemic significance — it only affects teeth","Bacteria from periodontal infection can spread via bloodstream to heart valves, kidneys, and liver — causing systemic disease","Periodontal disease only affects very old animals","The only risk is tooth loss"],"correct":1,"explain":"Periodontal disease allows bacteria to continuously enter the bloodstream (bacteremia) from inflamed gums. These bacteria can damage heart valves (endocarditis), kidneys, and liver over time. This is why dental care is considered essential preventive medicine, not cosmetic. 80% of dogs and 70% of cats over 3 have some degree of periodontal disease."}]);
  qz.hard=qz.hard.concat([{"q":"A dog is brought in after ingesting an unknown rodenticide 3 days ago. Lab work shows a markedly prolonged PT/PTT but normal platelet count. What is the most likely toxin and treatment?","opts":["Zinc phosphide — treat with IV fluids","Anticoagulant rodenticide (brodifacoum) — treat with oral vitamin K1 for 4+ weeks","Strychnine — treat with muscle relaxants","Metaldehyde — treat with activated charcoal"],"correct":1,"explain":"Anticoagulant rodenticides (especially second-generation brodifacoum) inhibit vitamin K epoxide reductase, blocking synthesis of clotting factors II, VII, IX, X. Signs appear 2-7 days after ingestion (when existing factors are depleted). Treatment: oral vitamin K1 for 4-6 weeks (duration matches toxin half-life). Relay toxicity occurs when pets eat poisoned rodents."},{"q":"A cat presents collapsed with pale mucous membranes and a heart rate of 60 bpm. Bloodwork shows severe hyperkalemia and azotemia. The most likely cause is:","opts":["Severe dehydration","Urethral obstruction causing post-renal uremia and life-threatening hyperkalemia","Hypovolemic shock from hemorrhage","Addison's disease (hypoadrenocorticism)"],"correct":1,"explain":"Urethral obstruction causes urine to back up, leading to: azotemia (waste product accumulation), hyperkalemia (K+ cannot be excreted — causes dangerous bradycardia and cardiac arrhythmias), and metabolic acidosis. Treatment is urgent: IV fluids, cardiac monitoring, urethral catheterization, and medical stabilization before anesthesia for catheter placement."},{"q":"Which statement best describes the veterinarian's role in antimicrobial stewardship?","opts":["Prescribe the broadest-spectrum antibiotic to ensure treatment success","Reserve all antibiotics for human use only","Culture and sensitivity testing before prescribing, use narrowest effective spectrum, complete full courses, report resistance patterns","Antibiotics are safe for long-term use so resistance concerns are overstated"],"correct":2,"explain":"Veterinary antimicrobial stewardship: perform culture and sensitivity testing to identify the pathogen and its susceptibilities, select the narrowest effective antibiotic (avoiding critically important antibiotics when alternatives exist), dose correctly, complete full courses, and participate in resistance surveillance. This reduces selection pressure for resistant organisms that can transfer to humans."}]);
})();

(function(){
  if(!window.QB_STOP_BLEED) return;
  var fc=window.QB_STOP_BLEED.flashcards,qz=window.QB_STOP_BLEED.quiz;
  if(!fc||!qz) return;
  ['easy','medium','hard'].forEach(function(d){if(!fc[d])fc[d]=[];if(!qz[d])qz[d]=[];});
  fc.easy=fc.easy.concat([{"term":"Hemorrhage","def":"Excessive bleeding — internal or external — can be life-threatening within minutes","breakdown":"Leading cause of preventable death in trauma. 35-40% of trauma deaths from hemorrhage. First 10 minutes ('platinum 10') most critical for intervention"},{"term":"ABC of bleeding control","def":"Alert (call 911), Bleeding control (apply pressure/tourniquet), Care (maintain until EMS arrives)","breakdown":"Stop the Bleed simplified framework. Alert = get help coming. Bleeding = stop it now. Care = stay with victim, reassure, monitor"},{"term":"Tourniquet placement","def":"Apply 2-3 inches above the wound on the limb — never on joint","breakdown":"High and tight. Tighten until bleeding stops completely. Note time applied. DO NOT remove once applied — only medical personnel remove. Pain is expected"},{"term":"Commercial tourniquet types","def":"CAT (Combat Application Tourniquet) and SOFTT-W most common military/civilian","breakdown":"CAT: single-handed application, windlass system. SOFTT-W: wider band, better for large thighs. Both proven effective. Improvised tourneys are last resort"},{"term":"Signs of severe blood loss","def":"Pale/cool/clammy skin, rapid weak pulse, confusion, dizziness, thirst, rapid breathing","breakdown":"Signs of hypovolemic shock. 1 liter blood loss visible on ground looks like enormous amount. Adults have 5 liters total. 15-30% loss causes these signs"},{"term":"Internal bleeding signs","def":"Abdominal pain/rigidity, bruising, swelling, blood in urine/stool/vomit, altered mental status","breakdown":"Cannot control internally — call 911 immediately. Lay flat, keep warm, reassure. No fluids by mouth. Monitor vitals. Must go to OR to control source"},{"term":"Junctional bleeding","def":"Bleeding at body junctions (groin, armpit, neck, buttocks) — cannot tourniquet — requires wound packing","breakdown":"Top cause of preventable death in military. Junctional Emergency Treatment Tool (JETT) and SAM Junctional Tourniquet for groin. Wound packing for all junctional sites"},{"term":"Bleeding control kit contents","def":"Tourniquet, hemostatic gauze, pressure bandage, gloves, marker, emergency blanket","breakdown":"STOP THE BLEED kits widely distributed. Mark time on tourniquet with marker (not pen — may fade). Gloves protect rescuer from bloodborne pathogens"},{"term":"Time to death from arterial bleeding","def":"Severed femoral artery: can cause death in 3-5 minutes without intervention","breakdown":"This is why bystander bleeding control matters — EMS average response 8-10 minutes. Proper tourniquet application in first minute dramatically improves survival"}]);
  fc.medium=fc.medium.concat([{"term":"Pediatric tourniquet considerations","def":"Same principles apply — use pediatric-sized tourniquet if available, adult CAT if not","breakdown":"Children have smaller limbs — adult tourniquet may work but harder. Pediatric CAT available. Same placement principles: 2-3 inches above wound, tighten until bleeding stops"},{"term":"Tourniquet for upper vs lower extremity","def":"Both treated same way — 2-3 inches above wound, tighten to stop bleeding","breakdown":"Femoral artery (thigh) bleeds faster than brachial (upper arm). Upper arm tourniquet: avoid axilla (armpit). Lower extremity: avoid knee joint. Windlass: tighten until pulsatile bleeding stops"},{"term":"Hemostatic agents mechanism","def":"Kaolin (QuikClot) activates clotting cascade. Chitosan (HemCon) creates physical seal and activates platelets","breakdown":"Both effective in 3 minutes with firm pressure. No significant heat generation with modern formulations. Safe to leave in wound. Removed in operating room during wound irrigation"},{"term":"Blood loss estimation","def":"Shirt soaked = ~100mL, pool size of hand = ~500mL, large pool on floor = ~1L","breakdown":"Difficult to estimate accurately — rescuers consistently underestimate. Shock signs are better guide than visual estimation. 1 liter from 5-liter system = significant loss"},{"term":"Coagulopathy in trauma","def":"Impaired blood clotting from blood loss, hypothermia, acidosis — worsens bleeding","breakdown":"The lethal triad: hypothermia + acidosis + coagulopathy. Keep patient warm, control bleeding, get to hospital for blood products. Diluting with saline worsens coagulopathy"},{"term":"Hemostasis phases","def":"Primary: platelet plug. Secondary: coagulation cascade (fibrin clot). Fibrinolysis: clot dissolving","breakdown":"Bleeding control supports primary and secondary hemostasis. Hemostatic gauze accelerates platelet activation. TXA (tranexamic acid) prevents premature fibrinolysis after injury"},{"term":"Wound assessment steps","def":"Expose wound (cut clothing), identify source, determine type (arterial vs venous), choose control method","breakdown":"Arterial: bright red, spurting, pulsatile. Venous: dark red, steady flow. Capillary: oozing. Each bleeds at different rate, same first response: pressure or tourniquet for limbs"},{"term":"Psychological considerations in bleeding control","def":"Rescuer: act decisively despite distress. Victim: reassure, maintain consciousness, prevent panic","breakdown":"Talking to victim keeps them calm (reduces adrenaline-driven bleeding), maintains consciousness monitoring. Rescuer: focus on task — emotional processing comes after. Normal stress response"},{"term":"Tourniquet vs wound packing decision","def":"Limb (arm/leg): tourniquet first choice. Junctional/torso/neck: wound packing required","breakdown":"Rule of thumb: can you put a tourniquet on it? If yes — tourniquet is faster and more effective. If no (can't encircle the area) — pack the wound with hemostatic gauze"}]);
  fc.hard=fc.hard.concat([{"term":"TXA (tranexamic acid) in trauma","def":"Antifibrinolytic drug given within 3 hours of injury — prevents premature clot dissolution","breakdown":"CRASH-2 trial: 15% reduction in hemorrhagic death. 10g loading dose, 1g maintenance. Time-sensitive — no benefit >3 hours. Increasingly carried by civilian EMS and battlefield medics"},{"term":"Damage control surgery","def":"Abbreviated surgery to control bleeding and contamination — definitive repair delayed until patient stabilized","breakdown":"Phase 1: hemorrhage and contamination control. Phase 2: ICU resuscitation. Phase 3: definitive repair. Avoids hypothermia/coagulopathy/acidosis from prolonged OR time"},{"term":"Balanced resuscitation (1:1:1)","def":"Equal ratio of packed red blood cells: fresh frozen plasma: platelets — replaces whole blood components","breakdown":"Avoids crystalloid dilution of clotting factors. PRBCs restore oxygen carrying capacity. FFP replaces coagulation factors. Platelets support primary hemostasis. Military origin: Damage Control Resuscitation"}]);
  qz.easy=qz.easy.concat([{"q":"What does the 'ABC' of bleeding control stand for?","opts":["Airway, Breathing, Circulation","Alert, Bleeding control, Care","Assess, Bandage, Call","Apply, Bind, Compress"],"correct":1,"explain":"The Stop the Bleed ABC stands for: Alert (call 911), Bleeding control (apply pressure or tourniquet), Care (maintain until EMS arrives). This simplified framework helps bystanders remember the sequence of actions during a bleeding emergency."},{"q":"Where should a tourniquet be placed on the leg?","opts":["Directly over the wound","On the knee joint","2-3 inches above the wound","At the ankle"],"correct":2,"explain":"A tourniquet should be placed 2-3 inches ABOVE the wound (between the wound and the heart) on the limb. Never place on a joint. 'High and tight' is the guideline — when in doubt, place higher up the limb."},{"q":"A wound is bleeding heavily from the thigh. What is the BEST first action?","opts":["Apply a pressure dressing","Apply a tourniquet 2-3 inches above the wound","Pack the wound with gauze","Apply ice to slow bleeding"],"correct":1,"explain":"For life-threatening extremity bleeding (like a thigh wound), a tourniquet is the fastest and most effective intervention. Apply it 2-3 inches above the wound and tighten until bleeding completely stops. Wound packing is used when tourniquets cannot be applied (groin, armpit, neck)."},{"q":"A tourniquet has been applied and the wound is bleeding controlled. EMS is 5 minutes away. Should you remove the tourniquet?","opts":["Yes, to allow blood flow back","Yes, if the patient asks you to","No — never remove a tourniquet once applied","Yes, after exactly 10 minutes"],"correct":2,"explain":"NEVER remove a tourniquet once it has been applied and bleeding is controlled. Only medical personnel should remove a tourniquet. Removal can restart hemorrhage and precipitate shock. Always note the time of application and communicate it to EMS."},{"q":"When should wound packing be used instead of a tourniquet?","opts":["When the wound is small","For wounds on the neck, armpit, or groin where a tourniquet cannot be placed","When the patient refuses a tourniquet","Only when trained medical personnel are present"],"correct":1,"explain":"Wound packing is used for junctional wounds — neck, armpit, groin, buttocks — where a tourniquet cannot encircle the limb. Pack tightly into the wound cavity with gauze, apply firm direct pressure for at least 3 minutes. Junctional wounds are a leading cause of preventable trauma death."},{"q":"How should you respond if a bandage on a wound becomes soaked with blood?","opts":["Remove and replace the bandage","Apply more material on top without removing","Apply ice to slow bleeding","Elevate and massage the limb"],"correct":1,"explain":"Do NOT remove the original dressing — removing it can disrupt any clot that has begun to form. Instead, add more material on top and continue applying firm pressure. If bleeding continues despite this, consider upgrading to a tourniquet if on an extremity."},{"q":"What is the Stop the Bleed program?","opts":["A hospital protocol for blood transfusions","A national initiative teaching civilians to control life-threatening bleeding before EMS arrives","A first aid certification required for all students","A military-only bleeding control program"],"correct":1,"explain":"Stop the Bleed is a national awareness campaign launched in 2015 teaching the general public how to control life-threatening bleeding. Based on military tourniquet success in combat, the program has trained millions of civilians. The goal: bystander intervention in the critical minutes before EMS arrives."},{"q":"Which body area CANNOT be treated with a tourniquet and requires wound packing?","opts":["Upper arm","Thigh","Groin","Forearm"],"correct":2,"explain":"The groin (and armpit and neck) cannot be treated with a tourniquet because you cannot encircle these areas to cut off blood flow. Wound packing — tightly filling the wound cavity with gauze and applying firm pressure — is the appropriate intervention for junctional bleeding."},{"q":"After applying a tourniquet, what important information should be communicated to EMS?","opts":["The patient's name and insurance","The time the tourniquet was applied","The color of the tourniquet","How much blood was lost before application"],"correct":1,"explain":"The time of tourniquet application is critical medical information — it helps medical personnel assess how long the limb has been without blood flow and make decisions about tourniquet management. Write the time on the tourniquet with a marker or on the patient's skin."},{"q":"A student has a deep stab wound to the shoulder (not on the limb). What is the appropriate treatment?","opts":["Apply a tourniquet to the neck","Pack the wound with gauze and apply firm pressure","Apply ice and elevate the arm","Do nothing — wait for EMS"],"correct":1,"explain":"A deep wound at the shoulder junction cannot be controlled with a tourniquet (cannot encircle the area). Pack the wound tightly with gauze — fill the entire cavity — then apply firm, sustained direct pressure for at least 3 minutes. This is wound packing for a junctional wound."},{"q":"What are signs that indicate a victim may be losing dangerous amounts of blood?","opts":["Flushed red skin and fever","Pale, cool, clammy skin; rapid weak pulse; confusion; and thirst","Bright red skin and high energy","Increased blood pressure and slow pulse"],"correct":1,"explain":"Signs of significant blood loss (hypovolemic shock): pale/cool/clammy skin, rapid and weak pulse, confusion or altered mental status, extreme thirst, and rapid breathing. These develop when 15-30% of blood volume is lost. Immediate bleeding control and EMS activation are critical."},{"q":"Which material is NOT appropriate for an improvised tourniquet?","opts":["A wide belt","A folded bandana (2+ inches wide)","A necktie","A thin rope or bungee cord"],"correct":3,"explain":"Thin ropes, bungee cords, or wire should NEVER be used as improvised tourniquets — they concentrate pressure on a narrow band, causing severe tissue and nerve damage without effectively stopping arterial blood flow. Any improvised tourniquet must be at least 2 inches wide."}]);
  qz.medium=qz.medium.concat([{"q":"What is hemostatic gauze and how does it improve bleeding control?","opts":["Normal gauze with extra absorbency","Gauze treated with clotting agents (kaolin or chitosan) that accelerates clot formation","Gauze that can be left in wounds permanently","A type of bandage that applies automatic pressure"],"correct":1,"explain":"Hemostatic gauze (QuikClot uses kaolin, HemCon uses chitosan) is impregnated with agents that accelerate the body's natural clotting process. It is more effective than plain gauze for severe bleeding, especially in wounds where direct pressure alone is insufficient. Pack into wound and hold firm pressure for 3 minutes."},{"q":"A tourniquet has been on for 2 hours. What should a rescuer do?","opts":["Remove it immediately to restore circulation","Loosen it slightly to allow some blood flow","Keep it in place and continue communicating time of application to medical personnel","Replace it with a new tourniquet"],"correct":2,"explain":"Keep the tourniquet in place and communicate the exact time of application to medical personnel. Only trained medical personnel in a clinical setting should evaluate removing or converting a tourniquet. While prolonged application (>2 hours) can cause nerve and muscle damage, uncontrolled hemorrhage is more immediately life-threatening."},{"q":"The 'lethal triad' in trauma refers to which three conditions that worsen bleeding?","opts":["Pain, confusion, and rapid pulse","Hypothermia, acidosis, and coagulopathy","Hypoxia, hypotension, and hypoglycemia","Dehydration, infection, and blood loss"],"correct":1,"explain":"The lethal triad: hypothermia (cold impairs clotting enzymes), acidosis (from shock and poor perfusion), and coagulopathy (impaired clotting from blood loss and dilution). These three conditions are mutually worsening — each makes the others worse. Prevention: keep patient warm, control bleeding early, limit saline."},{"q":"Why is TXA (tranexamic acid) time-sensitive in trauma?","opts":["It becomes toxic after 3 hours","It only works during active bleeding","Research shows no benefit when given more than 3 hours after injury, and possible harm","It must be given before tourniquet application"],"correct":2,"explain":"The CRASH-2 trial showed TXA significantly reduces hemorrhagic death when given within 3 hours of injury — but provides no benefit (and may cause harm) when given after 3 hours. TXA prevents fibrinolysis (premature clot dissolution). This strict time window makes early administration critical."},{"q":"How does wound packing work physiologically to control bleeding?","opts":["It chemically dissolves blood clots","It physically fills the wound cavity, applying pressure to bleeding vessels and supporting clot formation","It absorbs blood to prevent shock","It seals blood vessels with adhesive"],"correct":1,"explain":"Wound packing works by physically filling the wound cavity with gauze, applying direct pressure to bleeding vessels from within the wound. This mechanical compression slows blood flow, allowing the natural coagulation cascade to form a stable clot. Hemostatic gauze also activates platelets and clotting factors at the wound site."}]);
  qz.hard=qz.hard.concat([{"q":"A patient has a junctional groin wound with arterial bleeding. Wound packing has been applied with firm pressure for 3 minutes. Bleeding continues. What is the next step?","opts":["Remove the packing and apply fresh gauze","Apply a tourniquet to the leg above the knee","Re-pack more tightly with additional hemostatic gauze and maintain firm pressure, consider junctional tourniquet device","Apply ice to the groin"],"correct":2,"explain":"If initial wound packing fails: re-pack more tightly (the first attempt may not have filled the cavity completely), use hemostatic gauze if available, and maintain firm sustained pressure. Junctional tourniquet devices (SAM Junctional Tourniquet, JETT) can apply pneumatic pressure to the groin. Leg tourniquet above the knee is NOT effective for groin bleeding — the femoral artery originates above the tourniquet site."},{"q":"In damage control resuscitation, why are crystalloids (normal saline, Lactated Ringer's) limited?","opts":["They are too expensive","They dilute clotting factors, worsen coagulopathy, contribute to hypothermia, and increase risk of abdominal compartment syndrome","They cause allergic reactions","They raise blood pressure too quickly"],"correct":1,"explain":"Large-volume crystalloid resuscitation worsens the lethal triad: (1) dilutes clotting factors → worsening coagulopathy, (2) is administered at room temperature → contributes to hypothermia, (3) can cause third-spacing → abdominal compartment syndrome. Damage control resuscitation uses balanced blood products (1:1:1 PRBCs:FFP:platelets) to replace what was lost."}]);
})();

(function(){
  if(!window.QB_PUBLIC_HEALTH) return;
  var fc=window.QB_PUBLIC_HEALTH.flashcards,qz=window.QB_PUBLIC_HEALTH.quiz;
  if(!fc||!qz) return;
  ['easy','medium','hard'].forEach(function(d){if(!fc[d])fc[d]=[];if(!qz[d])qz[d]=[];});
  fc.easy=fc.easy.concat([{"term":"Incidence rate","def":"Number of NEW cases per population in a time period — measures risk of developing disease","breakdown":"Incidence = new cases ÷ population at risk × 100,000. High incidence = disease occurring frequently. Compare to prevalence (all existing cases)"},{"term":"Prevalence","def":"Total existing cases in a population at a given time (new AND old cases combined)","breakdown":"Prevalence = all cases ÷ total population. High prevalence = disease is common. Can be high even if incidence is low (when disease is chronic and long-lasting)"},{"term":"Epidemic vs pandemic vs endemic","def":"Endemic: constant baseline. Epidemic: above expected in a region. Pandemic: worldwide spread","breakdown":"Flu: endemic (always around), epidemic (seasonal surges), pandemic (1918, 2009). COVID-19: pandemic. Malaria in Africa: endemic. Same disease can transition between categories"},{"term":"Mortality vs morbidity","def":"Mortality = death rates. Morbidity = illness/injury rates","breakdown":"Crude mortality rate: total deaths ÷ population × 100,000. Cause-specific: by one cause. Case fatality rate: deaths ÷ cases (how deadly is the disease)"},{"term":"Outbreak investigation steps","def":"Confirm diagnosis → define case → count cases → describe by time/place/person → form hypothesis → test hypothesis → implement control","breakdown":"CDC EIS 'disease detectives' follow this systematic approach. Time-place-person (epidemiologic triad). Epidemic curve: cases over time. Source investigation: what do cases have in common?"},{"term":"Epidemic curve","def":"Graph of cases over time — shape reveals transmission pattern","breakdown":"Point source: sudden spike, short duration (one-time exposure like contaminated food). Propagated: gradual rise (person-to-person spread). Mixed: initial spike then continued spread"},{"term":"Food safety temperature danger zone","def":"40-140°F — bacteria multiply most rapidly in this range","breakdown":"Refrigerate below 40°F, keep hot food above 140°F. Don't leave food in danger zone more than 2 hours. Internal cooking temps: chicken 165°F, ground beef 160°F, whole beef 145°F"},{"term":"Surveillance (public health)","def":"Ongoing systematic collection and analysis of health data to guide public health action","breakdown":"Passive: voluntary provider reports. Active: health department seeks cases. Syndromic: real-time monitoring of ER visits and pharmacy sales. Foundation for outbreak detection"},{"term":"Reportable diseases","def":"Conditions legally required to be reported to health authorities — varies by state","breakdown":"National Notifiable Disease Surveillance System (NNDSS). Examples: TB, HIV, gonorrhea, measles, salmonella, Lyme disease, COVID-19. Enables national disease tracking and outbreak response"},{"term":"Health equity","def":"Fairness in health — eliminating avoidable differences in health outcomes between groups","breakdown":"Disparities by race, income, geography are not inevitable — they are the result of unjust systems. Health equity = everyone has a fair chance at good health"},{"term":"CDC role","def":"Centers for Disease Control and Prevention — leads U.S. public health surveillance, outbreak response, and prevention programs","breakdown":"Based in Atlanta, GA. Part of DHHS. ~$9B budget. Not a regulatory agency. EIS officers = 'disease detectives.' Also funds state health departments"},{"term":"WHO role","def":"World Health Organization — UN agency coordinating international public health","breakdown":"194 member states. Declares Public Health Emergencies of International Concern (PHEIC). Sets international health standards. Coordinates COVID, Ebola, polio eradication responses"}]);
  fc.medium=fc.medium.concat([{"term":"R0 (basic reproduction number)","def":"Average secondary cases one infectious person generates in fully susceptible population","breakdown":"R0 >1: epidemic grows. R0 <1: epidemic fades. Measles: 12-18. COVID Delta: ~5. Flu: 1.2. Determines herd immunity threshold: HIT = 1 - (1/R0)"},{"term":"Case fatality rate vs infection fatality rate","def":"CFR = deaths/confirmed cases. IFR = deaths/all infections (including undetected)","breakdown":"CFR overestimates mortality (misses mild/asymptomatic cases). IFR more accurate but needs population serology. COVID IFR: 0.2-0.5%. CFR was much higher early pandemic"},{"term":"Confounding variable","def":"Third variable associated with both exposure and outcome — creates spurious or distorted associations","breakdown":"Ice cream sales and drowning are correlated — confounded by hot weather. Control confounders: randomization, stratification, multivariate regression"},{"term":"Relative risk (RR)","def":"Ratio of disease risk in exposed vs unexposed: RR = incidence exposed ÷ incidence unexposed","breakdown":"RR=2: twice the risk. RR=1: no difference. RR=0.5: 50% lower risk (protective). Used in cohort studies. Odds ratio (OR) approximates RR in case-control studies"},{"term":"Population attributable risk","def":"Proportion of disease in total population attributable to a specific exposure","breakdown":"PAR = (incidence total - incidence unexposed) ÷ incidence total. Tells how much disease we could prevent by eliminating the exposure from the entire population"},{"term":"HACCP (food safety)","def":"Hazard Analysis Critical Control Points — systematic food safety management system","breakdown":"Identifies critical control points where hazards can be prevented, eliminated, or reduced. Required for meat, poultry, seafood, juice. 7 principles including monitoring, verification, record keeping"},{"term":"Lead poisoning in children","def":"No safe blood lead level — neurotoxic, causes permanent cognitive damage, most from paint in pre-1978 homes","breakdown":"CDC action level: 3.5 mcg/dL. Sources: paint chips, contaminated soil, water pipes. Disproportionately affects low-income communities. Flint, MI crisis: 2014-2016"},{"term":"Climate change health impacts","def":"Heat-related illness, expanded vector ranges, worsening air quality, extreme weather events, food insecurity","breakdown":"Mosquito ranges expand northward. More heat deaths. Longer allergy seasons. Hurricane intensity. Displacement crises. Low-income communities and developing nations most affected"},{"term":"DALY (disability-adjusted life year)","def":"One DALY = one year of healthy life lost — combines premature death years (YLL) and disability years (YLD)","breakdown":"WHO uses DALYs to measure global disease burden. Depression has high DALY burden despite low mortality. Allows comparison of fatal and non-fatal conditions across countries"},{"term":"Healthy People 2030","def":"National health promotion and disease prevention objectives for the U.S. — updated every decade","breakdown":"Set by DHHS. 500+ objectives covering leading health threats. Focus: health equity, SDOH, mental health, substance use, cancer, diabetes, COVID recovery. Progress tracked nationally"},{"term":"Foodborne illness major pathogens","def":"Salmonella, E. coli O157:H7, Listeria, Campylobacter, Norovirus, Hepatitis A are leading causes","breakdown":"Salmonella: poultry, eggs. E. coli: undercooked beef. Listeria: deli meat, soft cheese (dangerous in pregnancy). Norovirus: person-to-person + contaminated food. Annual U.S.: 48M sick, 128K hospitalized, 3K deaths"},{"term":"Water treatment and safety","def":"Chlorination, filtration, UV treatment, fluoridation — prevents waterborne disease, strengthens teeth","breakdown":"Cholera, typhoid, dysentery eliminated in U.S. through water treatment. Fluoridation: reduces dental caries 25%. Lead in pipes: Flint crisis, still issue in older cities. Private wells unregulated"},{"term":"Air quality index (AQI)","def":"0-50 good, 51-100 moderate, 101-150 unhealthy for sensitive groups, 151-200 unhealthy, 201-300 very unhealthy","breakdown":"PM2.5 (fine particles) most harmful — penetrate deep lungs, enter bloodstream. Ozone irritates airways. Children, elderly, and asthmatic most vulnerable. Wildfires dramatically worsen AQI"},{"term":"Vaccination schedule rationale","def":"Timed to when maternal antibody protection wanes and immune system matures — protects when most vulnerable","breakdown":"Hepatitis B: at birth (blood exposure risk). DTaP: 2, 4, 6 months. MMR: 12-15 months (after maternal antibodies wane). Boosters: maintain protection as immunity fades"}]);
  fc.hard=fc.hard.concat([{"term":"Bradford Hill criteria","def":"9 criteria for inferring causation from association: strength, consistency, specificity, temporality, dose-response, plausibility, coherence, experiment, analogy","breakdown":"Temporality is the ONLY required criterion. Used by Doll and Hill to establish smoking-lung cancer causation in 1950. Still used to evaluate causal claims in epidemiology"},{"term":"Syndromic surveillance","def":"Real-time monitoring of clinical indicators (ER chief complaints, pharmacy sales, absenteeism) for early outbreak detection","breakdown":"BioSense Platform monitors U.S. ER visits in real time. Detected 2009 H1N1 before traditional lab confirmation. Google Flu Trends: early example (later shown to overestimate)"},{"term":"Berkson's bias","def":"Selection bias from using hospital patients as controls — hospitalized patients differ from community on many variables","breakdown":"If both exposure and disease increase hospitalization probability, hospital controls have artificially high exposure rates. Solution: use community controls. Described by Joseph Berkson (1946)"},{"term":"Ecological study limitations","def":"Ecological fallacy: group-level associations do not necessarily apply at individual level","breakdown":"Country-level correlation between chocolate consumption and Nobel laureates. Doesn't mean individuals who eat chocolate win prizes. Individual-level data required for individual-level conclusions"},{"term":"Precautionary principle","def":"When action faces scientific uncertainty about potential harm, take precautionary measures without waiting for full proof","breakdown":"Applied to: GMO regulation (EU), chemical safety, climate policy. Criticized: can delay beneficial technologies. Balance: risk of inaction vs risk of action with uncertain evidence"}]);
  qz.easy=qz.easy.concat([{"q":"What is the difference between incidence and prevalence?","opts":["Same measurement, different names","Incidence = new cases; prevalence = all existing cases","Incidence = deaths; prevalence = new infections","Incidence measures outbreaks; prevalence measures epidemics"],"correct":1,"explain":"Incidence counts NEW cases occurring in a population over a time period — it measures the risk of getting the disease. Prevalence counts ALL existing cases (new and old) at a point in time — it measures how common the disease is. A chronic disease can have low incidence but high prevalence."},{"q":"Which level of prevention does a colonoscopy screening represent?","opts":["Primary prevention","Secondary prevention","Tertiary prevention","Quaternary prevention"],"correct":1,"explain":"A colonoscopy is secondary prevention — it detects disease (colorectal cancer or pre-cancerous polyps) early, before symptoms appear, so it can be treated effectively. Secondary prevention requires disease to already exist or be developing. Primary prevention would be behaviors that reduce cancer risk (diet, exercise)."},{"q":"What makes COVID-19 a pandemic rather than an epidemic?","opts":["It caused more than 1,000 deaths","It spread across multiple countries and continents worldwide","It affected only certain age groups","It was declared by the U.S. government"],"correct":1,"explain":"A pandemic is an epidemic that spreads across multiple countries or continents affecting large numbers of people. COVID-19 was declared a pandemic by the WHO in March 2020 because it had spread to countries on every inhabited continent with sustained community transmission."},{"q":"The CDC is primarily responsible for which function?","opts":["Approving new medications","Disease surveillance, outbreak investigation, and public health promotion in the U.S.","Setting international health standards","Regulating food and drug safety"],"correct":1,"explain":"The CDC (Centers for Disease Control and Prevention) leads U.S. public health — tracking diseases through surveillance, investigating outbreaks (EIS officers are 'disease detectives'), and promoting health through education and prevention programs. The FDA regulates drugs and food; WHO sets international standards."},{"q":"What is herd immunity?","opts":["When all people in a group are vaccinated","When enough of a population is immune that disease cannot spread to protect even non-immune individuals","Immunity that cows and horses develop","Natural immunity acquired from fighting a disease"],"correct":1,"explain":"Herd immunity occurs when a sufficient proportion of a population is immune (through vaccination or previous infection) that the disease cannot maintain sustained transmission. This protects people who cannot be vaccinated — infants, immunocompromised, etc. The threshold varies by how contagious the disease is."},{"q":"Which is an example of a social determinant of health?","opts":["Blood pressure reading","Genetic risk for diabetes","Access to nutritious food and safe housing","Antibiotic resistance"],"correct":2,"explain":"Social determinants of health are non-medical factors that influence health outcomes: food security, housing stability, income, education, employment, social support, transportation, and neighborhood safety. These account for an estimated 30-55% of health outcomes — more than clinical care alone."},{"q":"What temperature range is considered the 'danger zone' for bacterial growth in food?","opts":["Below 32°F","40°F to 140°F","140°F to 165°F","Above 165°F"],"correct":1,"explain":"The food safety danger zone is 40°F to 140°F — bacteria multiply most rapidly in this range. The food safety rule: keep cold food below 40°F, hot food above 140°F, and never leave food in the danger zone for more than 2 hours (1 hour above 90°F ambient temperature)."},{"q":"Contact tracing is used to:","opts":["Track billing between healthcare providers","Identify people who may have been exposed to an infectious disease and notify them","Follow the supply chain of contaminated food","Monitor a patient's vital signs remotely"],"correct":1,"explain":"Contact tracing identifies and notifies people who may have been exposed to someone with an infectious disease. Contacts are told to get tested, quarantine, and monitor for symptoms. It's a cornerstone of infectious disease control for diseases like TB, STIs, and COVID-19."},{"q":"What is the primary goal of public health surveillance?","opts":["To diagnose individual patients","To provide treatment for sick people","To continuously collect and analyze health data to guide public health action","To enforce health laws and regulations"],"correct":2,"explain":"Public health surveillance is the ongoing, systematic collection, analysis, and interpretation of health data — used to plan, implement, and evaluate public health practice. It enables early outbreak detection, trend monitoring, and evidence-based program planning."},{"q":"Health equity means:","opts":["Everyone receives identical healthcare services","Eliminating avoidable differences in health outcomes between population groups","All people have the same health outcomes regardless of genetics","Healthcare is free for all citizens"],"correct":1,"explain":"Health equity means everyone has a fair and just opportunity to be as healthy as possible. It requires eliminating avoidable, unjust differences in health outcomes that are systematically experienced by disadvantaged groups based on race, income, geography, and other social factors."},{"q":"What does R0 (R-naught) measure in epidemiology?","opts":["Rate of death from a disease","Average number of new cases one infectious person generates in a fully susceptible population","Rate of recovery from disease","Percentage of population that will develop the disease"],"correct":1,"explain":"R0 is the basic reproduction number — the average number of secondary infections caused by one infectious person in a completely susceptible population. R0 > 1: epidemic grows. R0 < 1: epidemic fades. Measles R0 = 12-18 (very contagious). Flu R0 ≈ 1.2-1.4."},{"q":"Which pathogen is commonly associated with undercooked poultry and eggs causing foodborne illness?","opts":["Listeria monocytogenes","Norovirus","Salmonella","Clostridium botulinum"],"correct":2,"explain":"Salmonella is one of the most common causes of foodborne illness in the U.S., most often linked to undercooked poultry and eggs, but also found in raw produce and unpasteurized products. Symptoms: diarrhea, fever, cramps 12-72 hours after exposure. Usually resolves in 4-7 days."},{"q":"Why is lead exposure especially harmful to young children?","opts":["Children absorb less lead than adults","Lead damages the developing brain, causing permanent cognitive impairment even at low levels","Lead only affects the respiratory system","Children's immune systems can easily clear lead"],"correct":1,"explain":"Children's developing brains and nervous systems are highly sensitive to lead. Even low levels cause irreversible cognitive damage — reduced IQ, learning disabilities, attention problems, and behavioral issues. There is NO safe blood lead level in children. The primary source: deteriorating lead paint in pre-1978 homes."}]);
  qz.medium=qz.medium.concat([{"q":"A study finds counties with more fast food restaurants have higher obesity rates. A researcher concludes fast food causes obesity. What is wrong with this conclusion?","opts":["The study is too small","This is the ecological fallacy — group-level data cannot establish individual-level causation","Fast food has been proven to not cause obesity","The study needs to run for longer"],"correct":1,"explain":"This is the ecological fallacy — drawing individual-level conclusions from group-level (aggregate) data. The county correlation doesn't prove individuals who eat fast food become obese. Other factors (poverty, physical inactivity) may explain both. Observational studies at the county level require individual-level data to establish individual causation."},{"q":"A new disease has R0 = 5. What percentage of the population must be immune to achieve herd immunity?","opts":["50%","60%","80%","95%"],"correct":2,"explain":"Herd immunity threshold (HIT) = 1 - (1/R0) = 1 - (1/5) = 1 - 0.2 = 0.80 = 80%. When 80% of the population is immune, each case generates an average of fewer than 1 new case, and the epidemic cannot sustain itself. Higher R0 requires higher HIT."},{"q":"Which study design is BEST for investigating a rare disease?","opts":["Cohort study following 1,000 healthy people","Case-control study comparing people with and without the disease","Cross-sectional survey","Double-blind randomized controlled trial"],"correct":1,"explain":"Case-control studies are ideal for rare diseases — you start by identifying people who HAVE the disease (cases) and compare their past exposures to matched controls without the disease. Cohort studies would need enormous populations to capture enough cases of a rare disease. RCTs are generally not ethical for studying disease causes."},{"q":"Primary, secondary, and tertiary prevention differ in TIMING relative to disease. Which sequence is correct?","opts":["All three occur after disease develops","Primary: before disease; secondary: early disease; tertiary: established disease","Primary: early disease; secondary: established disease; tertiary: prevention","Secondary: before disease; primary: early disease; tertiary: after recovery"],"correct":1,"explain":"Primary prevention occurs BEFORE disease develops (vaccines, lifestyle). Secondary prevention occurs in EARLY disease before symptoms (screening detects pre-symptomatic disease). Tertiary prevention occurs with ESTABLISHED disease (managing diabetes, cardiac rehab). The key: what stage of the disease process does the intervention target?"},{"q":"Climate change is considered a public health threat primarily because it:","opts":["Directly causes cancer in individuals","Worsens air quality, expands vector ranges, increases heat illness, and disrupts food and water security — affecting population health at scale","Only affects developing countries","Has a negligible effect on human health compared to other threats"],"correct":1,"explain":"Climate change threatens population health through multiple pathways: increased heat-related illness (extreme heat events), expanding ranges of disease vectors (mosquitoes spreading malaria, dengue), worsening air quality (ozone, wildfire smoke), disrupted food systems, sea-level rise displacing populations, and intensifying extreme weather events."},{"q":"HACCP (Hazard Analysis Critical Control Points) is a food safety system that:","opts":["Tests every food product before it leaves the factory","Identifies specific points in food production where hazards can be controlled or eliminated","Requires all food workers to be certified physicians","Applies only to restaurant food preparation"],"correct":1,"explain":"HACCP is a systematic, science-based food safety management system that identifies critical control points in the food production process where biological, chemical, or physical hazards can be prevented, eliminated, or reduced to safe levels. Required for meat, poultry, seafood, and juice production in the U.S."},{"q":"What is the key difference between the case fatality rate (CFR) and infection fatality rate (IFR)?","opts":["They are identical measurements with different names","CFR uses confirmed cases as denominator; IFR uses all infections (including undetected mild/asymptomatic cases)","CFR is only used for bacterial diseases; IFR for viral","IFR is always higher than CFR"],"correct":1,"explain":"CFR = deaths / confirmed cases. IFR = deaths / all infections (including mild and asymptomatic undetected cases). CFR overestimates mortality because it misses mild cases. During COVID-19, early CFR was ~3-4%, but IFR was ~0.2-0.5% once population surveys detected the full scope of infection."}]);
  qz.hard=qz.hard.concat([{"q":"Bradford Hill's criterion of temporality is the only REQUIRED criterion for causation. Why?","opts":["Because it is the easiest to measure","Because an exposure that occurs after the disease cannot logically be its cause — this is a logical necessity, not just evidence","Because it eliminates the need for other criteria","Because all other criteria can be faked in research"],"correct":1,"explain":"Temporality is logically necessary for causation — an exposure cannot cause a disease that already existed before the exposure occurred. This is not a matter of statistical evidence but logical necessity. All other Bradford Hill criteria (strength, consistency, dose-response, etc.) add to causal evidence but can theoretically occur by chance."},{"q":"A disease has R0 = 6 and a vaccine with 85% efficacy. What minimum vaccination coverage achieves herd immunity?","opts":["75%","83.3%","98%","Cannot be achieved with this vaccine"],"correct":2,"explain":"HIT = 1 - (1/R0) = 1 - (1/6) = 83.3%. Coverage needed = HIT ÷ vaccine efficacy = 83.3% ÷ 0.85 = 98%. Nearly universal vaccination is required. In practice, this is extremely difficult to achieve, which is why diseases with R0 > 6 are very hard to eliminate through imperfect vaccines alone."},{"q":"Syndromic surveillance detected the 2009 H1N1 pandemic earlier than traditional disease reporting. What is the key advantage of syndromic surveillance?","opts":["It is less expensive than traditional surveillance","It detects patterns in real-time clinical indicators (ER visits, medication sales) before laboratory confirmation is available","It eliminates the need for laboratory testing","It is more accurate than physician-reported cases"],"correct":1,"explain":"Syndromic surveillance monitors real-time data streams — ER chief complaints ('influenza-like illness'), over-the-counter medication sales, school absenteeism, even internet search trends. These signals appear days before laboratory-confirmed cases are reported, enabling earlier outbreak detection and response. The trade-off: lower specificity (more false alarms) than confirmed case reporting."}]);
})();

(function(){
  if(!window.QB_MEDICAL_READING) return;
  var fc=window.QB_MEDICAL_READING.flashcards,qz=window.QB_MEDICAL_READING.quiz;
  if(!fc||!qz) return;
  ['easy','medium','hard'].forEach(function(d){if(!fc[d])fc[d]=[];if(!qz[d])qz[d]=[];});
  fc.easy=fc.easy.concat([{"term":"2025-2026 HOSA Medical Reading books","def":"Gifted Hands (Carson), The Immortal Life of Henrietta Lacks (Skloot), The Hot Zone (Preston), When Breath Becomes Air (Kalanithi), Wonder (Palacio), Chasing My Cure (Fajgenbaum)","breakdown":"Selected to commemorate HOSA's 50th anniversary — books spanning the decades. Test covers plot, characters, themes, medical content, and connections to health careers"},{"term":"Gifted Hands — Ben Carson","def":"Autobiography of neurosurgeon Ben Carson — from poverty in Detroit to leading pediatric neurosurgeon at Johns Hopkins","breakdown":"Key themes: perseverance, faith, education, beating the odds. First surgeon to successfully separate twins joined at the head. Important: how education transformed his life trajectory"},{"term":"Henrietta Lacks — Rebecca Skloot","def":"Story of HeLa cells — first immortal human cell line taken from Henrietta Lacks without consent in 1951","breakdown":"Key themes: medical ethics, informed consent, race and medicine, scientific legacy vs human cost. HeLa cells used in polio vaccine, cancer research. Family never compensated"},{"term":"HeLa cells","def":"First immortal human cancer cell line — taken from Henrietta Lacks' cervical cancer without consent","breakdown":"'HeLa' = Henrietta Lacks. Grew outside body indefinitely — revolutionary for research. Used in 60,000+ research publications. Debate: who owns cells removed from your body?"},{"term":"Informed consent (Henrietta Lacks context)","def":"Medical ethics principle violated in 1951 — Lacks' cells were taken without knowledge or permission","breakdown":"Now foundational in medical research ethics. Nuremberg Code (1947) and Belmont Report (1979) developed partly in response to such violations. Patients must consent to tissue use in research"},{"term":"The Hot Zone — Richard Preston","def":"Account of 1989 Ebola outbreak in Reston, Virginia primate facility and origins of Ebola virus in Africa","breakdown":"Key themes: infectious disease, biosafety, human risk, Ebola's origins. First U.S. filovirus outbreak — affected monkeys, not humans (Reston strain). Basis for understanding BSL-4 lab protocols"},{"term":"Ebola virus disease","def":"Severe hemorrhagic fever with 25-90% mortality — viral hemorrhage, organ failure, massive bleeding","breakdown":"Filovirus. Spread by direct contact with infected bodily fluids. BSL-4 pathogen. Fruit bats: reservoir hosts. No effective treatment historically; Inmazeb approved 2020. African origin"},{"term":"When Breath Becomes Air — Paul Kalanithi","def":"Memoir by neurosurgeon diagnosed with terminal lung cancer at 36 — explores life, death, and meaning","breakdown":"Key themes: physician perspective on dying, what makes life meaningful, identity crisis when doctor becomes patient. Written while dying. Published posthumously. Won numerous awards"},{"term":"Wonder — R.J. Palacio","def":"Novel about Auggie Pullman, a boy with facial differences (Treacher Collins syndrome) entering 5th grade","breakdown":"Key themes: inclusion, kindness, disability, identity, bullying, acceptance. Medical content: craniofacial anomalies. 'Be kind, for everyone is fighting a hard battle' — core theme"},{"term":"Chasing My Cure — David Fajgenbaum","def":"Memoir of physician-researcher who developed life-threatening Castleman disease and helped find his own treatment","breakdown":"Key themes: rare disease, perseverance, physician-as-patient, medical research process, drug repurposing. Founded Castleman Disease Collaborative Network. Autobiographical and scientific"},{"term":"Author vs narrator distinction","def":"Author: real person who wrote the book. Narrator: voice telling the story (may be fictional character)","breakdown":"Important for HOSA test: in memoirs (Carson, Kalanithi, Fajgenbaum, Lacks): author = narrator. In fiction (Wonder): author is Palacio, narrator is Auggie/other characters"},{"term":"Non-fiction vs memoir","def":"Non-fiction: factual account. Memoir: personal first-person account of author's own experience","breakdown":"Gifted Hands, When Breath Becomes Air, Chasing My Cure: memoirs. Immortal Life: narrative non-fiction (Skloot is author but not protagonist). Hot Zone: narrative non-fiction. Wonder: fiction"},{"term":"Theme vs plot","def":"Plot: what happens (events). Theme: what it means (underlying message/lesson)","breakdown":"HOSA Medical Reading tests both. Theme in Gifted Hands: perseverance overcomes obstacles. Theme in Wonder: choose kindness. Theme in Lacks book: science without ethics causes harm"},{"term":"Medical ethics principles (4)","def":"Autonomy, Beneficence, Non-maleficence, Justice — the four pillars of medical ethics","breakdown":"Autonomy: patient's right to decide. Beneficence: do good. Non-maleficence: do no harm. Justice: fair treatment. Henrietta Lacks case violated autonomy and justice. Used in every medical ethics discussion"},{"term":"Biosafety level 4 (BSL-4)","def":"Highest level containment laboratory — for extremely dangerous pathogens with no treatment or vaccine","breakdown":"Full positive-pressure suit. Air showers. Negative pressure. Examples: Ebola, Marburg, smallpox. Featured in The Hot Zone. Only ~40 BSL-4 labs worldwide"},{"term":"Point of view (POV) in medical narratives","def":"First-person: narrator is in the story. Third-person: narrator outside the story. Second-person: 'you'","breakdown":"Memoirs use first-person. Wonder uses multiple first-person narrators (Auggie, Via, Jack, Summer, Julian's mom). The Hot Zone: third-person. Immortal Life: mixed (Skloot first-person + Lacks family third-person)"},{"term":"Annotation techniques","def":"Active reading: underlining, marginal notes, questions, summarizing key passages","breakdown":"HOSA Medical Reading tests comprehension, not just recall. Annotation helps: mark medical terms, ethical dilemmas, character decisions, themes. Particularly useful for identifying medical content connections"},{"term":"Foreshadowing","def":"Author's use of hints or clues about future events — important literary device in medical narratives","breakdown":"In When Breath Becomes Air: Kalanithi's descriptions of other patients' deaths foreshadow his own. In The Hot Zone: descriptions of Ebola symptoms foreshadow later human exposure. Test questions may ask about foreshadowing"}]);
  fc.medium=fc.medium.concat([{"term":"Henrietta Lacks — race and medicine","def":"Her cells were taken without consent, partly reflecting systemic devaluation of Black patients' autonomy in 1950s","breakdown":"Historical context: 1951 Baltimore. Segregated hospital wards. Black patients had less power to refuse. HeLa cells generated billions in pharmaceutical value; family received nothing and couldn't afford healthcare"},{"term":"Ben Carson — early life challenges","def":"Raised in poverty in Detroit by single mother, struggled academically early, transformed by reading program","breakdown":"Mother couldn't read but required Ben and Curtis to write book reports. Reading transformed Carson's trajectory. Themes of resilience, education as equalizer, parental influence, faith"},{"term":"Paul Kalanithi — identity crisis","def":"Shifts from doctor (expert) to patient (vulnerable) when diagnosed — explores what remains of identity when career is gone","breakdown":"Central tension of book: who am I when I can't be a surgeon? Wife is also physician. Wrote book while dying from cancer treatment. Published posthumously by wife Lucy. What gives life meaning?"},{"term":"David Fajgenbaum — drug repurposing","def":"Found that sirolimus (transplant drug) controlled his Castleman disease — systematic search through FDA-approved drugs","breakdown":"Searched for existing drugs with anti-inflammatory properties that might work for Castleman. Approach: mine published data for drugs affecting relevant pathways. Saved his own life, now helps others. CDCN founded"},{"term":"Auggie Pullman — inclusion themes","def":"Mainstreamed student with significant facial difference — navigates friendship, bullying, identity, belonging","breakdown":"Wonder explores who is 'different' from whose perspective. Auggie is the same inside. Other characters' POVs reveal their own struggles. 'Ordinary' is a theme — everyone is extraordinary in their struggles"},{"term":"Zaire Ebola vs Reston Ebola","def":"Zaire: fatal to humans (70-90% mortality). Reston: fatal to monkeys but NOT to humans — both in The Hot Zone","breakdown":"The 1989 Reston outbreak: monkeys dying in Reston, VA lab. Workers exposed — none got sick. Reston strain: airborne between primates but not lethal to humans. Lucky. Zaire strain is the one causing human outbreaks"},{"term":"Rebecca Skloot — narrative technique","def":"Weaves two narratives: Skloot's investigative journey + Lacks family history — alternates perspectives and time periods","breakdown":"Scientific narrative (HeLa cells, research) intercut with human narrative (Henrietta's life, family's pain). Technique shows how separate worlds of science and humanity affect each other. Won NBCC award"},{"term":"Medical research ethics — Belmont Report","def":"1979 federal report establishing three principles for human research ethics: respect, beneficence, justice","breakdown":"Response to Tuskegee and other abuses. Respect = informed consent. Beneficence = maximize benefit, minimize harm. Justice = fair subject selection. Still governs IRB (institutional review board) oversight"},{"term":"Tuskegee Syphilis Study connection","def":"1932-1972 U.S. government study withholding syphilis treatment from Black men — linked to ongoing medical distrust","breakdown":"Henrietta Lacks and Tuskegee: both illustrate historical exploitation of Black Americans in medicine. Tuskegee: treatment withheld. Lacks: tissue taken. Both violated autonomy and justice. Legacy: medical distrust in Black communities today"},{"term":"Palliative care vs curative care","def":"Palliative: comfort-focused, manages symptoms. Curative: aims to eliminate disease","breakdown":"Kalanithi's When Breath Becomes Air explores the transition from curative to palliative goals. Palliative care is appropriate when cure is not possible. Does not hasten death — manages suffering"},{"term":"Character vs theme distinction","def":"Character: person in the story with traits, motivations, development. Theme: universal message that transcends story","breakdown":"Character: Auggie is kind, resilient, funny. Theme: everyone deserves to belong. HOSA tests ask about both. Themes are stated or implied — identify them from character actions and author's message"},{"term":"Medical terminology in fiction context","def":"Wonder: craniosynostosis, mandibulofacial dysostosis, stapedectomy, tracheotomy. Hot Zone: hemorrhage, filovirus, viremia","breakdown":"HOSA test may ask about medical terms in context of books. Know what Auggie's surgeries involved. Know what Ebola does to the body (hemorrhage, organ failure). Connect book content to medical knowledge"},{"term":"Irony in medical memoirs","def":"Dramatic irony: reader knows something characters don't. Situational: unexpected outcome. Verbal: saying opposite of meaning","breakdown":"When Breath Becomes Air: irony that a neurosurgeon studying death dies young from cancer. Chasing My Cure: irony that a medical student develops a rare disease he then helps cure. Common test question type"},{"term":"Allusion","def":"Reference to another work, historical event, or cultural touchstone","breakdown":"Kalanithi alludes extensively to T.S. Eliot and Whitman. The Hot Zone alludes to outbreak movies. Gifted Hands alludes to biblical stories. HOSA may ask about significant allusions in the books"},{"term":"Tone vs mood","def":"Tone: author's attitude toward subject (determined by word choice). Mood: reader's emotional response","breakdown":"When Breath Becomes Air: tone is reflective, philosophical, often accepting. Mood: somber, contemplative, hopeful. Wonder: tone often hopeful/warm. Mood: emotional, uplifting despite challenges. Different things, easily confused"}]);
  fc.hard=fc.hard.concat([{"term":"HeLa cell contamination crisis","def":"HeLa cells contaminated thousands of other cell cultures globally — discovered in 1960s-1970s, denied by scientists","breakdown":"HeLa cells grow so aggressively they can contaminate and overtake other cell cultures. Major scientific crisis. Some scientists who discovered contamination were discredited. Lesson: scientific culture, reproducibility, transparency"},{"term":"Henrietta Lacks estate and bioethics","def":"Debate: who owns cells/tissue removed from a body? U.S. courts ruled patients have no property rights to removed tissue","breakdown":"Moore v. Regents of UC (1990): John Moore's cancer cells patented — court ruled he had no property rights. Lacks family received no compensation. HELA cell use ongoing. Genome published without consent in 2013 — withdrawn after family protest"},{"term":"Castleman disease pathophysiology","def":"Abnormal lymph node growth driven by IL-6 overproduction — causes multi-organ failure in idiopathic MCD","breakdown":"IL-6: pro-inflammatory cytokine. TAFRO syndrome subtype: Thrombocytopenia, Anasarca, Fever, Reticulin fibrosis, Organomegaly. Siltuximab (anti-IL-6): approved treatment. Sirolimus: Fajgenbaum's discovery. Extremely rare"},{"term":"Narrative medicine","def":"Medical discipline using storytelling to improve physician empathy, patient communication, and clinical care","breakdown":"Rita Charon (Columbia): founded narrative medicine. Reading literature builds empathy by inhabiting others' perspectives. HOSA Medical Reading embodies this philosophy — medical knowledge + human stories"},{"term":"Hemostatic fever viral disease classification","def":"Filoviruses (Ebola, Marburg), Arenaviruses (Lassa), Bunyaviruses (Hantavirus) — viral hemorrhagic fevers in The Hot Zone","breakdown":"Feature: damage to vascular endothelium → bleeding. Filoviruses: characteristic filamentous appearance. CDC Category A bioterrorism agents (Ebola, Marburg). BSL-4 containment required. No effective treatment historically"}]);
  qz.easy=qz.easy.concat([{"q":"Which book tells the story of HeLa cells and their original owner, Henrietta Lacks?","opts":["Gifted Hands","The Immortal Life of Henrietta Lacks","The Hot Zone","Chasing My Cure"],"correct":1,"explain":"The Immortal Life of Henrietta Lacks by Rebecca Skloot tells the story of how Henrietta Lacks' cancer cells were taken without her consent in 1951 and became the first immortal human cell line — used in thousands of scientific studies while her family remained in poverty and didn't know for decades."},{"q":"What is the central theme of Wonder by R.J. Palacio?","opts":["The dangers of modern medicine","Kindness, inclusion, and the value of every person regardless of appearance","How genetics determines personality","The history of facial surgery"],"correct":1,"explain":"Wonder's central theme is the importance of kindness and the value of every person. The story of Auggie Pullman — a boy with a facial difference entering mainstream school — explores how choosing kindness transforms communities. The school's motto: 'When given the choice between being right and being kind, choose kind.'"},{"q":"Ben Carson's autobiography Gifted Hands describes his journey to become a:","opts":["Heart surgeon","Oncologist","Pediatric neurosurgeon","General practitioner"],"correct":2,"explain":"Gifted Hands tells the story of Ben Carson's journey from poverty in Detroit to becoming one of the world's leading pediatric neurosurgeons at Johns Hopkins Hospital. He is famous for being the first surgeon to successfully separate twins who were joined at the head (craniopagus twins) in 1987."},{"q":"What virus is the focus of The Hot Zone by Richard Preston?","opts":["HIV","Influenza","Ebola virus","SARS-CoV-2"],"correct":2,"explain":"The Hot Zone by Richard Preston tells the true story of the 1989 Ebola outbreak in a Reston, Virginia primate research facility and traces the origins of the Ebola virus in Africa. The book is known for its detailed, visceral descriptions of what Ebola does to the human body."},{"q":"Paul Kalanithi wrote When Breath Becomes Air while:","opts":["Completing his residency","Retired from medicine","Dying from stage IV lung cancer","Studying philosophy in college"],"correct":2,"explain":"Paul Kalanithi, a neurosurgeon at Stanford, was diagnosed with stage IV lung cancer at age 36 and wrote When Breath Becomes Air while undergoing treatment and dying from the disease. The book explores life, death, meaning, and the experience of a doctor becoming a patient. It was published posthumously in 2016."},{"q":"What medical condition does Auggie Pullman have in Wonder?","opts":["Down syndrome","Treacher Collins syndrome (mandibulofacial dysostosis)","Cerebral palsy","Spina bifida"],"correct":1,"explain":"Auggie Pullman has a form of mandibulofacial dysostosis (similar to Treacher Collins syndrome) — a genetic condition causing underdevelopment of facial bones and tissues. He has had 27 surgeries by the time the story begins. The condition affects his appearance but not his intelligence or personality."},{"q":"Henrietta Lacks' cells were taken in which year?","opts":["1935","1945","1951","1963"],"correct":2,"explain":"Henrietta Lacks' cancer cells were collected at Johns Hopkins Hospital in 1951 without her knowledge or consent. They were given to researcher George Gey, who discovered they could survive and multiply outside the body indefinitely — creating the first immortal human cell line, named HeLa."},{"q":"What does 'HeLa' stand for?","opts":["Health Laboratory","Henrietta Lacks","Helen Lazar","Human Leukemia"],"correct":1,"explain":"HeLa stands for Henrietta Lacks — the cells were named using the first two letters of her first and last name. This was the naming convention used by the lab at the time to code cell samples. The name was kept secret for decades; the public didn't know who HeLa came from until much later."},{"q":"David Fajgenbaum in Chasing My Cure is remarkable because he:","opts":["Discovered the Ebola vaccine","Was the first neurosurgeon to separate conjoined twins","Developed Castleman disease as a medical student and helped find his own treatment","Identified the HeLa cell contamination problem"],"correct":2,"explain":"David Fajgenbaum developed a rare and life-threatening disease (Castleman disease) while in medical school, nearly died five times, and systematically searched through FDA-approved drugs to find a treatment that worked for him (sirolimus). He founded the Castleman Disease Collaborative Network to help others."},{"q":"Which of the 2025-2026 Medical Reading books is a work of FICTION?","opts":["Gifted Hands","When Breath Becomes Air","Wonder","Chasing My Cure"],"correct":2,"explain":"Wonder by R.J. Palacio is a novel — a work of fiction. Auggie Pullman and all characters are invented. The other three options (Gifted Hands, When Breath Becomes Air, Chasing My Cure) are memoirs — non-fiction accounts by real people about their real experiences."},{"q":"The ethical issue at the center of The Immortal Life of Henrietta Lacks is primarily:","opts":["Whether cancer is hereditary","Informed consent — Lacks' cells were taken and used without her knowledge or permission","Whether HeLa cells are scientifically valuable","The dangers of working in cancer research"],"correct":1,"explain":"The central ethical issue is informed consent — Henrietta Lacks' cancer cells were removed during a medical procedure in 1951 without her knowledge, consent, or any explanation of how they would be used. This was legal at the time but would violate today's research ethics standards. Her family struggled financially while her cells generated enormous scientific and commercial value."},{"q":"What is the significance of the 2025-2026 Medical Reading book selection for HOSA?","opts":["The books are all written by HOSA members","The selection commemorates HOSA's 50th anniversary with books spanning the decades","All books are about the same disease","The books are only about pediatric medicine"],"correct":1,"explain":"The 2025-2026 Medical Reading books were selected to commemorate HOSA's 50th anniversary (1976-2026). The books span different decades, health topics, and perspectives on medicine — from neurosurgery (Carson) to viral outbreak (Preston) to patient advocacy (Fajgenbaum) — representing the breadth of health careers HOSA has supported over 50 years."},{"q":"What literary device is used when an author hints at future events in the story?","opts":["Flashback","Foreshadowing","Allusion","Irony"],"correct":1,"explain":"Foreshadowing is the use of hints or clues early in a narrative to suggest events that will happen later. In When Breath Becomes Air, Kalanithi's descriptions of treating dying patients foreshadow his own death. In The Hot Zone, the descriptions of Ebola's effects on African patients foreshadow the Reston outbreak."},{"q":"The four principles of medical ethics are:","opts":["Safety, Efficacy, Equity, Access","Autonomy, Beneficence, Non-maleficence, Justice","Respect, Research, Results, Resources","Prevention, Diagnosis, Treatment, Recovery"],"correct":1,"explain":"The four pillars of medical ethics are: Autonomy (patient's right to make informed decisions), Beneficence (duty to do good), Non-maleficence (duty to do no harm — 'primum non nocere'), and Justice (fair treatment). These principles are violated in Henrietta Lacks' story and form the foundation of bioethics education."},{"q":"A 'memoir' differs from an 'autobiography' in that:","opts":["A memoir is always fiction","A memoir focuses on a specific period or theme rather than an entire life story","An autobiography is always shorter","A memoir must be written about a famous person"],"correct":1,"explain":"A memoir focuses on a specific period, event, or theme from the author's life — not the entire life story (which is an autobiography). When Breath Becomes Air is a memoir about Kalanithi's final years facing cancer. Chasing My Cure is a memoir about Fajgenbaum's illness and research. Both are written in first person about personal experience."}]);
  qz.medium=qz.medium.concat([{"q":"Why did the publication of Henrietta Lacks' genome in 2013 cause controversy, and what was the resolution?","opts":["Scientists disputed the genome's accuracy","It revealed genetic information about living family members who had not consented — the genome was later restricted with family involvement in access decisions","The genome proved HeLa cells were not from Lacks","The publication was a hoax"],"correct":1,"explain":"When researchers published the HeLa cell genome in 2013, the Lacks family objected because the genome revealed private genetic information about living family members — without their consent. After negotiations, NIH established a policy requiring researchers to apply for access to HeLa genomic data, with Lacks family representatives on the review board — a landmark decision in genomic privacy."},{"q":"How does Paul Kalanithi's experience as a patient change his perspective on medicine compared to his previous role as a physician?","opts":["He becomes more critical of the medical system","He gains empathy for what patients experience — uncertainty, vulnerability, loss of identity — that cannot be fully understood from the physician's side","He concludes that medicine is ineffective","He becomes less interested in patient communication"],"correct":1,"explain":"When Breath Becomes Air's core tension is Kalanithi's shift from the physician (who delivers news and controls care) to the patient (who receives news and depends on others). He discovers that the uncertainty patients face cannot be fully understood from the other side. This perspective shift is central to narrative medicine — reading such accounts builds physician empathy."},{"q":"The Reston Ebola outbreak in The Hot Zone was particularly alarming because:","opts":["It killed hundreds of people in Virginia","The Reston strain was airborne between primates — suggesting Ebola could spread via air — but fortunately was not lethal to humans","It was caused by laboratory contamination of water supply","Government officials covered it up completely"],"correct":1,"explain":"The Reston outbreak was alarming because the Reston strain appeared to spread via airborne route between monkey cages — not just direct contact. This suggested that if a lethal strain like Zaire Ebola acquired airborne transmission, it could be catastrophic. Fortunately, Reston strain causes no disease in humans. Several workers tested positive for antibodies but remained well."},{"q":"David Fajgenbaum's approach to finding a treatment for his own Castleman disease demonstrates which research strategy?","opts":["Developing entirely new drugs from scratch","Drug repurposing — systematically searching FDA-approved drugs for ones that might affect relevant disease pathways","Conducting traditional clinical trials with healthy volunteers","Using herbal remedies instead of pharmaceutical drugs"],"correct":1,"explain":"Fajgenbaum used drug repurposing — mining published scientific literature and databases to identify FDA-approved drugs that affect the interleukin-6 (IL-6) pathway that was overactive in his Castleman disease. He found sirolimus (an immunosuppressant used in organ transplant) and tried it on himself. Drug repurposing is faster and cheaper than developing new drugs — a growing strategy in rare disease research."},{"q":"What is the difference between 'tone' and 'mood' in a literary work?","opts":["They are identical — two words for the same concept","Tone is the author's attitude toward the subject; mood is the emotional atmosphere the reader experiences","Mood is the author's attitude; tone is the reader's feeling","Tone applies only to non-fiction; mood only to fiction"],"correct":1,"explain":"Tone is the author's attitude toward the subject, revealed through word choice (e.g., Kalanithi's tone is philosophical and accepting). Mood is the emotional atmosphere the reader experiences (somber, hopeful, tense). HOSA tests may ask you to identify both. They are related but distinct — the same tone can create different moods in different readers."},{"q":"Multiple narrators in Wonder (Auggie, Via, Jack, Summer, Julian's mom) serve which literary purpose?","opts":["To confuse the reader intentionally","To show that the same events look completely different from different perspectives — building empathy for all characters","Because Palacio couldn't decide on a single narrator","To make the book longer"],"correct":1,"explain":"Multiple narrators in Wonder serve to show how the same events, the same person (Auggie), and the same school year look radically different depending on who is experiencing them. Each narrator has blind spots and private struggles. This structure builds empathy — we see Auggie through other eyes, and we see the 'normal' kids struggling with their own difficulties. A key theme: everyone is fighting a hard battle."},{"q":"How does Rebecca Skloot's narrative technique in The Immortal Life of Henrietta Lacks differ from a standard biography?","opts":["Skloot only focuses on the science, avoiding the human story","Skloot weaves her own investigative journey alongside the Lacks family's story, making the author herself a character","Skloot uses entirely fictional composite characters","The book is told entirely from Henrietta's first-person perspective"],"correct":1,"explain":"Skloot uses a dual-narrative structure: her own investigative journey (reporting the book, building trust with Lacks family) runs parallel to the historical narrative of Henrietta's life and the discovery/use of HeLa cells. Skloot herself becomes a character — her relationship with Deborah Lacks (Henrietta's daughter) is central. This 'narrative non-fiction' approach makes abstract scientific and ethical issues deeply personal."}]);
  qz.hard=qz.hard.concat([{"q":"The Moore v. Regents of University of California (1990) Supreme Court ruling relates most directly to which book's central ethical issue?","opts":["Gifted Hands — about neurosurgical rights","The Immortal Life of Henrietta Lacks — about property rights in human tissue","The Hot Zone — about pathogen containment","Chasing My Cure — about drug patents"],"correct":1,"explain":"Moore v. Regents (1990) ruled that patients have NO property rights to cells and tissues removed from their bodies — doctors could patent and profit from such tissues without patient consent or compensation. This ruling directly relates to Henrietta Lacks' situation: her HeLa cells generated enormous commercial value, but the court's ruling (established after her case) confirms her family would have no legal claim even today."},{"q":"When Breath Becomes Air explores the concept of 'what makes life meaningful.' Which philosophical framework does Kalanithi primarily draw on in his exploration?","opts":["Utilitarianism — maximizing happiness for the greatest number","Existentialism and humanism — particularly T.S. Eliot's poetry and Whitman's transcendentalism — asking what constitutes a meaningful human existence","Nihilism — concluding that life has no inherent meaning","Religious determinism — accepting God's plan without question"],"correct":1,"explain":"Kalanithi extensively references T.S. Eliot (particularly 'The Waste Land') and Walt Whitman throughout his memoir. His philosophical exploration is existentialist — asking what constitutes a meaningful human life when the future is uncertain. He was a literature major before medical school and draws on humanist traditions to make sense of his mortality."},{"q":"Narrative medicine, as represented by the HOSA Medical Reading event, proposes that reading literature helps health professionals in which specific clinical way?","opts":["It teaches medical facts more efficiently than textbooks","It builds the capacity for empathy and perspective-taking — enabling providers to better understand patient experiences that differ from their own","It replaces the need for bedside manner training","It primarily helps with administrative tasks"],"correct":1,"explain":"Narrative medicine (founded by Rita Charon at Columbia) proposes that literary reading trains the 'close reading' and perspective-taking skills needed for empathetic clinical care. By inhabiting characters' inner lives — a dying surgeon, a child with facial differences, a patient whose cells were taken — health professionals develop imaginative capacity to understand patient experiences that differ from their own. This is the philosophical foundation of HOSA's Medical Reading event."}]);
})();

(function(){
  if(!window.QB_HOSA_BOWL) return;
  var fc=window.QB_HOSA_BOWL.flashcards,qz=window.QB_HOSA_BOWL.quiz;
  if(!fc||!qz) return;
  ['easy','medium','hard'].forEach(function(d){if(!fc[d])fc[d]=[];if(!qz[d])qz[d]=[];});
  fc.easy=fc.easy.concat([{"term":"Appendix function","def":"Small pouch attached to large intestine — no essential function, but can become infected (appendicitis)","breakdown":"Appendectomy: surgical removal. Signs of appendicitis: right lower quadrant pain, fever, rebound tenderness at McBurney's point. Rupture = medical emergency"},{"term":"Lymphatic system function","def":"Returns interstitial fluid to blood, transports fats, houses immune cells","breakdown":"Lymph nodes: filter lymph, house lymphocytes. Spleen: filters blood, largest lymphoid organ. Thymus: T-cell maturation. Swollen lymph nodes = active immune response"},{"term":"Thyroid gland function","def":"Produces T3 and T4 thyroid hormones — regulate metabolism, growth, development","breakdown":"Located in anterior neck. Goiter: enlarged thyroid (iodine deficiency or disease). Hypothyroid: slow metabolism, weight gain. Hyperthyroid: fast metabolism, weight loss"},{"term":"Pancreas dual function","def":"Endocrine: produces insulin and glucagon. Exocrine: produces digestive enzymes (amylase, lipase, proteases)","breakdown":"Endocrine portion: islets of Langerhans. Beta cells: insulin. Alpha cells: glucagon. Exocrine pancreas: acinar cells produce digestive juice released into duodenum"},{"term":"Liver functions","def":"Metabolizes nutrients, detoxifies blood, produces bile, stores glycogen and vitamins, makes clotting factors","breakdown":"Largest internal organ. 500+ functions. Hepatitis: liver inflammation. Cirrhosis: scarring from chronic damage (alcohol, hepatitis C). Produces albumin (main blood protein)"},{"term":"Kidney functions","def":"Filter blood, produce urine, regulate blood pressure, produce EPO (red blood cell stimulant), activate vitamin D","breakdown":"1 million nephrons per kidney. Filter 180L blood/day, excrete 1-2L urine. Renal failure: kidneys can't filter waste. EPO: erythropoietin — used by athletes (doping)"},{"term":"Homeostasis","def":"Maintaining stable internal environment despite external changes — through negative feedback loops","breakdown":"Temperature: hypothalamus thermostat. Blood glucose: insulin/glucagon. Blood pH: respiratory and kidney compensation. Negative feedback: corrects deviation from set point"},{"term":"Negative feedback","def":"Response that reverses/reduces the original stimulus — the primary mechanism of homeostasis","breakdown":"Body temp rises → sweat → cools → temp returns to normal → sweat stops. Blood glucose high → insulin released → glucose taken up → blood glucose falls → insulin stops"},{"term":"Positive feedback","def":"Response that amplifies the original stimulus — used in specific physiological processes","breakdown":"Labor contractions: oxytocin causes contractions → stretching → more oxytocin → stronger contractions until delivery. Blood clotting: platelet activation amplifies clotting. Uncommon — most physiology is negative feedback"},{"term":"Cell membrane structure","def":"Phospholipid bilayer with embedded proteins — selectively permeable, fluid mosaic model","breakdown":"Hydrophilic heads face water (outside/inside cell). Hydrophobic tails face inward. Proteins: channels, receptors, enzymes. Cholesterol: maintains fluidity. Singer-Nicolson fluid mosaic model (1972)"},{"term":"ATP (adenosine triphosphate)","def":"Energy currency of the cell — powers all cellular work","breakdown":"Made by: cellular respiration (mitochondria) from glucose + oxygen. Also from: glycolysis (no oxygen), creatine phosphate (quick burst). 36-38 ATP per glucose molecule"},{"term":"Mitochondria function","def":"Powerhouse of the cell — produces ATP via cellular respiration","breakdown":"Double membrane. Site of Krebs cycle and electron transport chain. Has own DNA — evidence of endosymbiotic origin. More mitochondria in high-energy cells (cardiac muscle, liver)"},{"term":"DNA vs RNA difference","def":"DNA: double helix, deoxyribose sugar, thymine. RNA: single strand, ribose sugar, uracil instead of thymine","breakdown":"DNA: permanent genetic storage. mRNA: message from DNA to ribosome. tRNA: brings amino acids to ribosome. rRNA: ribosome component. Central dogma: DNA → RNA → Protein"},{"term":"Immune system innate vs adaptive","def":"Innate: fast, non-specific (neutrophils, macrophages, NK cells). Adaptive: slow, specific, memory (B cells, T cells)","breakdown":"Innate: first line — skin, mucus, inflammation, fever. Adaptive: takes 7-10 days but creates memory. Vaccines stimulate adaptive immunity. Allergies: adaptive immunity overreaction"},{"term":"Blood types ABO system","def":"Type A: A antigens. Type B: B antigens. Type AB: both (universal recipient). Type O: neither (universal donor)","breakdown":"Antibodies against type not your own. O negative: universal RBC donor. AB positive: universal recipient. Transfusion incompatibility: fatal hemolytic reaction"},{"term":"Rh factor","def":"Rh antigen on red blood cells — Rh+ has it, Rh- does not","breakdown":"Hemolytic disease of newborn: Rh- mother + Rh+ fetus. Mother makes anti-Rh antibodies that attack future Rh+ fetuses. Prevented by RhoGAM (anti-Rh antibody given to mother)"},{"term":"Stroke types","def":"Ischemic (87%): clot blocks blood flow. Hemorrhagic (13%): blood vessel ruptures","breakdown":"Ischemic: tPA (clot buster) within 4.5 hours. Hemorrhagic: control bleeding, reduce pressure. TIA: transient ischemic attack ('mini stroke') — warning sign. Time is brain — 1.9M neurons die per minute"},{"term":"Diabetes mellitus types","def":"Type 1: autoimmune destruction of beta cells. Type 2: insulin resistance. Gestational: during pregnancy","breakdown":"T1: requires lifelong insulin. T2: lifestyle + oral meds ± insulin. Both: hyperglycemia. Diagnosed by: HbA1c ≥6.5%, fasting glucose ≥126 mg/dL, 2-hr glucose ≥200 mg/dL"},{"term":"Blood pressure classification","def":"Normal: <120/80. Elevated: 120-129/<80. Stage 1 HTN: 130-139/80-89. Stage 2 HTN: ≥140/90. Crisis: ≥180/120","breakdown":"Hypertension = 'silent killer'. No symptoms until organ damage. First-line: lifestyle changes. Stage 2: usually requires medication. Target: <130/80 in most adults"},{"term":"Pain scale (0-10)","def":"0=no pain, 1-3=mild, 4-6=moderate, 7-9=severe, 10=worst possible","breakdown":"Subjective measure — patient self-reports. Faces scale for children. Behavioral pain assessment for non-verbal patients. Document and reassess after intervention. Pain is the 'fifth vital sign'"}]);
  fc.medium=fc.medium.concat([{"term":"Cranial nerves (12)","def":"I Olfactory, II Optic, III Oculomotor, IV Trochlear, V Trigeminal, VI Abducens, VII Facial, VIII Vestibulocochlear, IX Glossopharyngeal, X Vagus, XI Accessory, XII Hypoglossal","breakdown":"Mnemonic: 'Oh Oh Oh To Touch And Feel Very Good Velvet, AH' (or many variants). Some sensory, some motor, some both. Vagus (X): longest, controls heart, lungs, GI. Facial (VII): facial expressions — palsy notable"},{"term":"Electrocardiogram (ECG) basics","def":"P wave: atrial depolarization. QRS: ventricular depolarization. T wave: ventricular repolarization","breakdown":"12-lead ECG: standard assessment. Normal sinus rhythm: rate 60-100, regular P before QRS. ST elevation: STEMI (heart attack). Wide QRS: bundle branch block or ventricular rhythm"},{"term":"Kidney nephron function","def":"Filtration (glomerulus) → Reabsorption (tubules) → Secretion → Excretion — produces urine","breakdown":"Glomerular filtration rate (GFR): measures kidney function. Normal: 90-120 mL/min. GFR <60 = chronic kidney disease. Tubules: reabsorb 99% of filtered sodium, glucose, water"},{"term":"Complement system","def":"Innate immune proteins that lyse pathogens, opsonize bacteria, and recruit immune cells","breakdown":"Activated by: classical (antibody-antigen), alternative (bacterial surfaces), lectin pathways. MAC (membrane attack complex): punches holes in bacteria. C3b: opsonin — tags bacteria for phagocytosis"},{"term":"Inflammatory response steps","def":"Tissue injury → vasodilation (redness, heat) → increased permeability (swelling) → neutrophil recruitment → healing","breakdown":"Chemical mediators: histamine (mast cells), prostaglandins, cytokines. Cardinal signs: rubor (red), calor (heat), tumor (swelling), dolor (pain), functio laesa (loss of function)"},{"term":"Pharmacodynamics vs pharmacokinetics","def":"Kinetics: what body does to drug (ADME). Dynamics: what drug does to body (mechanism, effect, dose-response)","breakdown":"ADME: Absorption, Distribution, Metabolism, Excretion. Dynamics: receptor binding, agonist/antagonist, therapeutic index, side effects. Together determine drug dosing and effects"},{"term":"Surgical asepsis vs medical asepsis","def":"Surgical (sterile technique): absence of all microorganisms. Medical (clean technique): reduces pathogen number","breakdown":"Surgical: ORs, sterile field, sterile gloves. Medical: handwashing, clean gloves, wound care. Breaking sterile field in OR is a critical error"},{"term":"Isolation precautions types","def":"Standard: all patients. Contact: skin/wound. Droplet: respiratory (<3 ft). Airborne: small particles (TB, measles, COVID)","breakdown":"PPE by type: Contact = gloves, gown. Droplet = add surgical mask. Airborne = N95 + negative pressure room. Standard: always — all patients carry potential pathogens"},{"term":"Informed consent elements","def":"Disclosure of procedure, purpose, risks, benefits, alternatives + patient comprehension + voluntary agreement","breakdown":"Cannot consent: minors (parent consents), incompetent adults (guardian), emergencies (implied consent). Informed refusal: same process. Must be in language patient understands"},{"term":"HIPAA covered entities","def":"Health plans, healthcare providers, healthcare clearinghouses — must protect PHI","breakdown":"PHI: Protected Health Information (18 identifiers: name, DOB, address, etc. + health information). Business associates also covered. Minimum necessary standard. Violations: $100-$50,000 per violation"}]);
  qz.easy=qz.easy.concat([{"q":"Which organ produces insulin to regulate blood glucose?","opts":["Liver","Kidney","Pancreas","Spleen"],"correct":2,"explain":"The pancreas produces insulin from beta cells in the islets of Langerhans. Insulin lowers blood glucose by enabling cells to absorb glucose. Glucagon (also from the pancreas, from alpha cells) raises blood glucose. Type 1 diabetes: beta cells destroyed; Type 2: cells resist insulin."},{"q":"What is homeostasis?","opts":["The study of blood disorders","Maintaining a stable internal environment through feedback mechanisms","The process of wound healing","The spread of disease through a population"],"correct":1,"explain":"Homeostasis is the maintenance of a stable internal environment despite external changes. The body uses negative feedback loops to regulate: temperature (sweating/shivering), blood glucose (insulin/glucagon), blood pH (breathing rate), and many other parameters."},{"q":"Blood type O negative is called the 'universal donor' because:","opts":["People with type O are the healthiest donors","O negative blood can be given to patients of any blood type without causing a reaction","Type O blood contains the most oxygen","People with type O can donate the most blood"],"correct":1,"explain":"Type O negative red blood cells have no A antigens, B antigens, or Rh factor — so the recipient's immune system cannot react against them. This makes O negative blood safe for transfusion to anyone in emergency situations when there is no time to determine blood type."},{"q":"What does the P wave on an ECG represent?","opts":["Ventricular contraction","Atrial depolarization (electrical activation of the atria)","Ventricular repolarization","The resting heart state"],"correct":1,"explain":"The P wave represents atrial depolarization — the electrical signal spreading through the atria, causing them to contract and push blood into the ventricles. It should appear before each QRS complex in normal sinus rhythm."},{"q":"Which type of stroke accounts for about 87% of all strokes?","opts":["Hemorrhagic stroke","Ischemic stroke","TIA (transient ischemic attack)","Lacunar stroke"],"correct":1,"explain":"Ischemic stroke (caused by a blood clot blocking an artery to the brain) accounts for about 87% of all strokes. Hemorrhagic stroke (caused by a ruptured blood vessel) accounts for the remaining 13% but has a higher mortality rate. Treatment differs significantly — tPA (clot buster) for ischemic, but NOT for hemorrhagic."},{"q":"The liver performs all of the following functions EXCEPT:","opts":["Producing bile for fat digestion","Detoxifying the blood","Producing insulin","Storing glycogen"],"correct":2,"explain":"The liver does NOT produce insulin — that is the pancreas's job. The liver performs hundreds of functions: producing bile (for fat digestion), detoxifying blood (processing alcohol, drugs, metabolic waste), storing glycogen (releasing glucose when needed), making clotting factors, and producing blood proteins like albumin."},{"q":"Which blood component is primarily responsible for fighting infections?","opts":["Red blood cells","Platelets","White blood cells (leukocytes)","Plasma"],"correct":2,"explain":"White blood cells (leukocytes) are the immune cells — they identify and destroy pathogens. Types include: neutrophils (bacterial infections), lymphocytes (viral infections, antibody production), monocytes (chronic infection, macrophages), eosinophils (parasites, allergies), and basophils/mast cells (allergic response)."},{"q":"What is ATP and why is it important?","opts":["A type of DNA that stores genetic code","Adenosine triphosphate — the energy currency of the cell","A hormone produced by the adrenal gland","A protein that carries oxygen in the blood"],"correct":1,"explain":"ATP (adenosine triphosphate) is the universal energy currency of cells. When cells need energy for any work (muscle contraction, nerve impulse, protein synthesis), they break down ATP. It is produced primarily by mitochondria through cellular respiration using glucose and oxygen."},{"q":"Standard Precautions in healthcare are used:","opts":["Only with patients who have confirmed infections","Only in the ICU and ER","With ALL patients at ALL times, regardless of diagnosis","Only when blood is visible"],"correct":2,"explain":"Standard Precautions are used with all patients at all times — because any patient may carry bloodborne pathogens or other infections. They include: hand hygiene, appropriate PPE (gloves, gown, mask, eye protection depending on task), safe handling of sharps, and proper waste disposal."},{"q":"A patient's blood pressure is 142/92 mmHg. According to current guidelines, this falls into which category?","opts":["Normal","Elevated","Stage 1 hypertension","Stage 2 hypertension"],"correct":3,"explain":"Stage 2 hypertension = systolic ≥140 OR diastolic ≥90 mmHg. This patient has 142 systolic (≥140) AND 92 diastolic (≥90), meeting Stage 2 criteria. Stage 2 typically requires antihypertensive medication in addition to lifestyle changes."},{"q":"What is the Rh factor and why does it matter in pregnancy?","opts":["A hormone that promotes fetal growth","An antigen on red blood cells — incompatibility can cause dangerous reactions in Rh-negative mothers carrying Rh-positive babies","A blood test measuring iron levels in pregnant women","The factor that determines blood type A, B, AB, or O"],"correct":1,"explain":"The Rh factor is an antigen on red blood cells. An Rh-negative mother carrying an Rh-positive fetus can develop anti-Rh antibodies. These antibodies can cross the placenta in future pregnancies and destroy fetal red blood cells (hemolytic disease of the newborn). Prevented by RhoGAM injection given to Rh-negative mothers."},{"q":"What is the function of the lymphatic system?","opts":["Pump blood through the body","Return interstitial fluid to the blood, transport dietary fats, and house immune cells","Filter air in the lungs","Produce hormones for growth and development"],"correct":1,"explain":"The lymphatic system serves three main functions: (1) returns excess interstitial fluid (that leaked from capillaries) back to the bloodstream as lymph, (2) transports dietary fat (as chylomicrons) from the intestine to the blood, and (3) provides immune surveillance through lymph nodes, spleen, and thymus."}]);
  qz.medium=qz.medium.concat([{"q":"A patient has both type A blood and Rh-negative status (A-). Which blood type can they SAFELY receive in a transfusion?","opts":["Only A-","A- and O-","A-, O-, A+, and O+","Any blood type"],"correct":1,"explain":"A Rh-negative patient can only receive Rh-negative blood (to avoid sensitization to Rh factor). A type blood can receive type A or type O (which has no ABO antigens). Therefore, an A- patient can receive A- or O-. Receiving Rh-positive blood would cause the immune system to produce anti-Rh antibodies, making future Rh+ transfusions dangerous."},{"q":"The cranial nerve responsible for facial expressions and taste on the front two-thirds of the tongue is:","opts":["Trigeminal nerve (V)","Facial nerve (VII)","Glossopharyngeal nerve (IX)","Hypoglossal nerve (XII)"],"correct":1,"explain":"Cranial nerve VII (Facial nerve) controls facial expressions (motor) and taste sensation from the anterior two-thirds of the tongue (sensory). Bell's palsy affects the facial nerve — causing unilateral facial paralysis. The trigeminal (V) provides general sensation to the face. Glossopharyngeal (IX) handles the posterior tongue and throat."},{"q":"Negative feedback differs from positive feedback in that:","opts":["Negative feedback is harmful; positive feedback is beneficial","Negative feedback reverses the original stimulus (maintaining stability); positive feedback amplifies it (moving away from set point)","Positive feedback is the primary mechanism of homeostasis","Negative feedback only occurs in the nervous system"],"correct":1,"explain":"Negative feedback reverses or reduces the original stimulus, bringing the system back to set point — it maintains homeostasis. Positive feedback amplifies the original stimulus until a specific endpoint is reached (labor contractions, blood clotting). Most physiological regulation uses negative feedback; positive feedback is reserved for specific completion-driven processes."},{"q":"In the context of HIPAA, which of the following is considered Protected Health Information (PHI)?","opts":["Published medical research results","A de-identified list of disease statistics","A patient's name combined with their diagnosis","General health information in a textbook"],"correct":2,"explain":"PHI is any health information that can identify an individual — the combination of a patient's name AND their health information (diagnosis, treatment, test results, etc.). HIPAA lists 18 specific identifiers. De-identified data (no identifiers) is not PHI and can be shared freely. The minimum necessary standard limits PHI sharing to what is needed for the purpose."},{"q":"What is the difference between ischemic and hemorrhagic stroke and why does it matter for treatment?","opts":["There is no difference — treatment is identical","Ischemic is a blood clot blocking flow; hemorrhagic is a ruptured vessel. tPA treats ischemic but would be fatal in hemorrhagic stroke","Hemorrhagic is more common and easier to treat","Ischemic is treated with surgery; hemorrhagic with medication"],"correct":1,"explain":"The distinction is critical because treatment is opposite: Ischemic stroke (87%) can be treated with tPA (tissue plasminogen activator — a clot buster) within 4.5 hours, dramatically improving outcomes. Giving tPA in hemorrhagic stroke (ruptured vessel) would cause more bleeding and likely kill the patient. CT scan distinguishes the two — done before any treatment decision."},{"q":"The complement system is part of which immune response?","opts":["Adaptive (specific) immunity only","Innate immunity (and can be activated by adaptive immunity as well)","Only activated during viral infections","Only present in vaccinated individuals"],"correct":1,"explain":"The complement system is a group of innate immune proteins (always present) that can be activated by three pathways: classical (requires antibodies from adaptive immunity), alternative (direct bacterial surface activation), and lectin (binds mannose on pathogens). It provides rapid innate defense by lysing pathogens (MAC), opsonizing bacteria (C3b), and recruiting immune cells."}]);
  qz.hard=qz.hard.concat([{"q":"A patient's GFR (glomerular filtration rate) is 45 mL/min. What does this indicate and what precautions are needed for medication dosing?","opts":["Normal kidney function — no precautions","Stage 3 CKD — drugs cleared by kidneys accumulate, requiring dose reduction or interval extension","Acute kidney injury — stop all medications","End-stage renal disease — immediate dialysis needed"],"correct":1,"explain":"GFR 45 mL/min = Stage 3 CKD (Chronic Kidney Disease) — moderate reduction in function. Normal GFR is 90-120 mL/min. Stage 3: 30-59 mL/min. Renally cleared drugs accumulate because the kidneys clear them more slowly. Dose reductions, extended intervals, or alternative drugs are needed. Nephrotoxic drugs (NSAIDs, contrast dye, aminoglycoside antibiotics) should be avoided or used cautiously."},{"q":"A Type 1 diabetic patient takes insulin but skips a meal. 30 minutes later they are confused, diaphoretic, and trembling. Blood glucose is 42 mg/dL. What is happening physiologically and what is the immediate treatment?","opts":["Diabetic ketoacidosis — give insulin","Hypoglycemia — insulin without adequate carbohydrate intake dropped glucose below 70 mg/dL. Give 15-20g fast-acting carbohydrates orally (conscious patient) or IV dextrose (unconscious)","Hyperglycemic hyperosmolar state — give large fluid bolus","Normal insulin response — no treatment needed"],"correct":1,"explain":"This is hypoglycemia (BG 42 mg/dL, well below the 70 mg/dL threshold). Insulin was given without corresponding food intake, dropping glucose dangerously. Physiologically: neurons cannot function without adequate glucose → confusion, diaphoresis (from epinephrine release), trembling. Treatment: 15-20g fast-acting carbs (juice, glucose tablets) if conscious. IV dextrose (D50W) if unconscious. Recheck in 15 minutes. Never give insulin."}]);
})();

(function(){
  if(!window.QB_HOSA_HISTORY) return;
  var fc=window.QB_HOSA_HISTORY.flashcards,qz=window.QB_HOSA_HISTORY.quiz;
  if(!fc||!qz) return;
  ['easy','medium','hard'].forEach(function(d){if(!fc[d])fc[d]=[];if(!qz[d])qz[d]=[];});
  fc.easy=fc.easy.concat([{"term":"HOSA current name","def":"HOSA – Future Health Professionals (changed from Health Occupations Students of America in 2004)","breakdown":"Delegate Assembly vote in June 2004. Name reflects broader scope of health careers beyond traditional 'occupations'"},{"term":"HOSA emblem components","def":"Caduceus (medical symbol) + hands + circle — representing medicine, caring, and unity","breakdown":"Caduceus: winged staff with two snakes. Hands: member caring. Circle: unity. Official HOSA colors: maroon and gold"},{"term":"ILC full name","def":"International Leadership Conference — HOSA's annual national competitive event, held each summer","breakdown":"Competitors qualify through state SLC. Events across all divisions. Delegate Assembly meets at ILC. National officers elected at ILC"},{"term":"SLC full name","def":"State Leadership Conference — state-level HOSA competition before national ILC","breakdown":"Winners advance to ILC. Each state runs its own SLC with own format and schedule. Gateway to national competition"},{"term":"HOSA membership divisions","def":"Middle School, Secondary (high school), Post-Secondary/Collegiate","breakdown":"Competitors only compete within their division. Events differ by division. HOSA Academy focuses on Middle School division events"},{"term":"HOSA chapter","def":"Local group of HOSA members at a school or college — the basic organizational unit","breakdown":"Chapters elect officers, pay dues, enter competitions at regional → state (SLC) → national (ILC). Advisors are health science CTE teachers"},{"term":"HOSA member count","def":"Approximately 300,000 members in the United States","breakdown":"One of the largest student CTE organizations nationally. Millions of alumni working across all healthcare fields"},{"term":"HOSA competitive event categories","def":"Health Science Events, Leadership Events, Recognition Events","breakdown":"Health Science: written tests, skills demos, team events. Leadership: public speaking, writing, parliamentary procedure. Recognition: community service, healthy lifestyle — non-competitive"},{"term":"Business attire (HOSA competitions)","def":"Professional dress required at most HOSA competitive events — bonus points awarded","breakdown":"Suit, dress, or official HOSA uniform. Bonus points awarded before competition begins. Trains students in professional presentation. Part of HOSA's professional development mission"},{"term":"HOSA event guidelines","def":"Official annual rules for each competitive event — updated each summer, must use current year's version","breakdown":"Specify: format, time limits, reference materials, scoring rubric, dress code, required supplies. Using outdated guidelines is a common mistake. Always confirm you have the current year"},{"term":"HOSA Health Science Events examples","def":"Medical Terminology, Nutrition, Math for Health Careers, HOSA Bowl, Stop the Bleed, Vet Science, Medical Reading","breakdown":"Written tests (35 questions, 60 min), skills demonstrations, team events. Most Middle School events are written tests. Each has specific reference materials listed in guidelines"},{"term":"HOSA Leadership Events examples","def":"Prepared Speaking, Extemporaneous Writing, Community Awareness, Parliamentary Procedure","breakdown":"Test communication, management, and leadership skills beyond clinical knowledge. Prepared Speaking: memorized health speech. Extemporaneous Writing: 30-minute timed essay. Parliamentary Procedure: team of 5"}]);
  fc.medium=fc.medium.concat([{"term":"HOSA co-curricular vs extracurricular","def":"Co-curricular: integrated with curriculum. Extracurricular: separate from coursework","breakdown":"HOSA events directly align with CTE Health Science learning standards. Students practice what they learn in class. Not just an after-school club — HOSA is part of the educational program"},{"term":"HOSA health science CTE pathway","def":"HOSA serves Health Science Technology Education (HSTE) — one of 16 career clusters in CTE","breakdown":"16 CTE career clusters include agriculture, technology, healthcare, etc. HOSA is the official student organization for HSTE cluster. Other CTE student orgs: FFA (agriculture), DECA (business), SkillsUSA (trade/tech)"},{"term":"HOSA mission statement","def":"Empower HOSA members to become effective leaders in the global health community through education, collaboration, and experience","breakdown":"Three pillars: education, collaboration, experience. Global = healthcare is international. Effective leaders = not just knowledgeable, but able to lead and communicate. Competitions develop all three"},{"term":"HOSA Hippocratic connection","def":"HOSA embeds healthcare ethics — First Do No Harm — into all health science education","breakdown":"'Primum non nocere' is the foundation of medical ethics. HOSA prepares students who will carry professional ethics into healthcare careers. Ethics tested in competitions and embedded in curriculum"},{"term":"HOSA 2025-2026 theme","def":"50th anniversary celebrated through Medical Reading book selection spanning decades, special events, and retrospective programming","breakdown":"Books selected representing different eras: Gifted Hands (1990), Immortal Life (2010), Hot Zone (1994), When Breath Becomes Air (2016), Wonder (2012), Chasing My Cure (2019)"}]);
  fc.hard=fc.hard.concat([{"term":"HOSA quadruple aim alignment","def":"HOSA's mission aligns with IHI's Quadruple Aim: better patient experience, population health, lower costs, AND improved provider experience","breakdown":"HOSA addresses provider experience aim by developing professionals who are passionate and prepared — reducing early career burnout and dropout. Well-trained passionate providers = better experience for all"},{"term":"National Health Care Skill Standards","def":"Standards defining competencies needed for healthcare careers — HOSA competitive events are aligned to these","breakdown":"Developed by Health Science Technology Education. Serve as curriculum foundation for CTE Health Science programs. HOSA events validate student attainment of these standards competitively"},{"term":"HOSA history timeline","def":"1976: founded as HOSA. 1992: joined with American Association for Health Professions. 2004: renamed HOSA – Future Health Professionals. 2015: Stop the Bleed event added. 2025-26: 50th anniversary","breakdown":"Timeline shows how HOSA evolves with healthcare. New events added as healthcare changes. Stop the Bleed: response to mass casualty events. Future events will reflect emerging health fields"},{"term":"HOSA and workforce pipeline","def":"HOSA creates a documented pipeline from student to health professional — critical for addressing projected healthcare worker shortage","breakdown":"BLS projects 1.8 million new healthcare jobs per year through 2030. HOSA alumni fill every healthcare role. With 300,000 current members and millions of alumni, HOSA is a major workforce development force"}]);
  qz.easy=qz.easy.concat([{"q":"What year was HOSA founded?","opts":["1968","1972","1976","1984"],"correct":2,"explain":"HOSA was founded in 1976 as Health Occupations Students of America. It was established to provide a student organization for health science Career and Technical Education (CTE) programs — like FFA for agriculture or DECA for business students."},{"q":"What is HOSA's current official name?","opts":["Health Occupations Students of America","HOSA – Future Health Professionals","Health Organization for Student Advancement","Healthcare Occupations Student Alliance"],"correct":1,"explain":"HOSA's current official name is HOSA – Future Health Professionals, changed in 2004 at the Delegate Assembly from the original name Health Occupations Students of America. The new name better reflects the modern scope of health careers."},{"q":"HOSA membership includes which three divisions?","opts":["Elementary, Middle School, High School","Middle School, Secondary, Post-Secondary/Collegiate","Freshman, Sophomore, Junior/Senior","High School, Community College, University"],"correct":1,"explain":"HOSA has three divisions: Middle School (grades 6-8), Secondary (high school, grades 9-12), and Post-Secondary/Collegiate (community college and university students). Competitors only compete against others in their same division."},{"q":"What body governs HOSA and votes on major decisions?","opts":["HOSA National Board of Trustees","U.S. Department of Education","The Delegate Assembly","State HOSA Advisors Council"],"correct":2,"explain":"The Delegate Assembly is HOSA's governing body — state delegates vote on constitutional amendments, bylaw changes, and elect national student officers. It meets annually at ILC. The 2004 name change was voted on by the Delegate Assembly."},{"q":"HOSA is described as 'co-curricular.' What does this mean?","opts":["HOSA is only for extracurricular activities after school","HOSA activities are integrated with the health science CTE classroom curriculum","HOSA is optional and separate from all coursework","Co-curricular means HOSA is competitive"],"correct":1,"explain":"Co-curricular means HOSA is part of the curriculum itself — HOSA events directly align with Career and Technical Education (CTE) Health Science learning standards. Students practice real health science knowledge in competitions. This distinguishes HOSA from purely extracurricular clubs."},{"q":"What are the three categories of HOSA competitive events?","opts":["Written, Oral, and Hands-On Events","Health Science Events, Leadership Events, and Recognition Events","Academic, Vocational, and Elective Events","Team, Individual, and Community Events"],"correct":1,"explain":"HOSA events are organized into: Health Science Events (clinical knowledge and skills — written tests, skills demos, team events), Leadership Events (communication and management — public speaking, writing, parliamentary procedure), and Recognition Events (non-competitive community service and character recognition)."},{"q":"The HOSA 2025-2026 school year is significant because it marks:","opts":["HOSA's 25th anniversary","The first year HOSA held an ILC","HOSA's 50th anniversary since its 1976 founding","HOSA's 100th anniversary"],"correct":2,"explain":"The 2025-2026 school year marks HOSA's 50th anniversary since its founding in 1976 (1976 + 50 = 2026). This milestone is commemorated through the Medical Reading book selection, which features titles spanning the decades of HOSA's existence."},{"q":"What does the circle in the HOSA emblem represent?","opts":["The global scope of healthcare","Unity among HOSA members","A medical pill","The cycle of education"],"correct":1,"explain":"The circle in the HOSA emblem represents unity among HOSA members. Combined with the caduceus (medicine/health) and hands (caring), the emblem as a whole represents HOSA's mission: unified, caring future health professionals."},{"q":"Which of these is a HOSA Leadership Event?","opts":["Medical Terminology","Stop the Bleed","Prepared Speaking","HOSA Bowl"],"correct":2,"explain":"Prepared Speaking is a HOSA Leadership Event — competitors deliver a memorized speech on a health topic and are judged on content, delivery, and organization. Medical Terminology, Stop the Bleed, and HOSA Bowl are all Health Science Events."},{"q":"A Recognition Event in HOSA differs from a competitive event because:","opts":["Recognition Events are only for seniors","They are non-competitive — judged on portfolio of activities, not against other students","They are harder to qualify for","Recognition Events are held at a different venue"],"correct":1,"explain":"HOSA Recognition Events (like Service Learning, Healthy Lifestyle, HOSA Chapter of Excellence) are non-competitive — students/chapters are recognized for their achievements based on submitted portfolios, not scored against each other. Any chapter or student who meets the criteria can earn recognition."},{"q":"Business attire is required at HOSA competitive events for which reason?","opts":["It helps judges identify competitors","It is part of professional development — healthcare is a professional field","It is required by federal law for CTE competitions","To make events look more prestigious on social media"],"correct":1,"explain":"Business attire requirements reflect HOSA's professional development mission — healthcare careers require professional appearance, communication, and conduct. Wearing professional dress at competitions trains students to present themselves as future health professionals from a young age. Bonus points are awarded."}]);
  qz.medium=qz.medium.concat([{"q":"Why was HOSA's name changed from Health Occupations Students of America to HOSA – Future Health Professionals in 2004?","opts":["The original name was trademarked by another organization","To better reflect the expanded scope of modern health careers beyond traditional occupations","The government required the change for CTE funding","To make the name work internationally"],"correct":1,"explain":"The name changed because 'health occupations' felt outdated by 2004 — the health field had expanded to include biotechnology, health informatics, research, administration, and many careers that weren't traditional 'occupations.' The new name reflects the broader professional scope HOSA serves."},{"q":"How does a HOSA competitor typically advance from chapter to ILC?","opts":["By applying directly to HOSA national","Chapter → Regional → State Leadership Conference (SLC) → International Leadership Conference (ILC)","By invitation from a HOSA national officer","By winning an online qualifying round"],"correct":1,"explain":"The typical pathway: compete at chapter level → advance to regional competition → place at State Leadership Conference (SLC) → qualify for International Leadership Conference (ILC). The exact structure varies by state, but SLC is always the gateway to ILC."},{"q":"HOSA competitive event guidelines must be from which year?","opts":["Any year from the past 5 years","Only the very first year guidelines were published","The current school year — guidelines are updated annually each summer","The most recent year available before 2020"],"correct":2,"explain":"HOSA event guidelines are updated annually every summer for the coming school year. Formats, reference materials, point values, and rules can change. Using outdated guidelines is a common mistake — always confirm you have the current year's guidelines. This is why advisors must check for updates each year."},{"q":"What is the significance of HOSA being 'co-curricular' rather than 'extracurricular'?","opts":["There is no practical difference — both mean after-school activities","Co-curricular means HOSA activities are aligned with and extend classroom learning — not separate from the educational program","Extracurricular is more prestigious than co-curricular","Co-curricular means HOSA is mandatory"],"correct":1,"explain":"Co-curricular means HOSA is integrated with the health science CTE curriculum — HOSA competitive events validate real classroom learning, not separate skills. Students who study medical terminology in class compete in Medical Terminology. This alignment is why HOSA has official recognition from the U.S. Department of Education."},{"q":"Which statement BEST describes how HOSA addresses the healthcare workforce shortage?","opts":["HOSA trains current healthcare workers through continuing education","HOSA creates a documented pipeline from student interest to health professional career through education, competition, and professional development","HOSA lobbies Congress for healthcare funding","HOSA recruits international healthcare workers"],"correct":1,"explain":"HOSA addresses the workforce shortage by creating an educational pipeline: identifying students interested in health careers → developing their knowledge, skills, and professional identity through CTE and HOSA activities → connecting them to career pathways. With 300,000 current members and millions of alumni, HOSA has already populated every sector of the healthcare workforce."},{"q":"The Parliamentary Procedure event in HOSA tests knowledge of which document?","opts":["HOSA's official bylaws","Robert's Rules of Order","The U.S. Constitution","The Hippocratic Oath"],"correct":1,"explain":"HOSA's Parliamentary Procedure event tests Robert's Rules of Order — the standard system for conducting formal meetings. A team of 5 students conducts a mock HOSA chapter meeting following parliamentary procedure. This same system is used in HOSA's own Delegate Assembly and chapter meetings."}]);
  qz.hard=qz.hard.concat([{"q":"HOSA's mission aligns with the Quadruple Aim's fourth element (improving provider experience). How?","opts":["By reducing healthcare costs directly","By producing passionate, prepared health professionals who are less likely to experience early burnout and career dropout","By eliminating the need for continuing education","By providing salary supplements to HOSA alumni"],"correct":1,"explain":"The Quadruple Aim's fourth element (provider experience/burnout reduction) is addressed by HOSA by developing health professionals who enter their careers with strong foundational knowledge, professional identity, and clear purpose. Research shows early career enthusiasm and competence — hallmarks of HOSA-prepared students — correlate with lower burnout rates and longer career retention."},{"q":"A state HOSA chapter wants to change a national HOSA policy. What is the correct formal process?","opts":["The state advisor emails HOSA national headquarters","The state chapter president contacts a national officer","The state association submits a proposed bylaw amendment to the Delegate Assembly at ILC for a vote by state delegates","Individual students can vote through the HOSA website"],"correct":2,"explain":"HOSA governance follows parliamentary procedure: policy changes require a bylaw amendment submitted through proper channels to the Delegate Assembly — HOSA's governing body that meets at ILC. State delegates (not individual students) vote. This is why understanding HOSA's governance structure is important — it's a model of democratic organizational governance."},{"q":"Which combination of factors BEST explains why HOSA has grown from a small vocational education organization to a 300,000-member organization?","opts":["Mandatory enrollment in all U.S. high schools","Alignment of HOSA's mission with growing demand for healthcare workers, expansion from vocational to all health science pathways, and the 2004 name change reflecting modern health career diversity","HOSA received a major federal government grant in 2000","Celebrity endorsements increased HOSA's visibility"],"correct":1,"explain":"HOSA's growth reflects multiple aligned factors: (1) the healthcare workforce shortage created massive demand for health career pathways, (2) CTE expanded health science programs beyond traditional vocational tracks to include biotech, informatics, and research, (3) the 2004 name change attracted students into broader health career pathways, and (4) competitive events like HOSA Bowl and newer events like Stop the Bleed kept content relevant to evolving healthcare practice."}]);
})();

